window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["techniques"]={"updatedAt":"2026-06-30","count":323,"techniques":[{"id":"tu-thuat-na-di","name":"Tử thuật - Na di","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ (Thiên Vận Tông)","soHuu":["Tứ sư tỷ (Tử hệ)"],"blurb":"Pháp thuật của Tử hệ Thiên Vận Tông; bắt quyết điểm vào hư không, một tia sáng bạc lan ra bao trùm phạm vi mười dặm trong nháy mắt.","detail":"Tử thuật - Na di là pháp thuật của tứ sư tỷ thuộc Tử hệ Thiên Vận Tông. Người thi triển bắt quyết điểm tay vào hư không, một tia sáng bạc từ cơ thể điên cuồng lan ra, trong nháy mắt bao trùm phạm vi mười dặm. Trong chương, thuật này được dùng để mở màn cuộc vây kích Vương Lâm tại Tử Lâm Các.","nguon":["@c0458"]},{"id":"tran-phap-khoa-pham-linh-cac","name":"Trận pháp khóa Phẩm Linh Các","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thiên Vận Tông","soHuu":[],"blurb":"Trận pháp khóa Phẩm Linh Các với ba đạo bạch ngân giao nhau; ấn lệnh bài vào chỗ giao sẽ kích hoạt cửa truyền tống lên tầng thứ bảy.","detail":"Trận pháp bảo vệ Phẩm Linh Các có ba đạo bạch ngân giao nhau dưới mặt đất. Khi ấn lệnh bài vào chỗ giao, ba đạo bạch ngân điên cuồng lao ra xuyên qua lệnh bài, hợp thành một khối khiến lệnh bài phát ánh sáng tím khuếch tán, rồi nối thành một cánh cửa lớn truyền tống tại tầng thứ bảy.","nguon":["@c0458"]},{"id":"than-thong-na-di-tu-su-ty","name":"Thần thông na di (tứ sư tỷ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ (Thiên Vận Tông)","soHuu":["Tứ sư tỷ (Tử hệ)"],"blurb":"Thần thông dịch chuyển không gian của tứ sư tỷ, dời người tới nơi khác trong nháy mắt.","detail":"Thần thông na di cho phép khóa chặt không gian bốn phía ngăn đối phương na di, đồng thời dịch chuyển người tới địa điểm xa trong chớp mắt. Tứ sư tỷ dùng nó đưa Vương Lâm tới thạch lâm khốn địa ngoài Thiên Vận Tông hơn mười ngàn dặm, và hứa truyền lại cho Vương Lâm sau khi mọi chuyện giải quyết xong.","nguon":["@c0459"]},{"id":"tran-phap-thach-lam-khon-dia","name":"Trận pháp thạch lâm khốn địa","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thiên Vận Tông","soHuu":["Đại sư huynh (Thiên Vận Tông)"],"blurb":"Trận pháp vây khốn do đại sư huynh bố trí trên thạch lâm, triệt tiêu mọi đòn công kích và ngăn thoát ra.","detail":"Trận pháp được khắc bằng những vết sâu trên các cự thạch trong thạch lâm, tạo màn sáng bạc bao phủ phạm vi mười dặm. Bên trong có lực cản đè từ trên xuống tương đương tu sĩ Anh Biến hậu kỳ toàn lực ra tay; kiếm quang và pháp bảo phóng ra đều ảm đạm rồi tan biến sau vài nhịp thở, người tu cũng không thể bay vượt qua biên giới thạch lâm. Vương Lâm thử phá bằng tiên kiếm, bay thẳng lên và cho Hứa Lập Quốc cùng loan đao lao tới đều thất bại.","nguon":["@c0459"]},{"id":"tu-vu-dai-tran","name":"Tử vụ đại trận","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Đại trận phòng ngự cấp tông","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tông"],"blurb":"Đại trận sương tím khổng lồ bao quanh Thiên Vận Tinh, có thể vận động hoặc tạm ngừng để mở thông đạo.","detail":"Trận sương tím bao trùm Thiên Vận Tinh, vận hành liên tục như hàng rào bảo vệ chủ tinh. Một tháng trước thọ yến, trận tạm ngừng vận động để đệ tử Thiên Vận Tông phái ra nghênh đón khách khắp nơi và mở thông đạo cho tu sĩ năm tiểu tinh cầu cùng lão quái các tiểu tu chân tinh tới chúc thọ.","nguon":["@c0460"]},{"id":"hu-that-nhi-y","name":"Hư Thật nhị ý","loai":"khac","loaiLabel":"Cảnh giới ý cảnh","phamCap":"Cảnh giới truyền thuyết","hePhai":"","soHuu":["Kim Ma tử"],"blurb":"Cảnh giới tu vi trong truyền thuyết, hiếm người chế phục được.","detail":"Cảnh giới ý cảnh truyền thuyết được nhắc đến trong giới tu sĩ vùng Thiên Vận Tinh. Tu vi loại thông thiên hoành hành ngang ngược như Kim Ma tử cũng chỉ có lời đồn đã đạt tới, cho thấy đây là một thang bậc cực cao mà ít ai vươn được.","nguon":["@c0460"]},{"id":"thuong-chi-luc","name":"Thượng chi lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tử hệ Thiên Vận Tông","soHuu":["Hứa Lập Quốc"],"blurb":"Thần thông của Hứa Lập Quốc, bấm quyết phóng khí vàng hóa thành đám cát.","detail":"Hứa Lập Quốc (nh�� sư huynh Tử hệ) bấm quyết phóng ra Thượng chi lực: khí vàng hóa thành đám cát lớn như bầy ong, tốc độ nhanh gấp mấy lần người thi triển, dùng để áp sát công kích. Trong trận với Vương Lâm, đám cát này bị Cấm Phiên tạo cơn lốc cấm chế đen xé tan.","nguon":["@c0462"]},{"id":"dai-tu-tai-thien-dia-quyet","name":"Đại tự tại thiên địa quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Tử hệ Thiên Vận Tông","soHuu":["Triệu Tinh Sát"],"blurb":"Công pháp của Triệu Tinh Sát, phát quầng sáng trắng bọc lấy mục tiêu.","detail":"Triệu Tinh Sát thi triển, tay phải liên tục phát ra quầng sáng trắng tản rộng bọc lấy mục tiêu để khống chế. Khi dùng để bọc ma hỏa của Vương Lâm, quầng sáng bị ma hỏa tự bạo thiêu vỡ trong ba nhịp thở.","nguon":["@c0462"]},{"id":"ma-hoa-vuong-lam","name":"Ma hỏa","cn":"","aliases":["Ma diễm"],"loai":"bi-thuat","loaiLabel":"Bí thuật tu ma","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Hỏa tu ma của Vương Lâm, đảo ngược tiên lực sinh ma hỏa, có thể tự bạo công kích.","detail":"Vương Lâm đảo ngược tiên lực sinh ma hỏa ở đầu ngón tay. Ma hỏa phóng ra có thể tự bạo, phát tiết ma khí và lửa tím công kích, sức hủy diệt quét ra nghìn trượng tạo hố lớn. Các tu sĩ nhận ra đây là ma diễm của người tu ma cao thâm, từ đó suy đoán thân phận của Vương Lâm.","nguon":["@c0462"]},{"id":"thuat-trieu-co-yeu","name":"Thuật triệu Cổ Yêu","cn":"","loai":"than-thong","loaiLabel":"Yêu thuật triệu hồn","phamCap":"Cấm thuật uy lực vượt cảnh giới","hePhai":"Bí thuật riêng của Triệu Tinh Sát","soHuu":["Triệu Tinh Sát"],"blurb":"Cấm thuật triệu hư ảnh cổ yêu trăm trượng; càng dùng càng tổn hại thân thể người thi triển.","detail":"Người thi triển bấm quyết niệm chú, ký hiệu cổ quái lóe giữa lông mày để gọi ra hư ảnh cổ yêu cao trăm trượng, hai sừng, thân ẩn sắc lam, móng tay như phi kiếm, phát khí yêu tà nồng đậm. Mỗi lần ký hiệu lóe thì hư ảnh càng rõ nhưng thân thể người thi triển càng suy yếu; dùng quá độ sẽ phun máu phản phệ. Triệu Tinh Sát vốn định để dành thuật này cho dịp tranh danh hiệu Thiên Vận Thất Tử nhưng buộc phải dùng trước để đối phó Vương Lâm.","nguon":["@c0463"]},{"id":"yeu-luc","name":"Yêu lực","cn":"","loai":"khac","loaiLabel":"Loại lực lượng","phamCap":"Vượt xa linh lực, ngang tiên lực và ma lực","hePhai":"Lực lượng của cổ yêu","soHuu":[],"blurb":"Khí tức cổ yêu phun ra, vượt xa linh lực và sánh ngang tiên lực, ma lực ma hỏa.","detail":"Khi cổ yêu điểm tay phun ra khí tức, Khương Thiên Tôn nhận ra đó không phải linh lực mà là “Yêu lực” — loại lực lượng vượt xa linh lực, sánh ngang tiên lực và ma lực ma hỏa của Vương Lâm. Yêu lực có thể tạo lốc xoáy đỏ hút linh hồn.","nguon":["@c0463"]},{"id":"cuu-chuyen-luyen-tien-quyet","name":"Cửu Chuyển Luyện Tiên Quyết","cn":"","loai":"bi-thuat","loaiLabel":"Cấm pháp / Tiên thuật phỏng tạo","phamCap":"Phỏng theo hạ phẩm tiên thuật","hePhai":"Tử hệ — Thiên Vận Tông","soHuu":["Vương Lâm","Thiên Vận Tử"],"blurb":"Cấm pháp vận dụng tiên lực theo phương thức quỷ dị, định hình xoắn ốc chín vòng trong cơ thể rồi phóng thích; tích càng lâu uy lực càng lớn.","detail":"Pháp thuật do sư tôn Thiên Vận Tử phỏng theo một hạ phẩm tiên thuật sáng tạo nên dù đạt chín vòng cũng chỉ tương đương uy lực ba vòng của tiên thuật thật. Khi vận chuyển, tiên lực hóa thành kim quang phân cấp nghiêm ngặt — kim tiên lực không cho tiên lực trắng tiếp cận. Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết, tu liên tiếp nhất chuyển (sinh luồng lực sắc bén), nhị chuyển (ba nén hương, sắc bén tăng gấp mười), tam chuyển (gần một canh giờ, đau đớn lục phủ ngũ tạng), cuối cùng ngưng tụ luồng kim tiên lực ở tay trái. Người muốn tu phải có tiên thể loại bỏ phàm cốt sau khi ngưng tiên lực.","nguon":["@c0464"]},{"id":"thuat-dai-na-di","name":"Thuật Đại Na Di","cn":"","aliases":["Cấm pháp dịch chuyển mười vạn dặm"],"loai":"bi-thuat","loaiLabel":"Cấm pháp di chuyển","phamCap":"Cấm pháp","hePhai":"Tử hệ — Thiên Vận Tông","soHuu":["Vương Lâm","Tứ sư tỷ (Tử hệ)"],"blurb":"Cấm pháp dịch chuyển mười vạn dặm, lợi dụng phong ấn bản thân khoảnh khắc trước dịch chuyển để bùng nổ khoảng cách gấp vô số lần.","detail":"Người thi triển lợi dụng khoảnh khắc trước dịch chuyển, dùng cấm pháp phong ấn bản thân để trong nháy mắt liên tục thi triển vài lần pháp thuật dịch chuyển; khi mở phong ấn các lần dịch chuyển đồng loạt bùng nổ, đẩy khoảng cách lên gấp vô số lần. Khi thi triển thân hư ảo, tay phải bấm ấn quyết tạo hào quang bạc, bước bảy bước trong cảm giác đáy biển sâu đông đặc, lực đạo hùng mạnh ngưng tụ rồi thân biến mất xuất hiện cách mười vạn dặm. Rủi ro: nắm không tốt thời gian phong ấn có thể đưa người vào khe không gian; định vị chính xác đòi hỏi thần thức Anh Biến Hậu Kỳ trở lên cộng thông thuộc địa hình. Khoảng cách dịch chuyển ngang ngửa Vấn Đỉnh tu sĩ.","nguon":["@c0464"]},{"id":"yeu-linh-than-thong","name":"Yêu linh (thần thông)","cn":"","aliases":["Yêu linh Triệu Sát Tinh"],"loai":"than-thong","loaiLabel":"Thần thông yêu dị","phamCap":"Tà dị","hePhai":"","soHuu":["Triệu Tinh Sát"],"blurb":"Vật yêu dị được cấy vào cơ thể, giống thần thông Cổ Thần — hại người hại mình, người thi triển chịu lực phản hồi lớn.","detail":"Yêu linh trong cơ thể Triệu Sát Tinh vừa hình thành đã gượng sử dụng, bị Xích Liệt khẳng định cần để sư phụ trừng phạt. Bản chất giống thần thông cổ thần, là vật hại người hại mình — người thi triển chịu lực phản hồi lớn. Đại sư huynh Tử hệ cũng bị sư tôn cấy yêu linh; nếu thức tỉnh sẽ khôi phục bản lãnh.","nguon":["@c0464"]},{"id":"sat-khi-huyet-tinh","name":"Sát Khí Huyết Tinh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cam Tông — Thiên Vận Tông","soHuu":["Người trung niên Cam Tông"],"blurb":"Thần thông/pháp thuật người trung niên Cam Tông dùng năm xưa khi đánh nhau với Sất Hổ ở tiên giới.","detail":"Pháp thuật được người trung niên đệ tử vị trí thứ tư Cam Tông (Thiên Vận Tông) sử dụng năm xưa ở tiên giới khi đối đầu Sất Hổ; thời điểm đó chủ nhân chưa tới Anh Biến, nay đã đạt Anh Biến Hậu Kỳ.","nguon":["@c0464"]},{"id":"thien-van-chi-dao","name":"Thiên Vận Chi Đạo","cn":"","loai":"cong-phap","loaiLabel":"Đạo pháp / Cảm ngộ thiên đạo","phamCap":"Đạo của tiên giả","hePhai":"Thiên Vận Tông","soHuu":["Thiên Vận Tử"],"blurb":"Đạo pháp cốt lõi của Thiên Vận Tử, lấy việc nghe theo mệnh trời làm gốc.","detail":"Thiên Vận Chi Đạo là cảm ngộ thiên đạo của Thiên Vận Tử, cốt lõi là ‘nghe theo mệnh trời’. Trong đại thọ vạn năm, ông đem đạo này ra giảng cho vô số tu sĩ, đồng thời mời người bất đồng quan điểm cứ đề xuất để cùng kiểm chứng. Đây là căn cơ làm nên địa vị thủy tổ của ông ở Thiên Vận Tinh.","nguon":["@c0465"]},{"id":"thien-thuat","name":"Thiên thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Bổn nguyên thần thông theo lý niệm cửu cửu quy nguyên chi vận mà Thiên Vận Tử đã lĩnh hội được chút ít.","detail":"Thiên Vận Tử coi thiên thuật là cửu cửu quy nguyên chi vận, là bổn nguyên thần thông của con đường mình tu, song mới chỉ hiểu được chút ít. Hắn gắn nó với học thuyết ba bước tu đạo: bước thứ ba truy cầu chữ ‘đạo’ chính là thiên vận — thiên vận đến thì tu thành, chưa tới thì hóa đất vàng, ngàn vạn năm thành số không.","nguon":["@c0466"]},{"id":"dan-tien-thuat","name":"Dẫn Tiên thuật","loai":"than-thong","loaiLabel":"Trung phẩm Tiên thuật","phamCap":"Trung phẩm Tiên thuật","hePhai":"","soHuu":["Thiên Vận Tử"],"blurb":"Trung phẩm Tiên thuật Thiên Vận Tử vô ý lấy được từ một tinh cầu bỏ hoang, vốn là thuật người Tiên giới dùng để đưa tu sĩ thăng lên Tiên giới.","detail":"Khi thi triển, người dùng bấm quyết phóng một đạo xích mang lên trời, không trung nổ vang và hiện ra một mảnh màu đỏ với mây cuộn như rồng giận dữ, sấm sét như hàng vạn con rắn bạc lan tỏa. Một cỗ thiên uy vô thanh giáng xuống khiến phần lớn tu sĩ tái mặt, phải hạ xuống khoanh chân ngồi. Tiên thuật vốn cực hiếm, trung phẩm càng hiếm; nghiên cứu cho thấy đây là thuật năm xưa người Tiên giới dùng đưa tu sĩ lên Tiên giới.","nguon":["@c0467"]},{"id":"cam-phap-mo-phong-tien-thuat","name":"Cấm pháp (mô phỏng tiên thuật)","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"Mô phỏng hạ phẩm tiên thuật","hePhai":"","soHuu":[],"blurb":"Pháp thuật mô phỏng theo hạ phẩm tiên thuật; uy lực đã rất cường đại nhưng vẫn kém xa Tiên thuật thật.","detail":"Trước khi chứng kiến Dẫn Tiên thuật, thứ uy lực cao nhất Vương Lâm từng thấy chỉ là loại Cấm pháp này — được mô phỏng từ hạ phẩm tiên thuật. So với Tiên thuật chân chính, Cấm pháp kém xa cả về uy thế lẫn thiên uy đi kèm.","nguon":["@c0467"]},{"id":"tam-chuyen-kim-tien-luc","name":"Tam chuyển kim tiên lực","loai":"khac","loaiLabel":"Lực lượng đặc thù","phamCap":"Kim tiên lực","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cỗ tiên lực đặc dị trong cánh tay trái Vương Lâm, có thể thả ra lưu chuyển toàn thân để chống lại sức hút và thiên uy của Tiên thuật.","detail":"Khi thiên uy của Dẫn Tiên thuật khiến tiên lực vốn có hỗn loạn, Vương Lâm vận tam chuyển kim tiên lực từ cánh tay trái cho lưu chuyển toàn thân, khống chế không để nó hòa lẫn với tiên lực thường, nhờ đó đứng vững lại. Riêng cỗ kim tiên lực này không bị Dẫn Tiên thuật dẫn dắt, cho thấy nó khác biệt với tiên lực thông thường.","nguon":["@c0467"]},{"id":"kim-tien-luc","name":"Kim tiên lực","loai":"khac","loaiLabel":"Linh lực tu luyện","phamCap":"Tiên lực","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Linh lực kim sắc Vương Lâm vận luyện, vận chuyển theo vòng để chống chịu áp lực và khôi phục.","detail":"Trong khảo nghiệm áp lực tại đại thọ Thiên Vận Tử, Vương Lâm vận chuyển kim tiên lực ba vòng để khôi phục sắc mặt sau khi trụ vững, biểu hiện vượt trội so với đa số đệ tử.","nguon":["@c0468"]},{"id":"yeu-anh-dao","name":"Yêu ảnh đạo","loai":"than-thong","loaiLabel":"Thần thông / Đạo","phamCap":"Đạo bản mệnh","hePhai":"Thiên Vận Tông","soHuu":["Triệu Hân Mộng"],"blurb":"Đạo bản mệnh của Triệu Hân Mộng; chỉ cần xem qua một thần thông của đối thủ tu vi không cao hơn nàng là bắt chước được một phần.","detail":"Yêu ảnh đạo là con đường tu hành của Tứ sư tỷ Triệu Hân Mộng. Đặc tính cốt lõi: chỉ cần nàng nhìn qua một thần thông của đối thủ — với điều kiện tu vi đối phương không cao hơn nàng — là có thể mô phỏng lại một phần (không hoàn toàn) thần thông đó. Nhờ đó nàng sáng chế ra Tử Ma thủ từ Hoá Ma chỉ của Vương Lâm.","nguon":["@c0469"]},{"id":"tu-ma-thu","name":"Tử Ma thủ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Vận Tông","soHuu":["Triệu Hân Mộng"],"blurb":"Thần thông Triệu Hân Mộng tự sáng chế bằng cách mô phỏng Hoá Ma chỉ của Vương Lâm qua Yêu ảnh đạo.","detail":"Triệu Hân Mộng vận Tử Ma thủ bằng cách bấm quyết điểm về phía trước: vô số tinh quang màu tím vờn quanh người rồi ngưng tụ bao bọc tay phải, sau đó nàng vỗ tay đẩy tử quang gào rít lao tới đối thủ. Thần thông này được mô phỏng một phần từ Hoá Ma chỉ của Vương Lâm thông qua Yêu ảnh đạo.","nguon":["@c0469"]},{"id":"hoang-tuyen-chi","name":"Hoàng tuyền chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Sát chiêu","phamCap":"","hePhai":"","soHuu":["Vương Lâm","Tư Đồ Nam"],"blurb":"Sát chiêu thứ ba và cuối trong ba sát chiêu của Tư Đồ Nam, thi triển bằng cách tiêu tan sinh mạng để mượn uy lực Hoàng tuyền.","detail":"Sát chiêu cuối trong ba sát chiêu Tư Đồ Nam truyền cho Vương Lâm. Muốn học phải nắm Hoàng tuyền thăng khiếu quyết, thông qua sinh mệnh tiến nhập Hoàng tuyền, biến chuyển sống-chết mà cảm ngộ. Tư Đồ Nam năm xưa giữa sống chết ở Hoàng tuyền kết hợp một bản hạ phẩm tiên thuật tàn khuyết mà bắt chước tạo ra, uy lực thua tiên thuật tàn khuyết thật không nhiều. Khi điểm ra, tiên lực không dao động, khí tức sinh mạng tiêu tan, trời tối sầm sét đánh, một bức tranh cuốn sơn thủy biểu thị Hoàng tuyền hiện ra rồi bụi khí dung hợp ngưng thành chỉ kích, kèm theo Sinh tử luân hồi ý cảnh. Đòi hỏi Anh Biến hậu kỳ trở lên mới dùng an toàn; Anh Biến sơ kỳ dùng sẽ bị cắn trả, Anh Biến trung kỳ miễn cưỡng dùng nhưng không thể dùng hết, chỉ Vấn Đỉnh mới tùy tâm thi triển.","nguon":["@c0471","@c0604"]},{"id":"tu-sac-quang-cau-tran-dao","name":"Tử sắc quang cầu","cn":"","loai":"bi-thuat","loaiLabel":"Thuật phòng ngự","phamCap":"","hePhai":"","soHuu":["Trần Đào"],"blurb":"Thuật phòng ngự tạo các quang cầu màu tím quanh thân, nổ tung khi bị tấn công.","detail":"Trần Đào bấm quyết tạo các quang cầu màu tím vây quanh thân để chống hắc mang của Hồn thú; các quang cầu nổ tung khi bị tấn công, nhưng vẫn khiến hắn chịu tổn thương và kêu đau.","nguon":["@c0471"]},{"id":"van-tam-chi-canh","name":"Vấn Tâm chỉ cảnh","aliases":["Vấn Tâm"],"loai":"khac","loaiLabel":"Cảnh giới tu tâm","phamCap":"Cực cao","hePhai":"Hệ tu tâm","soHuu":["Vương Lâm"],"blurb":"Cảnh giới tu tâm khi tâm lạnh tới mức vạn vật băng hàn cũng không thể đông lạnh thân tâm, ý chí bất khuất vờn quanh thân.","detail":"Một tầng cảnh giới tu tâm bộc lộ trong Toái Tiên chi địa: khi hàn khí cực dày xông vào kinh mạch nhưng bị thần thức từ nguyên thần quét lui, người tu nhận ra cái lạnh ngoại giới không lạnh bằng cái lạnh trong tâm mình. Sự lạnh lẽo trong lòng cùng ý chí bất khuất hợp lại thành then chốt vượt khảo nghiệm. Vương Lâm nhờ đó lĩnh ngộ Luân hồi đạo là đại Vô tình đạo và hiện Luân hồi Hoạ trục sau lưng. Thiên Vận Tử còn nghi vấn liệu tu thêm vạn năm có thể đột phá tới cảnh giới thứ ba sau Vấn Tâm.","nguon":["@c0472"]},{"id":"luan-hoi-dao","name":"Luân hồi đạo","aliases":["Luân hồi ý cảnh"],"loai":"khac","loaiLabel":"Ý cảnh đại đạo","phamCap":"Đại đạo","hePhai":"Hệ Luân hồi","soHuu":["Vương Lâm"],"blurb":"Đại đạo Vương Lâm lĩnh ngộ chính là đại Vô tình đạo, hiện thành Luân hồi Hoạ trục.","detail":"Tại Toái Tiên chi địa, Vương Lâm lĩnh ngộ rằng Luân hồi đạo chính là đại Vô tình đạo. Ý cảnh hiện thành Luân hồi Hoạ trục — bức tranh sơn thủy chỉ có hai màu đen trắng — xuất hiện sau lưng và có thể thu nhỏ xoay quanh đỉnh đầu, bao bọc toàn thân bằng một lực lượng kỳ dị. Trong trận đấu trước đó, ý cảnh này từng biến thành đạo Hoàng tuyền chỉ thứ hai công kích Trần Đào.","nguon":["@c0472"]},{"id":"chan-huyen-phap","name":"Chân huyễn pháp","loai":"bi-thuat","loaiLabel":"Huyễn thuật che giấu","phamCap":"Cao","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Pháp môn của Thiên Vận Tử tạo hai ngọn núi giả bên cạnh ngọn thật; tu vi Anh Biến trung kỳ rất khó nhìn ra.","detail":"Huyễn thuật che giấu của Thiên Vận Tử đặt tại Tổng tông ba ngọn núi: ngọn giữa là thật phủ bạch tuyết Cửu U chi hàn, còn hai sườn núi đen hai bên là giả do Chân huyễn pháp dựng nên. Ngọn giả bên trái có tuyết đen mà không kèm hàn khí (lộ vẻ quỷ dị), ngọn phải mơ hồ có sức sống. Tu sĩ Anh Biến trung kỳ nhìn ra được điểm giả là chuyện hiếm có, nên Thiên Vận Tử kinh ngạc tán thưởng khi Vương Lâm giải đúng.","nguon":["@c0472"]},{"id":"y-canh-nhap-the","name":"Ý cảnh nhập thể","cn":"","loai":"than-thong","loaiLabel":"Cảnh giới lĩnh ngộ","phamCap":"Đỉnh cao lĩnh ngộ Anh Biến kỳ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bước cụ thể hóa ý cảnh thành thực chất, dung một tia cảm ngộ vào tâm cảnh để vượt cực hạn và mở đường lên Vấn Đỉnh.","detail":"Ý cảnh là sự c�� thể hóa cảm ngộ qua sơ, trung, hậu kỳ; dưới cảm ngộ của tu sĩ Anh Biến kỳ thì ý cảnh hoàn toàn biến thành thực chất, cần một quá trình chứ không tức thời. Ý cảnh nhập thể là dung một tia cảm ngộ vào tâm cảnh để vượt qua cực hạn của bản thân, biểu hiện thành việc bước được càng nhiều bước trên nền tảng có sẵn. Vương Lâm nhờ đó bước hai mươi bảy bước, mở con đường tiến lên Vấn Đỉnh.","nguon":["@c0473"]},{"id":"than-thong-bay-mau-toi-hy-khau","name":"Thần thông bảy màu (Tối hỷ khẩu thất thải)","aliases":["Tối hỷ khẩu thất thải","Thần thông bảy màu"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấm pháp thần thông","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử"],"blurb":"Cấm pháp dùng bảy màu công kích; ánh sáng màu tím trong bảy màu có thể hoá vạn vật thành hư vô.","detail":"Một trong 3600 đạo Cấm pháp thần thông trong thế giới bảy màu. Thiên Vận Tử bắn ánh sáng bảy màu công kích, trong đó màu tím khiến mọi thứ hoá thành hư vô. Vương Lâm xem hết hơn phân nửa 3600 thần thông và coi đây là pháp thuật kỳ diệu, đáng sợ nhất, gần như định chọn nó trước khi chú ý tới Thiên Vận Tử áo xám.","nguon":["@c0474"]},{"id":"sat-luc-tien-quyet","name":"Sát Lục Tiên quyết","loai":"cong-phap","loaiLabel":"Tiên quyết","phamCap":"Tiên quyết (mô phỏng Tiên thuật)","hePhai":"Thiên Vận Tử áo xám","soHuu":["Thiên Vận Tử áo xám"],"blurb":"Tiên quyết bắt chước từ một loại Tiên thuật vô danh, dựa vào giết chóc đoạt sinh lực ngưng kết thành Sinh chi lạc ấn phòng thủ. (+) Công pháp thu hồi sinh lực ngay trong giết chóc; mỗi lần giết một sinh vật thu được một đạo bụi khí nghi là sinh lực. [CAN-SOAT-GOP]","detail":"Không phải Tiên thuật chân chính mà bắt chước từ một loại Tiên thuật vô danh. Người tu dựa vào giết chóc để đoạt sinh lực, sinh lực vờn quanh thân ngưng kết thành Sinh chi lạc ấn; lạc ấn càng nhiều thì phòng thủ càng mạnh — thân Thiên Vận Tử áo xám được hàng tỷ lạc ấn thủ hộ, dù Thiên Vận Tinh sụp đổ cũng bình yên vô sự. Điều kiện học là ‘xuất thủ không lưu người sống’; được cho là rất xứng với Sinh tử Luân hồi ý cảnh của Vương Lâm, song Vương Lâm từ chối học.","nguon":["@c0474","@c0479","@c0602"],"aliases":["#sat-luc-tien-quyet-tu-luyen"]},{"id":"sinh-chi-lac-an","name":"Sinh chi lạc ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật hộ thể","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ký hiệu màu xám trên mi tâm lan bao trùm toàn thân, giúp xuyên qua khói độc vô hại và di chuyển nhanh như điện. (+) Ấn pháp Vương Lâm đang suy diễn, đem sức sống (sinh lực thu được từ Sát Lục Tiên quyết) hóa thành ấn. (+) Ấn pháp hộ thể của Vương Lâm, có tác dụng phòng hộ rất lớn. [CAN-SOAT-GOP]","detail":"Sinh chi lạc ấn là một ấn pháp hộ thể Vương Lâm sở hữu, được hắn nhắc tới khi ngẫm về các thủ đoạn phòng thân; tác dụng phòng hộ rất lớn.","nguon":["@c0476","@c0479","@c0500"],"aliases":["#sinh-chi-lac-an-suy-dien","#sinh-chi-lac-an-than-thong"]},{"id":"thuat-thuan-di-ngan-mang","name":"Pháp thuật thuấn di ngân mang","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"Cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dịch chuyển khoảng cách cực lớn bằng cách bước trên không trung như lên bậc thang trời.","detail":"Vương Lâm vẽ trận lên không trung, thân thể nổi ngân mang, bước từng bước như leo bậc thang trời rồi dịch chuyển khoảng cách cực lớn; mỗi lần thi triển tạo dị tượng ngân mang phủ khắp bầu trời như một mặt trời bạc. Mười bước là cực hạn hắn chịu được; khi hiện thân sắc mặt tái nhợt, phải dùng đan dược mới hồi phục.","nguon":["@c0478"]},{"id":"kiem-phong-chi-cam","name":"Kiếm phong chi cấm","loai":"bi-thuat","loaiLabel":"Cấm thuật / Phong ấn","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Thạch Phương"],"blurb":"Cấm thuật phong ấn của Thạch Phương, phát động qua ngọc giản đỏ để giam giữ cả vùng sơn cốc.","detail":"Thạch Phương lấy ngọc giản màu đỏ, kết kiếm chỉ hô “Mở!” rồi “Phong!”. Ngọc giản bay vào sơn cốc tan thành vô số sợi tơ đỏ đan thành tấm lưới đỏ bao vây mục tiêu, kết hợp với kỳ hiệu điện quang tạo thành phong ấn nghiêm mật; dùng để phong ấn nam tử áo trắng cùng đàn Cửu Lê trùng trong phạm vi mấy trượng.","nguon":["@c0481"]},{"id":"tu-chuyen-ham-tien-luc","name":"Tứ chuyển hàm tiên lực","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên lực Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chiêu thức dùng kính tản tia sáng ngưng tụ kim sắc lốc xoáy chứa tiên lực, vỗ ra phá tan kiếm quang đối thủ.","detail":"Vương Lâm khuếch tán tiên lực bao phủ sơn cốc, dùng một chiếc kính tản vô vàn tia sáng tụ thành kim sắc lốc xoáy trong lòng bàn tay rồi hô “Tứ chuyển, hàm tiên lực!”, vỗ ra phá tan kiếm quang của Thạch Phương, gây nứt vỡ địa hình, vách núi sụp đổ.","nguon":["@c0483"]},{"id":"doat-xa-sieu-toc","name":"Đoạt xá siêu tốc","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thạch Phương","soHuu":["Thạch Phương"],"blurb":"Phương pháp đoạt xá cực nhanh, gần như hoàn thành chiếm thân và khôi phục thần trí tức thì.","detail":"Khác với đoạt xá thường mất rất lâu để dung hợp (Tư Đồ Nam đoạt kim cũng cần hơn một ngày), bí pháp của Thạch Phương cho phép xuyên phi kiếm qua mi tâm vật chủ rồi đoạt xá gần như tức khắc, hồi phục thần trí ngay khiến Vương Lâm kinh ngạc. Thạch Phương ghi lại vào ngọc giản, kèm thần thông mượn xử nữ chữa thương.","nguon":["@c0483"]},{"id":"phuong-phap-dieu-hoa-do-ti","name":"Phương pháp điều hoà (ký ức Đồ Ti)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật Cổ Thần","hePhai":"Ký ức Cổ Thần Đồ Ti","soHuu":["Vương Lâm"],"blurb":"Thủ pháp cổ quái thừa kế trong ký ức Đồ Ti, dùng Chú ngôn ép linh quả héo rũ thành linh căn cấp tốc thay vì chờ chu kỳ tự nhiên.","detail":"Người thi triển kết thủ ấn cổ quái bằng tay trái (không phải pháp quyết của tu sĩ) rồi thốt Chú ngôn như tiếng ‘Một!’, phóng ánh sáng vàng làm nổ lần lượt các ngọc giản dẫn đặt cạnh hoa, ép hoa, quả và cành cây héo rũ tan thành chất lỏng dung nhập xuống đất để hình thành linh căn dưới gốc. Cổ Thần nguyên bản dùng xương cốt yêu thú làm vật dẫn; Vương Lâm thay bằng ngọc giản nên hiệu quả kém hơn, thu được bốn linh căn thay vì năm.","nguon":["@c0484"]},{"id":"tam-phan-than-thuc-thuat","name":"Tam phân thần thức thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Lão già thấp người (Trưởng lão Đại La Kiếm Tông)"],"blurb":"Bí thuật cho phép người tu tái sinh ba lần sau khi bị giết.","detail":"Công pháp do lão già thấp người của Đại La Kiếm Tông tu luyện, cho phép tái sinh tối đa ba lần. Sau khi bị loan đao của Vương Lâm xuyên đầu, lão dùng lần tái sinh cuối cùng: khoảng ba nén nhang sau lão mở mắt, vết thương mi tâm tự khép lại. Tuy nhiên ngay sau đó lão bị khí xám Sát lục tiên quyết truy sát hút sạch sức sống, không còn cơ hội tái sinh.","nguon":["@c0485"]},{"id":"yeu-linh-quan-dinh","name":"Yêu Linh quán đính","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Ban thưởng","phamCap":"","hePhai":"Đông Hải Yêu Linh chi môn","soHuu":[],"blurb":"Phần thưởng quý giá của Đông Hải Yêu Linh chi môn: cưỡng ép tu vi tăng một cảnh giới và hỗ trợ đột phá Vấn Đỉnh.","detail":"Chỗ tốt chân chính khi đi ra khỏi Đông Hải Yêu Linh chi môn là được Yêu Linh quán đính một lần. Quán đính cưỡng ép tu vi tăng một cảnh giới; nếu đúng lúc Vấn Đỉnh thì cơ hội đạt Vấn Đỉnh tăng vô số lần; đã đạt Vấn Đỉnh thì bước thêm một bước; tới Vấn Đỉnh hậu kỳ thì sau quán đính có thể đột phá vào Âm Dương nhị ý, thọ mấy vạn năm, thân thể bất diệt. Tục truyền nếu chỉ một người duy nhất đi ra thì còn được ban một loại hạ phẩm tiên thuật hoàn chỉnh chưa từng xuất hiện.","nguon":["@c0485"]},{"id":"huyet-cong-dieu-tinh-hai","name":"Huyết Công","cn":"","loai":"cong-phap","loaiLabel":"Ma công","phamCap":"Không rõ","hePhai":"Huyết hệ","soHuu":["Huyết Tổ Diêu Tinh Hải","Diêu Tích Tuyết"],"blurb":"Ma công huyết hệ của Huyết Tổ Diêu Tinh Hải, thi triển trong lần thứ bảy khiêu chiến Thiên Vận Tử khiến người kinh sợ.","detail":"Công pháp trấn gia của Huyết Tổ, tu luyện bằng cách nạp huyết trên Huyết Tinh. Huyết Tổ đem toàn bộ công pháp này truyền cho con gái Diêu Tích Tuyết rồi nghịch thiên cải mệnh cho nàng.","nguon":["@c0486"]},{"id":"tran-phap-tinh-khong-huyen-uyen","name":"Trận pháp tinh không (Huyền Uyên phái)","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"","hePhai":"Huyền Uyên phái","soHuu":["Tôn Vân Sơn"],"blurb":"Trận pháp truyền tống trong tinh không của Huyền Uyên phái, dùng để di chuyển tới Đông Hải Yêu Linh.","detail":"Đại trận truyền tống đặt trong tinh không; khi khởi động cần dùng lượng lớn tinh thạch và tiên ngọc, đồng thời mấy trăm đệ tử cùng vận chuyển linh lực dung nhập. Khi bùng nổ, trận tạo ra một cầu vồng cao trăm trượng đâm thẳng vào tầng mây, đưa người dùng di chuyển tới cửa Đông Hải Yêu Linh ở tinh không phía đông.","nguon":["@c0487"]},{"id":"bi-thuat-nhot-kiem-hon-kiem-ton","name":"Bí thuật nhốt kiếm hồn (Kiếm Tôn)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Kiếm Tôn"],"blurb":"Bí thuật Lăng Thiên Hậu dùng để nhốt đạo kiếm hồn của nữ quân tiên giới vào trong Đông Hải Yêu Linh.","detail":"Năm xưa Kiếm Tôn bị một đạo kiếm hồn uy lực kinh người làm phiền không dứt; do không khống chế được, lão dùng bí thuật này nhốt kiếm hồn lại trong Đông Hải Yêu Linh, và còn định mượn thủy triều năm nghìn năm một lần để hút nó chìm sâu vĩnh viễn.","nguon":["@c0487"]},{"id":"am-duong-hu-thuc-nhi-y","name":"Âm Dương Hư Thực Nhị Ý","cn":"","loai":"khac","loaiLabel":"Ý cảnh / điều kiện đột phá","phamCap":"","hePhai":"","soHuu":[],"blurb":"Lĩnh hội liên quan tới việc đột phá tầng hạn chế thọ nguyên và tiến vào Đông Hải Yêu Linh.","detail":"Là điều kiện then chốt để vượt qua tầng hạn chế thọ nguyên: tu sĩ không lĩnh hội tiến vào được thì thọ nguyên không thăng hoa, không sống quá năm nghìn năm. Việc tiến vào Đông Hải Yêu Linh cũng liên quan tới nhị ý này.","nguon":["@c0487"]},{"id":"thuong-pham-tien-thuat","name":"Thượng phẩm tiên thuật (hoàn chỉnh)","cn":"","loai":"khac","loaiLabel":"Tiên thuật","phamCap":"Thượng phẩm","hePhai":"Tu Chân Liên Minh","soHuu":[],"blurb":"Tiên thuật cấp cao nhất, loại hoàn chỉnh được Tu Chân Liên Minh treo làm phần thưởng truy tìm hạt châu.","detail":"Một bộ thượng phẩm tiên thuật hoàn chỉnh là phần thưởng lớn chưa từng có mà Tu Chân Liên Minh đưa ra từ khi thành lập, treo cho ai tìm được hạt châu mấy vạn năm trước. Theo manh mối Tham Lang nắm được, loại tiên thuật hoàn chỉnh trong Tu Chân Liên Minh tuyệt đối không quá mười bộ, cho thấy mức độ trân quý và hiếm có của nó.","nguon":["@c0488"]},{"id":"than-thong-anh-mat-khi-xam","name":"Thần thông ánh mắt khí xám (Ba đạo ấn ký)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hệ Cổ Thần khí xám","soHuu":["Vương Lâm"],"blurb":"Thần thông gắn với khí xám hệ Cổ Thần của Vương Lâm: ba đạo ấn ký trên mi tâm cấp lực cho ánh mắt để xuyên phá thứ ngăn cản thần thức và tầm nhìn.","detail":"Khi vận thần thông, ba đạo khí xám hiện trên mi tâm Vương Lâm rồi hóa thành ba ấn ký phức tạp, theo hai mắt cuộn thành vòng tròn mịn khiến đồng tử phát luồng sáng như ánh trăng, vệt sáng dài chừng nửa thước. Ánh mắt biến thành thần quang xuyên qua hư vô, có thể đuổi theo và đâm thủng những thứ chặn cả thần thức lẫn ánh mắt thăm dò; khí xám hóa thành tơ chui vào đồng tử tiếp sức liên tục. Cái giá là đôi mắt đỏ bừng, chảy nước mắt lẫn máu, tim đau dữ dội. Tại cửa Đông Hải Yêu Linh, ánh mắt hắn cuối cùng nổ tung phá vỡ tầng tầng hồng quang để nhìn rõ khối lệnh bài bên trong.","nguon":["@c0490"]},{"id":"tran-phap-an-giau-khi-tuc-son-coc","name":"Trận pháp ẩn giấu khí tức sinh mạng (sơn cốc)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Tu sĩ thời kỳ thượng cổ","soHuu":[],"blurb":"Trận pháp do tu sĩ thượng cổ dùng đại thần thông bố trí ngoài sơn cốc, ẩn giấu mọi khí tức sinh mạng và phòng vệ bằng khí xanh thôn phệ.","detail":"Bố trí bên ngoài một sơn cốc trong vùng Đông Hải yêu linh, đã tồn tại vô số năm. Trận pháp ẩn giấu mọi khí tức sinh mạng nên rất khó phát hiện nếu không ở thật gần. Có chức năng phòng vệ: khi bị tấn công liền phóng ra luồng khí xanh thôn phệ linh quang, kẻ mạnh xông vào sẽ bị giết sạch. Thủ pháp hoàn toàn khác với tu sĩ liên minh tu chân; Vương Lâm trong thời gian ngắn không thể phá giải.","nguon":["@c0492"]},{"id":"thuong-co-tran-phap-son-coc","name":"Thượng cổ trận pháp (cổ cấm chế sơn cốc)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Bộ tộc sơn cốc","soHuu":["Âu Dương Hoa"],"blurb":"Trận pháp thượng cổ bảo vệ sơn cốc bộ tộc Âu Dương Hoa, có thể hút kéo vạn vật ngưng thành hư ảnh người công kích.","detail":"Cổ cấm chế bao quanh sơn cốc, chống đỡ thanh quang và cấm khí công phá. Khi bị kích phát mạnh, trận vận chuyển dùng thanh quang dày đặc bao phủ vạn vật ngoài cốc, hút kéo sinh lực mọi thứ về trong cốc, ngưng tụ thành một bóng người hư ảo màu xanh cao mấy trượng, mờ ảo không rõ tướng mạo, dùng để giết kẻ địch và lấy hồn phách tế yêu linh. Vương Lâm phải nghiên cứu cổ cấm chế hồi lâu mới tìm ra cách phá.","nguon":["@c0493"]},{"id":"cam-phap-chi-mau","name":"Cấm pháp chi mâu","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Cấm pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật Vương Lâm triệu cấm khí đen ngưng tụ thành trường mâu ba trượng, vung ra hóa tia chớp đen công kích.","detail":"Vương Lâm bắt quyết hô “Cấm pháp chi mâu”, triệu cấm khí màu đen như du long từ chân trời bay tới kèm tiếng gào khóc, ngưng tụ trên tay thành một thanh trường mâu đen dài ba trượng — gợn sóng đen, tiếng sấm rền, u quang ở lưỡi mâu. Vung mâu hóa thành tia chớp đen lao thẳng vào mục tiêu, dùng nghênh chiến hư ảnh xanh do trận pháp sơn cốc tạo ra.","nguon":["@c0493"]},{"id":"thuong-co-cam-che-co-than","name":"Thượng cổ cấm chế của cổ thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thượng cổ","hePhai":"Cổ thần","soHuu":["Vương Lâm"],"blurb":"Sở học cấm chế thượng cổ Vương Lâm kế thừa từ cổ thần năm xưa, ghép phù văn thành tổ hợp cấm chế để phá trận.","detail":"Loại thủ pháp ra đời từ thời cực xa xưa, ngay cả thượng cổ tu sĩ cũng chỉ nắm được chứ không sáng tạo thêm. Khi vận dụng, các phù văn hợp-tản-hợp như vòng tròn luân hồi, tách thành mấy chục cấm chế giống nhau rồi tổ hợp lại phóng ra. Tại sơn cốc Âu Dương Hoa, Vương Lâm tính toán dần từ năm mươi bảy lên tám mươi ba tổ hợp cấm chế, phóng các đạo phù văn yêu dị từ trong hai mắt tạo sóng gợn hủy diệt thanh mang, phá tan lồng thanh quang thượng cổ.","nguon":["@c0494"]},{"id":"truong-mau-cam-khi","name":"Trường mâu cấm khí","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Cấm khí của Vương Lâm biến hóa thành trường mâu phá không lao nhanh như sấm sét, chủ yếu dùng để câu giờ.","detail":"Cấm khí Vương Lâm biến ảo thành hình trường mâu, lao đi cực nhanh đánh vào thanh ảnh của trận pháp. Mục đích chính không phải sát thương mà là câu giờ để hắn tính toán cấm chế phá trận. Tại sơn cốc Âu Dương Hoa, trường mâu bị lồng thanh quang phân thành hai và hủy đi, nhưng Vương Lâm không tiếc vì đã đạt mục đích câu giờ.","nguon":["@c0494"]},{"id":"tran-phap-son-coc","name":"Trận pháp sơn cốc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp cổ bao quanh sơn cốc tộc Âu Dương Hoa, tồn tại từ vô số năm trước, bảo vệ tộc nhân khỏi yêu linh.","detail":"Trận pháp đã có mặt từ trước khi Hoàng Long dẫn tổ tiên Âu Dương Hoa đến định cư, không ai nhớ nguồn gốc. Lực lượng bảo vệ của trận từng dần tiêu tán khiến tộc nhân lo bại lộ dưới đêm yêu linh; Vương Lâm chỉ cần giơ tay điểm lên hư không tạo một đợt sóng gợn như tấm vải là khôi phục lại, làm tốc độ tiêu tán chậm dần rồi ngừng hẳn.","nguon":["@c0495"]},{"id":"hap-thu-yeu-luc","name":"Hấp thu yêu lực","cn":"","loai":"luyen-the","loaiLabel":"Luyện hóa","phamCap":"","hePhai":"Nơi yêu linh","soHuu":["Vương Lâm"],"blurb":"Cách hấp thu khí tức yêu lực từ ngọc yêu linh: khí tức cực lạnh chạy theo các khớp xương chứ không qua kinh mạch, tụ tại đan điền thành tinh thể.","detail":"Khi Vương Lâm hấp thu ngọc yêu linh, một khí tức cực lạnh theo tay phải chui vào cơ thể, không đi trong kinh mạch như linh lực thông thường mà chạy dọc các khớp xương, cuối cùng tụ lại đan điền hóa thành tinh thể cỡ hạt gạo, khí tức xoay tròn như tinh vân. Thứ khí tức trắng này trông như tiên lực nhưng trong vẻ ôn hòa lại lộ sự yêu dị cực kỳ; sau khi hấp thu, toàn thân Vương Lâm có biến hóa cực kỳ rõ ràng, gợi mở một con đường biến hóa mới.","nguon":["@c0496"]},{"id":"tran-phap-ho-lo-coc","name":"Trận pháp Hồ Lô Cốc","cn":"","loai":"khac","loaiLabel":"Trận pháp phòng thủ","phamCap":"","hePhai":"Hồ Lô Cốc","soHuu":["Âu Dương Hoa"],"blurb":"Trận pháp bảo vệ thung lũng Hồ Lô Cốc, tỏa thanh quang chống sóng yêu khí trong đêm Yêu linh săn mồi.","detail":"Trận pháp bao bọc thung lũng Hồ Lô Cốc, mỗi khi đêm Yêu linh săn mồi (ba tháng một lần) ập tới thì mở thanh quang chống cự sóng yêu khí cuồng nộ. Trận do Âu Dương Hoa giơ tay niệm chú duy trì. Trong chương này trận đã bị Vương Lâm tiêu hao hơn nửa nên Âu Dương Hoa không chắc chống nổi; khi một vật nặng va vào, nhiều chỗ trận vỡ tan.","nguon":["@c0497"]},{"id":"dia-diet-chi-hoa","name":"Địa diệt chi hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông hỏa hệ","phamCap":"","hePhai":"","soHuu":["La mỗ"],"blurb":"Hỏa thuật hắc y nam tử triệu trên lòng bàn tay trái, ngọn lửa đen che phủ trời đất.","detail":"La mỗ bấm thần chú, lòng bàn tay trái hiện ngọn lửa đen, hô “Địa diệt chi hỏa, nhiên tận hư vô”. Ngọn lửa bay lên không trung che phủ trời đất, hóa thành sáu con rồng lửa (Viêm Long) gầm vang như Thiên Lôi xông tới cắn xé đối phương.","nguon":["@c0498"]},{"id":"kiem-toai-la-mo","name":"Kiếm toái","cn":"","loai":"kiem-quyet","loaiLabel":"Cấm thuật kiếm","phamCap":"","hePhai":"","soHuu":["La mỗ"],"blurb":"Cấm thuật khiến tế kiếm vỡ vụn thành vô số mảnh nổ tung lao về đối phương.","detail":"La mỗ quát “Kiếm toái”, tế kiếm lập tức vỡ thành vô số mảnh nhỏ nổ tung, đồng loạt lao về phía Vương Lâm như mưa kiếm sát thương.","nguon":["@c0498"]},{"id":"ma-cam","name":"Ma cấm","loai":"bi-thuat","loaiLabel":"Cấm thuật ma đạo","hePhai":"Ma đạo","soHuu":["La mỗ (Hắc y nhân)"],"blurb":"Cấm thuật ma đạo hút khói đen vào ngực, biến tay trái thành mười Quỷ ảnh quái dị để công kích.","detail":"Thi triển bằng cách ấn tay vào ngực hút khói đen vào người, chịu đau tột độ tới mức da nổi gân xanh mụn sần, mắt đầy tơ máu rồi gào thét chấn động (nguyên thần cảm được dù không thành tiếng), đánh văng vật chất quanh mình tạo khoảng trống. Khẩu quyết “Ma cấm, thiên quỷ đệ tứ tôn, hiện!” khiến lực kỳ dị từ ngực chảy qua cánh tay, tay trái mọc xúc tu biến thành mười Quỷ ảnh đen nhe răng cười, mắt tràn hàn quang, có thể nuốt kiếm quang. Cấm thuật gây phản phệ rõ rệt lên người thi triển.","nguon":["@c0499"]},{"id":"huyet-sac-ngu-sat","name":"Huyết sắc ngũ sát","loai":"bi-thuat","loaiLabel":"Cấm pháp phong ấn","soHuu":["La mỗ (Hắc y nhân)"],"blurb":"Cấm pháp tạo năm điểm đỏ đan thành lưới năm sao phong ấn pháp bảo của kẻ thù.","detail":"Năm ngón tay tạo năm điểm đỏ di động, đan thành lưới năm sao, hô “Cấm” để phong ấn pháp bảo đối phương. Trong trận với Vương Lâm, lần đầu thất bại khi định phong ấn Côn Cực Tiên: roi tiên phát hắc mang lan tới tay phải khiến tay bốc khói trắng, đau đớn.","nguon":["@c0499"]},{"id":"phong-than-chu-goi-gio","name":"Phong (thần chú gọi gió)","loai":"than-thong","loaiLabel":"Thần chú","soHuu":["Vương Lâm"],"blurb":"Thần chú bấm tay niệm chú gọi gió quái lạ và mây đen phá màn sương độc.","detail":"Vương Lâm bấm tay niệm chú, gọi gió quái lạ cùng mây đen phá vỡ màn sương độc do Hắc y nam tử phun ra, đồng thời hóa thân thành làn mây thoát ra ngoài.","nguon":["@c0499"]},{"id":"hoa-ma-chi","name":"Hóa ma chỉ","loai":"than-thong","loaiLabel":"Thần thông / Sát chiêu","phamCap":"Sát chiêu trục","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chiêu thứ hai trong Tam thức sát chiêu của Vương Lâm — tiên lực nghịch chuyển ngưng tụ thành ma khí ở đầu ngón trỏ.","detail":"Hóa ma chỉ là chiêu thứ hai trong bộ Tam thức sát chiêu của Vương Lâm. Khi thi triển, tiên lực bị nghịch chuyển và chuyển hóa, ngưng tụ thành ma khí dày đặc ở đầu ngón trỏ; ma khí khuếch tán mãnh liệt, ngón tay trở nên linh hoạt sắc bén. Vương Lâm từng dùng chiêu này đấu với Tử hệ lão Tứ. Khi hai Hóa ma chỉ (của Vương Lâm và khói đen của đối thủ) va chạm sẽ hình thành tiểu cầu chứa điện quang như Thiên kiếp tiên lôi.","nguon":["@c0500"],"aliases":["#hoa-ma-chi-tam-sat"]},{"id":"tam-thuc-sat-chieu","name":"Tam thức sát chiêu","loai":"cong-phap","loaiLabel":"Bộ sát chiêu","phamCap":"Sát chiêu trục","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Bộ ba sát chiêu của Vương Lâm; Hóa ma chỉ là chiêu thứ hai.","detail":"Tam thức sát chiêu là bộ ba sát chiêu Vương Lâm thường dùng trong giao đấu sinh tử, trong đó Hóa ma chỉ là chiêu thứ hai. Bộ chiêu này từng được Vương Lâm thi triển trong các trận sinh tử và lưu lại ấn tượng mạnh nơi người xem.","nguon":["@c0500"]},{"id":"cuu-tu-chan-ngon","name":"Cửu Tự Chân Ngôn","loai":"bi-thuat","loaiLabel":"Chân ngôn khống chế","phamCap":"Truyền thừa tiên nhân","hePhai":"Di sản tiên nhân","soHuu":["Vương Lâm"],"blurb":"Chín chữ chân ngôn từ Ngọc giản của tiên nhân, dùng khống chế Hồn thú trong Xạ Thần Xa.","detail":"Cửu Tự Chân Ngôn gồm chín chữ chân ngôn Vương Lâm học được từ Ngọc giản của một vị tiên nhân. Chân ngôn dùng để khống chế con Hồn thú bất khuất, vốn không nghe lời, bị phong ấn trong Xạ Thần Xa: mỗi đạo phong ấn mở ra cần nắm một chữ chân ngôn. Việc Vương Lâm chỉ nắm phần chân ngôn khống chế gợi mở mối liên hệ giữa hắn với di sản, truyền thừa của vị tiên nhân luyện bảo.","nguon":["@c0500"]},{"id":"thuat-khong-che-quy-anh-to-den","name":"Thuật khống chế Quỷ ảnh","loai":"bi-thuat","loaiLabel":"Bí thuật khống quỷ","phamCap":"Công pháp môn phái","hePhai":"Môn phái Hắc y nam tử","soHuu":["Hắc y nhân (mặt sẹo)"],"blurb":"Dùng tơ mảnh màu đen từ ngực và tay để thu hồi và khống chế Thiên Quỷ.","detail":"Bí thuật của Hắc y nam tử dùng những sợi tơ mảnh màu đen tỏa ra từ ngực và tay để thu hồi, khống chế Thiên Quỷ (Quỷ ảnh). Khi thi triển, hắn phải đặt tay phải trên ngực để giữ thuật quỷ ảnh khỏi bị phá vỡ. Trong trận với Vương Lâm, thuật này không giữ nổi Thiên Quỷ vốn đã hạ quyết tâm bỏ trốn.","nguon":["@c0500"]},{"id":"ton-than-thuat","name":"Tổn Thần thuật","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thiên Quỷ Đạo","soHuu":["La Vân"],"blurb":"Pháp môn hao tổn tinh hoa nguyên thần vĩnh viễn không khôi phục để bùng tốc độ bỏ trốn.","detail":"Khi nguyên thần lâm nguy, thuật này đốt tinh hoa nguyên thần (tổn thất vĩnh viễn, không thể khôi phục) để bùng nổ tốc độ tháo chạy. La Vân dùng để thoát khỏi quỷ phong của hồn thú nhưng vẫn bị Vương Lâm bắt kịp.","nguon":["@c0501"]},{"id":"bi-thuat-luyen-thien-quy","name":"Bí thuật luyện Thiên quỷ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Thiên Quỷ Đạo","soHuu":["Thiên Quỷ Đạo"],"blurb":"Bí thuật của Thiên Quỷ Đạo để bắt một Thiên Quỷ làm bản mạng quỷ linh.","detail":"Dùng máu phụ nữ có thai làm chất dẫn, nhiệt huyết thanh niên dẫn dắt, nguyên thần tu sĩ triệu tập; trải bảy bảy bốn mươi chín năm mới hấp dẫn được một Thiên Quỷ sinh ra từ hư vô, rồi dùng bí thuật bắt làm bản mạng quỷ linh phòng thân.","nguon":["@c0502"]},{"id":"thuat-bui-khi-hoa-han-quang","name":"Thuật đám bụi khí hóa hàn quang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm dùng diệt Thiên quỷ: bụi khí thét gào lao như rồng rồi hóa vô số tia hàn quang bám lấy mục tiêu.","detail":"Vương Lâm vẽ tay vào hư không khiến đám bụi khí thét gào lao vào rãnh sâu như con rồng; bụi khí tiêu tan rồi hóa nhiều tia hàn quang khuếch tán bám lấy mục tiêu, hết đám này tới đám khác ngưng tụ đánh tới liên hồi, chẳng mấy chốc phủ đầy tro bụi lên thân đối phương.","nguon":["@c0502"]},{"id":"luyen-hon-tong-tam-mon","name":"Luyện Hồn Tông pháp thuật (tam môn)","cn":"","loai":"cong-phap","loaiLabel":"Hệ pháp môn","phamCap":"","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm"],"blurb":"Hệ pháp môn của Luyện Hồn Tông gồm ba môn luyện hồn, trừu phách và tỏa thần.","detail":"Pháp thuật trục của Luyện Hồn Tông chia làm ba môn. Luyện hồn là luyện hóa linh hồn có sẵn để rút phách hoặc hút linh hồn người sống; trừu phách và luyện hồn là căn bản của tông; tỏa thần do các thế hệ chính thống tu luyện, vốn là phương pháp dùng để điều khiển Thập Ức Tôn Hồn Phiên. Luyện ra được hồn phiên là điều kiện chính thức để thành đệ tử của tông.","nguon":["@c0503"]},{"id":"thuat-hon-phien","name":"Thuật hồn phiên","cn":"","loai":"bi-thuat","loaiLabel":"Pháp thuật","phamCap":"","hePhai":"Luyện Hồn Tông","soHuu":["Vương Lâm"],"blurb":"Thuật Vương L��m định truyền cho cư dân thung lũng: dễ nhập môn, hợp việc chết chóc.","detail":"Thuật chế tác và dùng hồn phiên mà Vương Lâm dự định truyền cho cư dân sơn cốc nhằm gây dựng lực lượng riêng. Đặc tính dễ nhập môn, càng giết chóc càng tụ nhiều hồn phách làm tăng thực lực. Khẩu quyết bước đầu được lưu vào ngọc giản, nhưng Vương Lâm cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử thành vật của mình.","nguon":["@c0503"]},{"id":"phuong-phap-che-hon-phien-thay-the","name":"Phương pháp chế hồn phiên thay thế","cn":"","loai":"bi-thuat","loaiLabel":"Phép chế tác","phamCap":"","hePhai":"Luyện Hồn Tông nhất mạch","soHuu":["Vương Lâm","Thập Tam","Âu Dương Hoa"],"blurb":"Cách chế hồn phiên ứng biến do Vương Lâm sáng tạo khi thiếu tài liệu ở Thiên Vận Tinh.","detail":"Do tài liệu nơi yêu linh cực kỳ thiếu khuyết, Vương Lâm dùng cươn thụ chi mộc kết hợp da dã thú ngưng hóa bằng yêu lực và thủ ấn để miễn cưỡng bắt chước hiệu quả hồn phiên. Thứ thay thế này chỉ phong ấn được không quá mười hồn phách; thi triển đồng thời mười hồn phiên thì đạt một nửa uy lực của bách hồn phiên. Bên trong có một sơ hở trí mạng chỉ mình Vương Lâm biết.","nguon":["@c0505"]},{"id":"co-che-khong-che-hon-thu-vuong-lam","name":"Sơ hở khống chế hồn thú","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế cài sẵn","phamCap":"","hePhai":"Luyện Hồn Tông nhất mạch (đã cải biến)","soHuu":["Vương Lâm"],"blurb":"Backdoor Vương Lâm cài vào Luyện Hồn Thuật để khống chế mọi hồn thú do người học phong ấn.","detail":"Vương Lâm cố ý cải biến Luyện Hồn Thuật và phương pháp chế hồn phiên, gài một sơ hở cài sẵn lên cả công pháp lẫn hồn phiên. Hệ quả là mọi hồn thú do người học thuật (đã bị hắn cải biến) phong ấn đều bị Vương Lâm hoàn toàn điều khiển và chấn nhiếp, nắm quyền sinh sát toàn bộ lực lượng Luyện Hồn ở Thiên Vận Tinh. Khi sư tử cánh dài của Thập Tam phản phệ, chỉ một tiếng hừ của Vương Lâm đã khiến nó tan nát rồi thuần phục.","nguon":["@c0505"]},{"id":"tran-phap-vien-co-thien-thuy","name":"Trận pháp viễn cổ bộ lạc Thiên Thủy","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Viễn cổ","hePhai":"Bộ lạc Thiên Thủy","soHuu":["Bộ lạc Thiên Thủy"],"blurb":"Trận pháp viễn cổ phủ mười dặm, mạnh hơn trận thung lũng một bậc; ban đêm Yêu Linh hạ xuống vẫn an toàn.","detail":"Phản kích bằng sóng gợn màu xanh; hấp thu tổn thương chuyển thành phòng ngự tạo vòng tuần hoàn khó phá trong thời gian ngắn. Vương Lâm dùng Khai Thiên phủ chém vẫn không phá nổi nên phải đào vòng quanh ven trận rồi nhổ cả mảnh đất mười dặm.","nguon":["@c0507"]},{"id":"tran-phap-luyen-hon-hai-muoi-dam","name":"Trận pháp Luyện Hồn (hai mươi dặm)","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Cải biên","hePhai":"Bộ lạc Luyện Hồn","soHuu":["Vương Lâm","Bộ lạc Luyện Hồn"],"blurb":"Trận bảo vệ phạm vi hai mươi dặm do Vương Lâm dung hợp ba trận pháp để che chở bộ lạc Luyện Hồn.","detail":"Dung hợp trận cấm chế làm căn bản với trận thung lũng cũ và trận pháp mảnh đất mười dặm cướp từ bộ lạc Thiên Thủy, mở rộng phạm vi bảo vệ thành hai mươi dặm.","nguon":["@c0507"]},{"id":"thap-bang-chien-y","name":"Thập Băng Chiến Ý","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cực hiếm thấy","hePhai":"Tả dực Yêu tương (Yêu linh chi địa)","soHuu":["Tả dực Yêu tương"],"blurb":"Thần thông của Tả dực Yêu tương: mười quyền đánh vào hư không, gồm mười lần biến hóa sụp đổ chồng chất.","detail":"Tả dực Yêu tương đánh mười quyền cực nhanh vào hư không, các quyền không có thực chất mà dung nhập vào hư vô, gồm mười lần biến hóa và sụp đổ chồng chất lên nhau; tới lần thứ mười đạt tới mức độ kinh người khó tin. Đây là thần thông cực hiếm thấy trong Tu Chân Giới. Yêu tương ném đòn này về phía Vương Lâm, hứa nếu tiếp được sẽ ban chức Đô thống. Vương Lâm nhìn ra manh mối, đứng vững như cây tùng, vận Sát lục tiên quyết kết hợp Hóa Ma chỉ để tiếp.","nguon":["@c0509"]},{"id":"sanh-an-phong-ho","name":"Sanh ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn pháp phòng hộ: hai ký hiệu màu xám hiện trên mi tâm rồi lan bao trùm toàn thân thành hai đạo phòng hộ.","detail":"Khi đối mặt lần sụp đổ thứ tư của Thập Băng Quyền Ý, Vương Lâm thu trường kiếm khí xám thành hai luồng khí chui vào cơ thể, trên mi tâm hiện hai ký hiệu màu xám lan ra bao trùm toàn thân, hóa thành hai đạo Sanh ấn phòng hộ để chống đỡ đợt công kích cực mạnh mà không phải lộ ra Hoàng Tuyền chỉ.","nguon":["@c0510"]},{"id":"huyet-thuat-gia-truyen-dieu-tich-tuyet","name":"Huyết thuật gia truyền","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Dòng Huyết tổ","soHuu":["Diêu Tích Tuyết"],"blurb":"Thuật gia truyền của dòng Huyết tổ, giúp người dùng cầm cự qua những đợt công kích cực mạnh.","detail":"Là thuật gia truyền của Diêu Tích Tuyết, con gái Huyết tổ. Ba năm trước nhờ vận dụng thuật này mà nàng sống sót quá lần sụp đổ thứ năm của Thập Băng Quyền Ý — một thần công mà nếu không có thuật hộ thân thì khó qua nổi lần thứ tư.","nguon":["@c0510"]},{"id":"than-thong-niem-tin","name":"Thần thông Niềm tin","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cảnh giới thần thông tinh thần","hePhai":"","soHuu":["Vương Lâm","Tả Dực tướng quân"],"blurb":"Cảnh giới thần thông dựa trên niềm tin tinh thần thay vì tu vi, một niềm tin vững chắc đủ để ảnh hưởng và thay đổi trời đất.","detail":"Thần thông Niềm tin là bản chất ẩn dưới Thập Băng Quyền Ý: đạo tâm thăng hoa tới đỉnh, nguyên thần dung nhập đạo tâm, chỉ còn lại một niềm tin vững chắc có thể đổi cả thiên địa. Niềm tin của Tả dực Yêu tướng là ‘tất thắng’, tích lũy từ kinh nghiệm sa trường và tâm niệm của vô số kẻ từng bại dưới quyền ý. Vương Lâm ngộ ra rằng phá thần thông này không dựa vào tu vi mà phải dung niềm tin của bản thân vào pháp thuật, biến cuộc đối kháng lực lượng thành đối kháng niềm tin; hắn giao ‘linh hồn’ cho Hóa Ma chỉ và chỉ một lời đã phá được đợt sụp đổ thứ bảy.","nguon":["@c0511"]},{"id":"ma-niem","name":"Ma niệm","loai":"khac","loaiLabel":"Ý niệm","phamCap":"Ý niệm","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý niệm Vương Lâm lĩnh ngộ: không phải giết chóc hay tất thắng mà là nghịch thiên, tùy ý làm, phá hư đạo pháp, tự đi con đường riêng.","detail":"Khi dồn niềm tin vào Hóa Ma chỉ, Vương Lâm nhận ra ý niệm chống đỡ Thập Băng Quyền Ý không phải là giết chóc cũng không phải tất thắng, mà là Ma niệm — nghịch thiên, tùy ý đoạt sinh mạng trí tuệ, phá hư đạo pháp đã định, tự mở lấy con đường riêng nên gọi là Ma. Chính ý niệm này khiến tiên lực trong người hắn vô thanh hóa thành ma khí và Hóa Ma chỉ phát huy uy lực chân chính.","nguon":["@c0511"]},{"id":"thap-bang-quyen","name":"Thập Băng Quyền Ý","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Khảo nghiệm","hePhai":"Vân Lệ Hải (Tả Dực Yêu tương)","soHuu":["Vân Lệ Hải (Tả Dực Yêu tương)"],"blurb":"Quyền pháp của Yêu Tương; Diêu Tích Tuyết lấy việc có thể tiếp được Thất Băng quyền làm thước đo cho rằng tu vi Vương Lâm vừa đủ để nhờ cậy. (+) Mười quyền khảo nghiệm của Vân Lệ Hải, mỗi quyền là một ‘lần sụp đổ’ từ hư vô hóa thành. (+) Tuyệt học quyền ý của Mạc Lệ Hải, nhưng bị Mặc Phi đỡ được toàn bộ. [CAN-SOAT-GOP]","detail":"Quyền pháp Vân Lệ Hải dùng làm khảo nghiệm thực lực: gồm mười quyền, mỗi quyền gọi là một ‘lần sụp đổ’, từ hư vô hóa thành mà công kích. Càng về sau uy lực càng tăng — lần thứ tám hóa thành dạng nước lũ cuồn cuộn với uy lực chưa từng có, lần thứ chín im lìm xuất hiện áp tới khi lần trước chưa kịp tan. Người chủ thi triển chỉ cần chộp tay là thu lại được toàn bộ quyền ý, trời đất lập tức khôi phục như cũ. Vương Lâm nhập ma vượt được tám lần rồi chủ động lùi trước quyền thứ chín.","nguon":["@c0512","@c0518","@c0542"],"aliases":["#that-bang-quyen-yeu-tuong","#thap-bang-quyen-y-mac-le-hai"]},{"id":"tru-tien-tran","name":"Tru Tiên trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Quân yêu Cổ Yêu thành","soHuu":["Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)"],"blurb":"Trận pháp sát phạt mà thống lĩnh Nghiêu Lĩnh định thi triển để giết người ngoài đến.","detail":"Trận pháp được thống lĩnh cũ tính dùng để giết người ngoài đến nếu đối phương mạnh; bị yêu binh cảnh báo rằng động trận này trong nội bộ sẽ bị Yêu Tương đại nhân trách phạt.","nguon":["@c0513"]},{"id":"luyen-the-thuat-thap-tam","name":"Luyện Thể thuật (Thập Tam)","cn":"","loai":"luyen-the","loaiLabel":"Công pháp luyện thể","phamCap":"","hePhai":"","soHuu":["Thập Tam"],"blurb":"Công pháp luyện thể của Thập Tam, vốn chưa đầy đủ nên uy lực sau tu luyện chưa mạnh.","detail":"Dù công pháp còn khuyết thiếu, Thập Tam vẫn tung được một quyền đánh trọng thương yêu binh, hất đối phương phun máu văng đi mấy trượng.","nguon":["@c0513"]},{"id":"yeu-luc-pha-than","name":"Yêu lực phá thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông yêu thuật","phamCap":"","hePhai":"Quân yêu Cổ Yêu thành","soHuu":[],"blurb":"Chiêu của sáu yêu binh, phát ra sáu luồng yêu lực mạnh như rồng nổi giận để bức lui hồn phách.","detail":"Sáu yêu binh đồng loạt ra tay, phóng sáu luồng yêu lực cuồng bạo đẩy lui đám hồn phách của Hồn phiên; khi mất khống chế, sáu đạo yêu lực này bay thẳng vào mi tâm Vương Lâm và bị ma niệm của hắn hút trọn.","nguon":["@c0513"]},{"id":"phap-thuat-dung-lau-bun-dat","name":"Pháp thuật dựng lầu bùn đất","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp thuật điều khiển đất đá, lập tức dựng lên kiến trúc từ bùn đất.","detail":"Vương Lâm nhấn tay xuống đất, mặt đất rung chuyển và phun lên, tạo tức thì một ngôi lầu hai tầng bằng bùn đất uy nghiêm giữa quân doanh. Uy thế của pháp thuật chấn nhiếp cả Tư Mã Viêm lẫn chín ngàn yêu binh.","nguon":["@c0517"]},{"id":"thuat-tai-tao-mau-lam-dieu-tich-tuyet","name":"Thuật tái tạo bằng máu lam","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Diêu Tích Tuyết"],"blurb":"Bí thuật phân thân và hồi sinh thân thể bằng một giọt máu lam kết hợp Huyết Hồn đan.","detail":"Diêu Tích Tuyết bóp nát cây đèn trắng lấy ra giọt máu lam, cắn ngón tay vẽ phù văn bằng máu, dung hợp giọt máu lam rồi điểm vào mi tâm trước khi xuất ra trở lại để xông vào “nơi đó”. Khi thất bại, giọt máu lam sôi trào phình thành quả cầu máu lam, các phù văn gắn lên tái tạo lại thân thể nàng — cơ chế hồi sinh dựa vào Huyết Hồn đan.","nguon":["@c0517"]},{"id":"tran-cam-che-muoi-tam-phong-an","name":"Trận pháp cấm chế mười tám phong ấn","loai":"khac","loaiLabel":"Trận pháp / cấm chế","phamCap":"","hePhai":"","soHuu":[],"blurb":"Trận pháp cấm chế bí ẩn chưa rõ tên; khi mở ra sẽ xoay tròn, bên trong có mười tám phong ấn, phá thành công thì sống, thất bại thì chết.","detail":"Trận pháp cấm chế giấu kín trong Yêu Linh chi địa, muốn tới được phải có một loại pháp bảo đặc biệt mà hiện chỉ Diêu Tích Tuyết có thể vào. Trận mở ra sẽ xoay tròn, bên trong xếp mười tám tầng phong ấn; phá giải mang tính sinh tử — thành công thì sống, thất bại thì chết. Diêu Tích Tuyết một mình chỉ phá được tới phong ấn thứ mười một, đã thất bại bốn lần và mỗi lần phải dùng Huyết Hồn đan hồi sinh, nên tìm Vương Lâm trợ lực.","nguon":["@c0518"]},{"id":"tran-an-than-bay-pho-tuong","name":"Trận ẩn thân bảy pho tượng","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Huyết Tổ sáng tạo","soHuu":["Diêu Tích Tuyết","Huyết Tổ Diêu Tinh Hải"],"blurb":"Trận pháp do Huyết Tổ sáng tạo, dùng bảy pho tượng đỏ chui xuống đất tạo nguồn lực vô hình khiến thần thức không soi thấy chính mình.","detail":"Người thi triển kết ấn, cắn lưỡi vẽ ký tự máu to trăm trượng in lên mặt đất; bảy pho tượng đỏ bay tới bảy điểm rồi chui xuống đất tạo nguồn lực vô hình. Trong phạm vi trăm trượng, thần thức kẻ ở trong không thể cảm nhận được thân ảnh của chính mình, như soi gương mà không thấy mình. Diêu Tích Tuyết nói trận này tinh diệu tới mức cả Yêu Tương cũng không phát hiện ra.","nguon":["@c0520"]},{"id":"truyen-tong-tran-yeu-linh-chi-dia","name":"Truyền tống trận (Yêu Linh chi địa)","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Thượng cổ","hePhai":"Huyết Tổ bố trí","soHuu":["Diêu Tích Tuyết","Huyết Tổ Diêu Tinh Hải"],"blurb":"Điểm truyền tống do Huyết Tổ bố trí sẵn, chỉ mở được trong Yêu Linh chi địa lúc trăng tím mạnh nhất nửa năm một lần.","detail":"Trận kích hoạt khi yêu khí trong vùng lên cực điểm và la bàn đỏ lóe sáng một nhịp hô hấp; ánh trăng tím bùng phủ tím mặt đất, một luồng đỏ như kiếm xuyên hiện ra để người vào lao tới. Trận chỉ truyền tống được trong phạm vi Yêu Linh chi địa, đưa người tới không gian Tôn Thú nơi đặt bình đài trận pháp cùng nguồn gốc.","nguon":["@c0520"]},{"id":"luyen-tien-tinh","name":"Luyện Tiên tinh","loai":"cong-phap","loaiLabel":"Kỹ thuật tu luyện","phamCap":"Tự sáng","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Vương Lâm vận dụng kết cấu yêu tinh học ở bộ lạc Luyện Hồn để cô đọng tiên lực thành ‘Tiên tinh’.","detail":"Sau thời gian dài nghiên cứu yêu tinh ở bộ lạc Luyện Hồn, Vương Lâm nắm rõ kết cấu yêu tinh và mượn nó để nén tiên lực hấp thu từ tiên ngọc thành một tinh thể giống yêu tinh nhưng tỏa ra tiên lực. Mỗi viên Tiên tinh chứa lượng tiên lực bằng khoảng một phần mười số tiên ngọc đã dùng, tiện cất giữ và vận dụng.","nguon":["@c0520"]},{"id":"tao-an-ky-buoc-duong-ton-thu","name":"Tạo ấn ký bước trên đường Tôn Thú","loai":"bi-thuat","loaiLabel":"Pháp môn","phamCap":"Bí truyền","hePhai":"Huyết Tổ truyền thừa","soHuu":["Diêu Tích Tuyết"],"blurb":"Ngưng thần cảm ngộ ý cảnh bản thân để tạo ra ấn ký, nhờ đó có thể bước trên con đường thân thể giao long Tôn Long.","detail":"Tại không gian Tôn Thú, người tu phải ngồi ngưng thần, cảm ngộ ý cảnh của chính mình rồi tạo thành ấn ký riêng. Có được ấn ký này mới đủ tư cách bước lên con đường nhỏ uốn lượn — thực chất là cơ thể con giao long Tôn Long do người dùng thần thông bố trí.","nguon":["@c0520"]},{"id":"suy-dien-cam-che-vuong-lam","name":"Suy diễn cấm chế","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Cấm chế chi đạo","soHuu":["Vương Lâm"],"blurb":"Thuật vận cấm chế trong hai mắt để suy diễn, nhìn thấu bản chất sự vật.","detail":"Vương Lâm vận cấm chế ngưng trong hai con mắt rồi suy diễn với tốc độ ngày càng nhanh. Nhờ vậy hắn nhìn thấu pho tượng đá ba mắt ở bình đài thứ ba vốn không phải là tượng, mà chỉ là một đống cấm chế chồng lớp lên nhau — từ đó tìm ra cách phân giải và hấp thu chúng.","nguon":["@c0522"]},{"id":"kim-phu-ba-net-phu-van","name":"Kim phù (ba nét phù văn)","cn":"","loai":"bi-thuat","loaiLabel":"Phù văn bí thuật","phamCap":"Ẩn chứa ấn ký thiên đạo","hePhai":"Động phủ tiên nhân đường Tôn Long","soHuu":["Vương Lâm"],"blurb":"Phù văn vẽ ba nét trong mắt hoặc hư không, khi dung tiên lực thì phát kim quang cực mạnh xua tan hắc khí trên đài phong ấn.","detail":"Vương Lâm cảm ngộ và vẽ thành công ba nét, ký hiệu phát kim quang uy thế ngang hàng cường giả lớp phụ thân Diêu Tích Tuyết, đủ buộc nàng dùng huyết ngọc trăm năm hóa giải. Hắn không vẽ ra nổi nét thứ tư vì thiếu căn cứ; nếu phù chưa hoàn thành thì ký hiệu tự sụp đổ. Cảm ngộ được kim phù mới đạt tư cách bước vào động thí luyện; nghi vấn rằng mười tám ký hiệu hợp lại có thể là một môn tiên thuật bất thành.","nguon":["@c0523"]},{"id":"phuc-hoat-than-thong","name":"Phục Hoạt Thần Thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Truyền thừa Huyết Quân","soHuu":["Diêu Tích Tuyết"],"blurb":"Thần thông mà Động Phủ Chi Linh yêu cầu Diêu Tích Tuyết thi triển để chứng minh thân phận truyền nhân.","detail":"Khi nhận ra Diêu Tích Tuyết mang công pháp Huyết Quân năm xưa, Động Phủ Chi Linh đòi nàng thi triển Phục Hoạt Thần Thông rồi cút khỏi cửa động phủ.","nguon":["@c0523"]},{"id":"than-thong-phong-an-mi-tam","name":"Thần thông phong ấn (dấu ấn mi tâm)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Điểm một dấu khí xám lên mi tâm đối thủ, làm đứt kinh mạch và phong ấn toàn thân giữa sự sống và cái chết.","detail":"Vương Lâm dùng để giam Diêu Tích Tuyết trong trạng thái không thể chết, qua đó vô hiệu hóa Huyết Hồn Đan vốn phải chết mới phát huy tác dụng, khiến nàng cô độc bị giam giữ lâu dài.","nguon":["@c0523"]},{"id":"tran-phap-tron-do-dieu-tich-tuyet","name":"Trận pháp tròn màu đỏ","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp huyết hệ","phamCap":"","hePhai":"Huyết công","soHuu":["Diêu Tích Tuyết"],"blurb":"Diêu Tích Tuyết phun máu hóa ký hiệu đỏ rồi dựng trận tròn trên hai tay để chắn đạo kiếm khí thứ ba.","detail":"Trận pháp vỡ vụn trước kim quang, kiếm khí tan thành điểm sáng dung nhập cơ thể buộc nàng ngồi xuống vận tiên lực đối kháng.","nguon":["@c0523"]},{"id":"mai-hoa-thap-bat-cam","name":"Mai Hoa Thập Bát Cấm","loai":"bi-thuat","loaiLabel":"Bí thuật phá cấm","phamCap":"Thượng cổ","hePhai":"Dòng chính thống thượng cổ Tu Chân Giới","soHuu":[],"blurb":"Thủ pháp phá cấm chế cực tinh xảo thời thượng cổ, khi phá phong ấn để lại dấu vết hình hoa mai.","detail":"Một môn cấm thuật phá-cấm tinh xảo bậc nhất thời thượng cổ Tu Chân Giới, dấu vết phá giải để lại tựa như hoa mai nở. Pháp môn rất coi trọng dòng chính thống, người ngoài tuyệt không được truyền; đệ tử chính thống tối đa chỉ học đến Cửu Cấm, duy chỉ chưởng môn mới học hết Thập Bát Cấm. Người nắm trọn thuật này có thể đạt độ nắm chắc phá giải bảy phần trở lên. Trong động phủ tiên cấm, tiền nhân đầu tiên tiến vào chính là người dùng môn này, cao ngạo chỉ lấy vật quý.","nguon":["@c0524"]},{"id":"ho-phu-than-thong","name":"Hộ Phủ Thần Thông","loai":"than-thong","loaiLabel":"Thần thông phòng thủ","phamCap":"Tiên gia","hePhai":"Chủ nhân động phủ tiên cấm","soHuu":[],"blurb":"Thần thông phòng thủ động phủ, biểu hiện bằng ký hiệu vàng trên mười một đài bên ngoài.","detail":"Thần thông canh giữ động phủ, thể hiện qua các ký hiệu màu vàng trên mười một đài bên ngoài cửa đá. Khi thần thông còn hiệu lực thì không ai tiến vào được; chủ nhân đã phong ấn lại nhưng cố ý không để lại đầu mối điều khiển sau khi rời đi.","nguon":["@c0524"]},{"id":"tien-cam","name":"Tiên Cấm","loai":"bi-thuat","loaiLabel":"Cấm chế tiên giới","phamCap":"Tiên gia","hePhai":"Tiên giới","soHuu":[],"blurb":"Thủ pháp phong ấn của tiên giới, hiếm thấy cả ở thời thượng cổ; đặc điểm có đường sinh không cố định.","detail":"Cấm chế bậc tiên giới, theo sách cổ thì hiếm thấy ngay cả ở thời thượng cổ. Đặc trưng là có đường sinh biến đổi không cố định, dịch chuyển theo cấm chế. Trong động phủ của chủ nhân giấu mặt, tiên cấm bao phủ toàn bộ kiến trúc cả trong lẫn ngoài, khiến tiên ngọc nền móng không thể đào lấy.","nguon":["@c0524"]},{"id":"cam-che-phong-an-khu-vuon","name":"Cấm chế phong ấn khu vườn","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"Tiên gia","hePhai":"Động phủ tiên cấm","soHuu":[],"blurb":"Trận pháp trung tâm của mọi cấm chế quanh động phủ, biến hóa hơn vạn loại, phát động kéo theo toàn bộ.","detail":"Cấm chế bao quanh khu vườn còn nguyên vẹn trong động phủ, là trung tâm của tất cả cấm chế xung quanh với hơn một vạn biến hóa. Một khi phát động sẽ kéo theo toàn bộ hệ thống, tạo cơn lốc đen cùng sấm sét tia chớp tựa Du Long, tu sĩ Vấn Đỉnh đứng trong đó ba hơi thở cũng chết. Đường sinh tiến vào không cố định, biến đổi theo cấm chế và có thể đột ngột xoay ngược đổi phương hướng vận chuyển.","nguon":["@c0524"]},{"id":"tran-phap-truyen-tong-huyet-to","name":"Trận pháp truyền tống Huyết Tổ","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Thông thiên (do Huyết Tổ lưu)","hePhai":"Di sản Huyết Tổ","soHuu":["Vương Lâm"],"blurb":"Trận truyền tống Huyết Tổ lưu trên cái đài đầu tiên trong động phủ, khớp với la bàn huyết sắc để dịch chuyển.","detail":"Trận pháp do Huyết Tổ để lại trên cái đài đầu tiên của động phủ, phải khớp với la bàn huyết sắc mới đổi được phương vị dịch chuyển. Vương Lâm hiệu chỉnh trong ba ngày rồi dùng ba mươi ngày bố trí vô số cấm chế cải tạo nó thành cạm bẫy: người ngoài nào bước vào sẽ bị truyền đi rồi truyền về liên tục cho tới khi vách không gian vỡ, bị cuốn vào khe không gian.","nguon":["@c0526"]},{"id":"tran-phap-trong-la-ban-huyet-sac","name":"Trận pháp trong la bàn huyết sắc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Di sản Huyết Tổ","soHuu":["Vương Lâm"],"blurb":"Trận nhỏ bên trong la bàn huyết sắc, kim đong đưa luôn biến hóa, phải khớp với truyền tống trận mới đổi phương được.","detail":"Bên trong la bàn huyết sắc có một trận pháp nhỏ đong đưa theo kim, biến hóa không ngừng; chỉ khi khớp với trận truyền tống ở cái đài mới đổi được phương vị dịch chuyển. Trong trận này vốn lưu thần thức Diêu Tích Tuyết (không có Huyết Tổ) nên Vương Lâm xóa được và lưu thần thức của mình vào.","nguon":["@c0526"]},{"id":"huyen-vu-hoa-than-do-thong","name":"Huyền Vũ hóa thân (Đô Thống)","cn":"","loai":"than-thong","loaiLabel":"Yêu lực hóa thân","phamCap":"Anh Biến hậu kỳ","hePhai":"Yêu tộc","soHuu":["Đô Thống Hắc Giáp quân"],"blurb":"Hóa thân Huyền Vũ kích thước trăm trượng của Đô Thống Hắc Giáp quân, lưng và đuôi đầy gai nhọn như giáo đen.","detail":"Khi mất khí thế trước Vương Lâm, Đô Thống hóa thân Huyền Vũ trăm trượng, lưng và đuôi mọc đầy gai nhọn như giáo đen, một cú vung có thể phá nát không gian, dùng để chống đỡ Tịch Diệt Chỉ.","nguon":["@c0526"]},{"id":"cam-bay-than-thuc-huyet-to","name":"Cạm bẫy thần thức (Huyết Tổ)","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"Thông thiên","hePhai":"Di sản Huyết Tổ","soHuu":["Huyết Tổ Diêu Tinh Hải"],"blurb":"Lạc ấn thần thức phong trên túi trữ vật phóng huyết quang chống cự; túi thứ tư ẩn một đạo tử tuyến giết kẻ không quan sát kỹ.","detail":"Thần thức phong ấn trên các túi trữ vật của Diêu Tích Tuyết phóng huyết quang chống cự khi bị phá. Riêng túi thứ tư có một đạo tử tuyến ẩn trên huyết quang, nghi là cạm bẫy thần thức của chính Huyết Tổ — ai không quan sát kỹ mà cưỡng phá sẽ bị giết, khiến Vương Lâm thu thần thức, không dám mở.","nguon":["@c0526"]},{"id":"yeu-hai-bach-lang","name":"Yêu Hải Bách Lãng","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt chiêu Anh Biến","hePhai":"Yêu tộc","soHuu":["Mạc Lệ Hải (Yêu Tướng)"],"blurb":"Tuyệt chiêu của yêu tướng Mạc Lệ Hải, biến yêu lực hư vô thành biển cả thực thể tung ra sóng yêu khí trùng trùng. (+) Một trong các thần thông đã biết của Mạc Lệ Hải. [CAN-SOAT-GOP]","detail":"Mạc Lệ Hải vỗ tay biến yêu lực hư vô thành thực thể biển cả rộng mười dặm, từ đó tung ra hàng chục đợt sóng yêu khí công kích (ba mươi đến sáu mươi đợt nối nhau), ẩn chứa thần thông vượt trên quyền ý. Cấm chế thông thường và cả Huyết sắc Ngọc phù đều bị sóng phá vỡ, Vương Lâm phải liên tục lùi để tìm cách phá giải.","nguon":["@c0529","@c0543"],"aliases":["#yeu-hai-bach-lang-than-thong"]},{"id":"chuong-an-hu-ao-vo-danh","name":"Chiêu vô danh (chưởng ấn hư ảo)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cảm ngộ tiên giới (chưa hoàn chỉnh)","hePhai":"Thủ ấn tiên giới","soHuu":["Vương Lâm"],"blurb":"Chưởng ấn khổng lồ mang khí thế hủy thiên diệt địa nhưng thực chất chỉ là hư ảnh vô lực, dùng để đánh tâm lý.","detail":"Vương Lâm nhắm mắt vận dụng cảm ngộ về thủ ấn khổng lồ từng thấy ở tiên giới (đã dùng trong trận với Hồng Điệp), tạo một chưởng ấn khổng lồ mang khí thế hủy diệt thiên địa khiến đối thủ cảm thấy không thể kháng cự. Thực chất chưởng ấn chỉ là hư ảnh không có lực công kích, xuyên qua thân Mạc Lệ Hải mà không gây biến hóa; Vương Lâm gọi đây là chiêu vô danh, dùng tâm lý chiến buộc đối phương không dám đánh cuộc mạng sống. Mạc Lệ Hải nhận xét chiêu này Vương Lâm chưa học toàn bộ.","nguon":["@c0529"]},{"id":"phu-van-than-thong-khi-xam","name":"Phù văn thần thông (ba nét khí xám)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông phù văn","hePhai":"Phù văn tượng đá","soHuu":["Vương Lâm"],"blurb":"Vương Lâm dùng khí xám vẽ ba nét phù văn, dung hợp lực màu vàng từ tượng đá thứ hai để bắn khí xám xuyên Yêu Hải.","detail":"Khi phù văn màu vàng hấp thu từ tượng đá thứ hai hiện rõ trong đầu và quấy nhiễu tiên lực, Vương Lâm thuận theo dùng khí xám vẽ ba nét bút thành phù văn thần thông. Lực màu vàng hòa tan dung nhập, bắn ra ba luồng khí xám xuyên qua Yêu Hải đánh thẳng Mạc Lệ Hải, buộc hắn phải dựng màn chắn yêu lực chống đỡ và kinh ngạc khen thần thông của phù văn.","nguon":["@c0529"]},{"id":"cu-linh-cuu-tu","name":"Cự Linh Cửu Tu","loai":"luyen-the","loaiLabel":"Công pháp luyện thể","phamCap":"Thần thông luyện thể chín tầng","hePhai":"","soHuu":["Vương Lâm","Thập Tam"],"blurb":"Công pháp thần thông tu luyện cơ thể gồm chín tầng, ghi trong ngọc giản; Vương Lâm chỉ truyền lại sáu tầng đầu.","detail":"Cự Linh Cửu Tu là một bộ công pháp thần thông luyện thể chia làm chín tầng, được ghi chép trong ngọc giản mà Vương Lâm thu được trước đó. Vương Lâm ghi nhớ trọn chín tầng khẩu quyết rồi xóa đi ba tầng phía sau, chỉ chép lại sáu tầng đầu vào một ngọc giản màu xanh và truyền cho Thập Tam.","nguon":["@c0530"]},{"id":"diet-the-ap-nguyen-cong","name":"Diệt Thế Áp Nguyên Công","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Công pháp yêu lực","hePhai":"Truyền thừa lão già hắc y","soHuu":["Hổ Bào"],"blurb":"Công pháp lão già hắc y truyền cho Hổ Bào; chỉ cần tu đến tầng thứ tư sẽ có yêu lực vô tận.","detail":"Diệt Thế Áp Nguyên Công là công pháp do lão già hắc bào truyền cho Hổ Bào sau khi cứu hắn khỏi hắc lao. Lão nói chỉ cần tu luyện đến tầng thứ tư sẽ có yêu lực vô tận, là một phần trong kế hoạch bồi dưỡng Hổ Bào thành Yêu Vệ.","nguon":["@c0530"]},{"id":"khau-quyet-chu-nhan-luyen-yeu-ve","name":"Khẩu quyết của chủ nhân (luyện Yêu Vệ)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí thuật truyền từ chủ nhân hắc tháp","hePhai":"Chủ nhân (bộ giáp hắc tháp)","soHuu":["Lão già hắc bào (ân công của Hổ Bào)"],"blurb":"Khẩu quyết do chủ nhân trong hắc tháp truyền xuống, ngưng tụ toàn bộ tuổi thọ và tiềm lực trong một canh giờ rồi bùng nổ biến tu sĩ thành Yêu Vệ.","detail":"Là khẩu quyết bí truyền mà chủ nhân trong bộ giáp hắc tháp truyền cho lão già hắc y. Người tu luyện ngưng tụ toàn bộ tuổi thọ và tiềm lực của mình trong một canh giờ rồi bùng nổ để biến thành một Yêu Vệ. Lão già định cho Hổ Bào tu luyện sau khi hắn hấp thụ lượng lớn hồn phách qua Luyện Hồn Thuật.","nguon":["@c0530"]},{"id":"hon-phach-thu-than","name":"Hồn Phách Thủ Thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm","Âu Dương Hoa","Bộ lạc Luyện Hồn"],"blurb":"Pháp môn phòng thủ thần hồn dùng để chống lại thuật Linh Thang Loạn Thần khi tiềm nhập bộ lạc khác.","detail":"Vương Lâm chỉ định cho bộ lạc Luyện Hồn dùng Hồn Phách Thủ Thần làm lá chắn thần hồn khi mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ; cốt yếu là vô hiệu hóa pháp thuật phòng vệ Linh Thang Loạn Thần thường được các bộ lạc bố trí để phát hiện và làm loạn thần kẻ xâm nhập.","nguon":["@c0531"]},{"id":"linh-thang-loan-than","name":"Linh Thang Loạn Thần","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Các bộ lạc lớn nhỏ vùng Yêu Linh"],"blurb":"Pháp thuật phòng vệ bộ lạc gây loạn thần kẻ xâm nhập, được Hồn Phách Thủ Thần khắc chế.","detail":"Mỗi bộ lạc lớn nhỏ trong vùng Vương Lâm nhắm tiềm nhập đều có Linh Thang Loạn Thần như một lớp cấm chế phát hiện và làm loạn thần kẻ ngoại lai; muốn xâm nhập thành công phải dùng Hồn Phách Thủ Thần chống đỡ.","nguon":["@c0531"]},{"id":"thap-bat-yeu-ma-than","name":"Thập Bát Yêu Ma Thân","cn":"","loai":"luyen-the","loaiLabel":"Luyện Thể","phamCap":"","hePhai":"","soHuu":["Mạc Lực Hải"],"blurb":"Công pháp luyện thể hợp luyện đủ mười tám bộ ma thân, là vốn liếng then chốt của Yêu tướng Mạc Lực Hải.","detail":"Mạc Lực Hải tu Thập Bát Yêu Ma Thân, hiện đã luyện hóa được mười bảy bộ; bộ thứ mười tám — gọi là Thập Tam — bị Vương Lâm mang đi khỏi Cổ Yêu thành khiến hắn dở dang. Nếu được trợ lực hoàn tất công pháp, hắn tự tin vào nổi vòng ba cuộc chiến Yêu tướng, lấy tư cách vào Cổ Yêu điện tu luyện rồi thành phó soái.","nguon":["@c0531"]},{"id":"tho-nap-long-khi","name":"Thổ nạp long khí","loai":"cong-phap","loaiLabel":"Công pháp tu luyện","phamCap":"","hePhai":"Thiên Yêu quận","soHuu":[],"blurb":"Hấp thu lớp sương mỏng do chín dãy núi quanh Thiên Yêu thành tỏa ra để tăng tu vi.","detail":"Sáng sớm Thiên Yêu thành phủ một lớp sương mỏng tụ từ chín dãy núi bao quanh, được Yêu Đế gọi là long khí. Yêu tộc trong thành thổ nạp loại sương khí này có thể bồi bổ và tăng tiến tu vi, nên long khí trở thành phúc lợi đặc thù của kinh đô.","nguon":["@c0532"]},{"id":"than-thong-tam-thuc-mac-le-hai","name":"Thần Thông Tam Thức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiên Yêu quận","soHuu":["Mạc Lệ Hải"],"blurb":"Bộ thần thông ba thức của Mạc Lệ Hải: Thập Băng Quyền Ý (thức một), Yêu Hải Bách Lãng (thức hai) và thức cuối do đích thân Yêu Đế thân truyền với uy lực khổng lồ.","detail":"Thần thông trục của Mạc Lệ Hải gồm ba thức nối tiếp tăng tiến. Thức một là Thập Băng Quyền Ý — quyền như gió gào, hư vô tan vỡ. Thức hai là Yêu Hải Bách Lãng. Thức ba do chính Yêu Đế thân truyền, uy lực được mô tả là khổng lồ và chưa từng thi triển; Thạch Tiễn cảnh báo đây là chìa khóa khiến Mạc Lệ Hải đáng gờm trong cuộc chiến Yêu tướng.","nguon":["@c0533"]},{"id":"luc-chi-kiem-quyet","name":"Lục Chỉ Kiếm Quyết","cn":"","aliases":["Lục Chỉ Yêu Kiếm"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Tiễn"],"blurb":"Thần thông sở trường của Thạch Tiễn, bị Mạc Lệ Hải gọi mỉa là Lục Chỉ Yêu Kiếm; uy lực khó lường.","detail":"Khi thi triển, người dùng cong tay phải điểm năm chỉ cực nhanh theo thứ tự (ngón trỏ rồi ngón giữa…), sau đó khép năm ngón thành chùy điểm tới, tạo tiếng nổ và sóng xung khuếch tán. Trong lần đấu thử với Thập Băng Quyền Ý của Mạc Lệ Hải, dù cả hai nén lực ở mức thấp nhất, chiêu vẫn làm nứt cả bốn chân chiến mã. Mạc Lệ Hải đánh giá uy lực khó lường.","nguon":["@c0533"]},{"id":"sat-luc-chi-khi","name":"Sát Lục Chi Khí","cn":"","loai":"than-thong","loaiLabel":"Sản vật thần thông","phamCap":"","hePhai":"Sát Lục Tiên Quyết","soHuu":["Vương Lâm"],"blurb":"Hôi khí xoay chuyển giữa kẽ ngón tay, sản vật luyện hóa từ Sát Lục Tiên Quyết.","detail":"Khí hôi luyện hóa được khi giết chóc hoặc thu từ Yêu binh không rõ con nào; cơ chế sinh ra chưa được giải thích, mỗi đạo như do ngẫu nhiên đoạt được — có khi nén giận xuất thủ thì luyện được một đạo, có khi lòng không dao động vẫn có. Vương Lâm tu vài năm mới luyện ra, hiện khống chế năm đạo, tính cả một đạo trên người là sáu; bên trong còn ẩn chứa huyền bí chưa lĩnh ngộ.","nguon":["@c0534"]},{"id":"sat-luc-khi-nam-thuong-long","name":"Sát lục khí (Năm con thương long)","cn":"","loai":"than-thong","loaiLabel":"Thần thông sát khí","phamCap":"","hePhai":"Sát Lục Tiên quyết","soHuu":["Vương Lâm"],"blurb":"Năm đạo khí màu xám của Vương Lâm hình thành năm con thương long; bị đánh tan thì tự dung hợp lại, len qua phòng ngự công kích, sắc bén hơn yêu kiếm.","detail":"Vương Lâm vung tay tạo ra năm đạo sát lục khí màu xám hóa thành năm con thương long lao tới. Khi bị đánh tan, chúng không tan biến mà tự dung hợp lại thành một thể, len qua quyền phong đánh thẳng tới mục tiêu. Thứ khí xám này sắc bén so với yêu kiếm, lại ẩn chứa một biến hóa khó giải có thể dẫn động sinh cơ trong cơ thể đối phương. Mạc Lệ Hải nhận xét chỉ năm đạo đã chấn động được yêu giáp của hắn; nếu hình thành tới mấy ngàn đạo thì uy lực cực kỳ đáng sợ.","nguon":["@c0535"]},{"id":"sat-luc-yeu-dao","name":"Sát lục yêu đạo","aliases":["Tâm hóa yêu"],"loai":"than-thong","loaiLabel":"Yêu đạo tu luyện","phamCap":"Không rõ","hePhai":"Hồng lao","soHuu":["Nam tử họ Hứa"],"blurb":"Con đường tu luyện sát đạo dùng tâm hóa yêu, biểu hiện sát tâm như kiếm chưa rời vỏ.","detail":"Đạo tu của nam tử họ Hứa ở Hồng lao, dùng tâm hóa yêu để luyện sát lục. Khi hắn biểu lộ sát tâm, không hề tỏa ra sát khí mà người đối diện vẫn lông tóc dựng ngược, nguyên thần rúng động — ví như kiếm chưa rời vỏ đã khiến người khác chấn động. Hứa tự xưng là người duy nhất trong mười người ở Hồng lao đi con đường này.","nguon":["@c0536"]},{"id":"sinh-an-vuong-lam","name":"Sinh ấn","cn":"","loai":"bi-thuat","loaiLabel":"Ấn pháp","phamCap":"","hePhai":"Sinh Tử luân hồi","soHuu":["Vương Lâm"],"blurb":"Ấn pháp thuộc ý cảnh Sinh Tử luân hồi của Vương Lâm, thi triển đúng thời điểm để nắm bắt tin tức chân thật.","detail":"Khi rơi vào cảnh huyễn lúc đắc kim phù ấn, Vương Lâm ngưng tụ hai tai và thi triển Sinh ấn đúng vào khoảnh khắc mọi thứ sắp biến mất, nhờ đó nghe được thanh âm chân thật “Ta là Thanh Sương” thay vì bị ý niệm chủ quan của hình ảnh dẫn dắt.","nguon":["@c0521"]},{"id":"sat-luc-chi-dao","name":"Sát Lục chi đạo","cn":"","loai":"bi-thuat","loaiLabel":"Ấn ký / Đạo pháp","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ấn ký đạo pháp của Vương Lâm hiện trên mi tâm trong trạng thái huyễn, dùng kèm việc ngưng tụ hai tai để cảm tri.","detail":"Trong cảnh huyễn lúc đắc kim phù ấn, Vương Lâm vận dụng ấn ký Sát Lục chi đạo trên mi tâm phối hợp Sinh ấn, giúp hắn phân biệt được giữa hình ảnh (ý niệm chủ quan) và thanh âm (tin tức chân thật) để nắm bắt đúng manh mối.","nguon":["@c0521"]},{"id":"kim-phu-an","name":"Kim phù ấn","cn":"","loai":"khac","loaiLabel":"Ký hiệu lực lượng","phamCap":"","hePhai":"Yêu Linh chi địa","soHuu":["Vương Lâm","Diêu Tích Tuyết"],"blurb":"Ký hiệu màu vàng do lực lượng thần bí ngưng tụ trong mắt người cảm ngộ; là điều kiện để đi trên con đường Tôn Long.","detail":"Lực lượng thần bí từ trên trời giáng xuống bình đài, ngưng tụ vào mi tâm người cảm ngộ, để lại ký hiệu màu vàng tạo thành từ các nét: Diêu Tích Tuyết được ba nét, Vương Lâm được sáu nét phức tạp hơn. Số nét càng nhiều, uy thế kim phù càng lớn — kim phù sáu nét của Vương Lâm lấn át hẳn kim phù ba nét của Diêu Tích Tuyết, khiến kim phù của nàng nhạt đi như đốm lửa so với trăng rằm. Có kim phù ấn mới có thể bước lên con đường Tôn Long.","nguon":["@c0521"]},{"id":"sat-luc-tien-quyet-dai-ngo","name":"Sát Lục tiên quyết (đại ngộ)","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Tiên thuật","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Công pháp lấy sát niệm đoạt tính mệnh người khác, luyện sinh cơ thành lạc ấn sinh mệnh — “từ tử tới sinh”, hợp luân hồi chi đạo.","detail":"Bản chất là lấy sát niệm đoạt tính mệnh người khác, luyện sinh cơ thành lạc ấn sinh mệnh: mỗi cái chết tạo một đạo lạc ấn, đi từ tử tới sinh, hợp với luân hồi chi đạo. Cùng nguyên lý với trận pháp thế giới huyết sắc và cách ngân long hấp thu sát vụ chuyển thành sinh cơ. Vương Lâm minh ngộ trong thế giới huyết sắc của Hồng Lao, ngưng được 3792 đạo sát lục khí, mỗi đạo hóa lạc ấn in giữa lông mày làm phòng hộ.","nguon":["@c0537"]},{"id":"lac-an-sinh-menh","name":"Lạc ấn sinh mệnh","cn":"","loai":"cong-phap","loaiLabel":"Cơ chế tu luyện","phamCap":"","hePhai":"Sát Lục tiên quyết","soHuu":["Vương Lâm"],"blurb":"Dấu ấn sinh mệnh hình thành từ Sát Lục tiên quyết; hơn ba nghìn lạc ấn chồng lên nhau tạo phòng hộ.","detail":"Dấu ấn sinh mệnh hình thành từ Sát Lục tiên quyết khi đoạt sinh cơ của người chết. Hơn ba nghìn lạc ấn chồng lên nhau tạo hơn ba nghìn tầng phòng hộ trên thân Vương Lâm, giúp hắn chịu được kiếm quang hủy diệt của Đế Kiếm khi lao khỏi thế giới huyết sắc.","nguon":["@c0537"]},{"id":"yeu-giap-man-bay-tac","name":"Yêu giáp (màn giáp bảy tấc)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu tộc","soHuu":["Phó soái Huyền Thành"],"blurb":"Thần thông phòng ngự của phó soái Huyền Thành, biến hóa màn yêu giáp cuồn cuộn cách thân bảy tấc.","detail":"Phó soái Huyền Thành dồn yêu lực biến hóa thành màn yêu giáp cuồn cuộn cách thân bảy tấc để chống đỡ. Khi bị hai nghìn đạo sát lục chi khí của Vương Lâm tấn công, màn giáp bị ép co rút tới ba tấc rồi tan vỡ.","nguon":["@c0538"]},{"id":"manh-ho-yeu-khi","name":"Mãnh hổ yêu khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu tộc","soHuu":["Phó soái Huyền Thành"],"blurb":"Thần thông của phó soái Huyền Thành, dồn yêu lực hình thành đầu mãnh hổ trên thân chống đỡ.","detail":"Phó soái Huyền Thành dồn yêu lực hình thành đầu mãnh hổ trên thân để chống đỡ đòn của Vương Lâm, nhưng bị sát lục chi khí xuyên thủng tức thì.","nguon":["@c0538"]},{"id":"tran-phap-kiem-cac-de-do","name":"Trận pháp Kiếm Các","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Đế Đô Kiếm Các","soHuu":["Người mặc hoàng bào (Đế Đô Kiếm Các)"],"blurb":"Trận pháp ở Đế Đô Kiếm Các giam giữ, trấn áp Đế Kiếm.","detail":"Trận pháp đặt tại Đế Đô Kiếm Các ở trung tâm Thiên Yêu Thành, dùng để giam giữ và trấn áp Đế Kiếm — thanh ngân kiếm có linh tính kiêu ngạo, hay tới Hồng Lao phá hoại.","nguon":["@c0538"]},{"id":"trang-phap-phong-thu-phu-mac-le-hai","name":"Trận pháp phòng thủ (phủ Mạc Lệ Hải)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Mạc phủ","soHuu":["Mạc Lệ Hải"],"blurb":"Trận pháp phòng thủ bố trí trong phủ Mạc Lệ Hải để chống ám sát.","detail":"Mạc Lệ Hải bế quan trong phủ giữ trạng thái tốt nhất và tránh ám sát, đồng thời bố trí trận pháp phòng thủ do bộ hạ bản lãnh cao thâm điều khiển, thường xuyên vận hành.","nguon":["@c0539"]},{"id":"sat-luc-dao","name":"Sát Lục Đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo sát khí phóng ra từ ánh mắt màu hồng, mang sát khí ngập trời đâm thẳng vào tâm trí đối thủ. (+) Đạo tu luyện rất khó, dựa vào giết chóc nhiều năm để bồi đắp sát khí. [CAN-SOAT-GOP]","detail":"Khi phát động, hai mắt Vương Lâm lóe màu hồng, một luồng sát lục chi khí như ki��m sắc phóng ra theo ánh mắt, đâm qua giữa lông mày vào tâm trí đối phương tới thiên linh khiến tâm thần sắp sụp đổ, thân thể cứng đờ run rẩy, cảm giác như đối mặt cái chết. Uy lực bắt nguồn từ việc đã giết rất nhiều người mà tích tụ thành. Người ngoài cách xa cũng cảm nhận được sát khí như bị kiếm sắc đâm.","nguon":["@c0540","@c0546"],"aliases":["#sat-luc-dao-he"]},{"id":"chuyen-luan-thuat-mac-phi","name":"Chuyển Luân thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Trấn phái","hePhai":"Mặc Phi (Yêu Tướng)","soHuu":["Mặc Phi"],"blurb":"Thần thông trấn phái của Mặc Phi, làm tăng uy lực mọi thần thông và làm chiêu thức đối thủ quay ngược trở về.","detail":"Thần thông bí ẩn của Mặc Phi — đệ nhất nhân trong đám Yêu Tướng. Có thể làm tăng uy lực công pháp, thần thông và làm chiêu thức của đối thủ (như Yêu Hải Bách Lãng của Mạc Lệ Hải) quay ngược trở về. Trong ba năm tĩnh tu ở Long Đàm Cổ Yêu Điện, chưa ai buộc Mặc Phi phải dùng thần thông thứ hai ngoài Chuyển Luân thuật.","nguon":["@c0542"]},{"id":"kiem-khi-bao-menh-lang-thien-hau","name":"Kiếm khí bảo mệnh của Lăng Thiên Hậu","loai":"than-thong","loaiLabel":"Kiếm khí thần thông","phamCap":"Bảo mệnh thần thông","hePhai":"Đại La Kiếm Tông / Kiếm Tôn Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu","Mạt Dương","Vương Lâm"],"blurb":"Đạo kiếm khí Lăng Thiên Hậu ban cho mười hai đệ tử Đại La Kiếm Tông, hình một thanh kiếm thu nhỏ màu lam ẩn ở mi tâm.","detail":"Năm xưa ở ngoài cửa Yêu Linh tại Đông Hải, trước khi đệ tử Đại La Kiếm Tông tiến vào, Kiếm Tôn Lăng Thiên Hậu đã ban cho mỗi người một đạo kiếm khí gọi là bảo mệnh thần thông của mười hai người. Kiếm khí ẩn ở mi tâm dưới dạng một thanh kiếm thu nhỏ vô số lần, màu lam; khi phát ra có thể trực tiếp đột phá ba nghìn dấu ấn bao trùm thân thể và nguyên thần — điều mà cả tu sĩ Vấn Đỉnh Trung Kỳ cũng không làm được. Vương Lâm đoạt đạo kiếm khí này từ nguyên thần Mạt Dương rồi nuốt vào.","nguon":["@c0542"]},{"id":"yeu-nhien-mac-le-hai","name":"Yêu Nhiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thiên Yêu Quận","soHuu":["Mạc Lệ Hải"],"blurb":"Tuyệt chiêu của Mạc Lệ Hải do Đế Quân đích thân truyền.","detail":"Thần thông Mạc Lệ Hải được Đế Quân đích thân truyền thụ khi hắn trở thành Yêu Tướng. Sử ra có thể phá được mười bảy trong mười tám tầng Chuyển Luân thuật, chỉ thua ở tầng cuối cùng.","nguon":["@c0543"]},{"id":"cuu-tu-cuu-sinh-chi-khi","name":"Cửu Tử Cửu Sinh chi khí","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"","soHuu":["Mộ Vân"],"blurb":"Công pháp của Mộ Vân, cảnh giới đo bằng số tầng “X Tử X Sinh”.","detail":"Công pháp đặc biệt mà Mộ Vân tu luyện, đo cảnh giới bằng số tầng dạng “X Tử X Sinh”. Mộ Vân ba trăm năm trước đã đạt Ngũ Tử Ngũ Sinh, đến trận Yêu Tướng đột phá tầng bảy, hóa năm đạo sinh tử yêu khí màu xanh lục uốn lượn như linh xà.","nguon":["@c0543"]},{"id":"quang-do-thach-tieu","name":"Quang đồ hình thoi và hình nón (Thạch Tiêu)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thạch Tiêu"],"blurb":"Thần thông biến hóa quang đồ của Thạch Tiêu, tốc độ cực nhanh.","detail":"Điểm năm ngón tay biến hóa, Thạch Tiêu tạo ra quang đồ hình thoi cắn nát yêu khí địch thủ rồi ấn nổ, và hình nón dung yêu lực đen có thể đâm xuyên cơ thể kẻ địch thành máu thịt. Đòn ra cực nhanh, từng dùng để hạ Mộ Vân và giết trợ giúp Thiên Khôi Công Nhân.","nguon":["@c0543"]},{"id":"suong-tien-luc-cam-che-thien-khoi-cong-nhan","name":"Sương tiên lực và cấm chế (Thiên Khôi Công Nhân)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cự Linh Môn","soHuu":["Thiên Khôi Công Nhân"],"blurb":"Thần thông thiên về sức lực của Thiên Khôi Công Nhân.","detail":"Thiên Khôi Công Nhân đẩy tiên lực từ lỗ chân lông tạo sương bao bọc thân thể, kèm chú ngữ dựng cấm chế phạm vi trăm trượng. Thần thông thiên về sức lực, phong cách tương tự Cự Ma Tộc.","nguon":["@c0543"]},{"id":"chieu-don-tho-ngao-dich","name":"Chiêu độn thổ (Ngao Địch)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu tộc","hePhai":"Yêu tộc","soHuu":["Ngao Địch"],"blurb":"Thần thông độn thổ phối hợp bổn mệnh yêu thú, đổi được hướng tấn công.","detail":"Ngao Địch lấy yêu lực thôi thúc, giậm chân biến mất xuống lòng đất, phối hợp bổn mệnh yêu thú để di chuyển và phản kích. Chiêu có thể đổi hướng tấn công khi đối phương phá đất, nhưng trong quảng trường Thiên Yêu Môn đầy cấm chế thì thi triển khó hơn bên ngoài gấp mười lần, nên bị Vương Lâm bức ra khỏi lòng đất.","nguon":["@c0544"]},{"id":"sat-luc-dao-vu-sam","name":"Sát Lục Đạo (Vu Sâm)","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Yêu tộc","hePhai":"Yêu tộc","soHuu":["Vu Sâm"],"blurb":"Pháp môn Yêu Tướng Vu Sâm tu luyện, khí tức toàn thân âm hàn.","detail":"Sát Lục Đạo là pháp môn của Yêu Tướng Vu Sâm, khiến toàn thân hắn tỏa ra khí tức âm hàn lạnh lẽo. Khi chứng kiến Vương Lâm phế Ngao Địch, Vu Sâm lộ rõ chiến ý nhìn về phía hắn.","nguon":["@c0544"]},{"id":"that-yeu-chi-thuat","name":"Thất Yêu Chi Thuật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu tộc","hePhai":"Yêu tộc","soHuu":["Nam tử tóc đen (đeo nhẫn)"],"blurb":"Tuyệt kỹ của một Yêu Tướng tóc đen, thử thách đối thủ chịu được mấy Yêu.","detail":"Thất Yêu Chi Thuật là tuyệt kỹ của một nam tử tóc đen đeo nhẫn trong hàng ngũ Yêu Tướng. Khi thấy Vương Lâm ra tay, hắn nhắc tới thuật của mình, tò mò không biết đối phương chịu được “mấy Yêu”.","nguon":["@c0544"]},{"id":"than-thong-ngung-anh-mat-troi","name":"Thần thông ngưng ánh sáng mặt trời","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao cấp","hePhai":"","soHuu":["Nam tử mặc giáp vàng"],"blurb":"Thần thông biến ánh sáng mặt trời thành sức mạnh; cao cấp thì hóa thành chất lỏng.","detail":"Thần thông ngưng tụ ánh sáng mặt trời thành sức mạnh để vận dụng. Bậc cao thâm có thể luyện ánh sáng mặt trời thành chất lỏng — điều Thiên Vận Tử từng tán thưởng. Kim tổng quản dùng thần thông này ngưng kim quang thành trường thương vàng có uy lực như khai thiên lập địa, dù chưa đạt tới mức hóa lỏng.","nguon":["@c0544"]},{"id":"ky-xao-cam-nhan-kiem-linh","name":"Kỹ xảo cảm nhận Kiếm Linh","loai":"bi-thuat","loaiLabel":"Kỹ xảo","phamCap":"","hePhai":"","soHuu":["Tiểu Hắc Đao (Tiểu Hắc)","Hứa Lập Quốc"],"blurb":"Kỹ xảo của Tiểu Hắc Đao giúp Kiếm Linh bậc cao cảm nhận đồng loại và che giấu khí tức.","detail":"Kỹ xảo do Tiểu Hắc Đao truyền cho Hứa Lập Quốc: Kiếm Linh bậc cao có thể cảm nhận đồng loại quanh mình sau khi đối phương ra khỏi Kiếm Thể; kèm theo tuyệt chiêu che giấu khí tức Kiếm Linh. Nhờ kỹ xảo này, Hứa Lập Quốc phát hiện được thiếu nữ Kiếm Linh của Đế Kiếm ẩn trong hư không.","nguon":["@c0544"]},{"id":"in-dau-an-nguyen-than-loan-dao","name":"In dấu ấn nguyên thần (thu phục loan đao)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn luyện hóa cứng rắn: phun khí nguyên thần, không luyện hóa lâu mà không tiếc tổn hại linh thể, in dấu ấn nguyên thần lên pháp bảo để thu phục.","detail":"Vương Lâm dùng thủ đoạn này để thu phục loan đao Tiểu Hắc Đao: hắn phun khí nguyên thần, không luyện hóa từ từ mà dùng cách cứng rắn không tiếc tổn hại linh thể, in dấu ấn nguyên thần lên loan đao đã bị ép thành quả cầu. Tuy bị in dấu ấn, loan đao vẫn do dự rồi đi theo bên cạnh Hứa Lập Quốc chứ không phục Vương Lâm hoàn toàn.","nguon":["@c0545"]},{"id":"sau-muoi-tu-dao-kiem-khi-mat-duong","name":"Sáu mươi tư đạo kiếm khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông kiếm khí","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Mạt Dương"],"blurb":"Thần thông kiếm khí của Mạt Dương: một đạo hóa hai, hai hóa bốn, nhân lên thành sáu mươi tư đạo gào thét tấn công.","detail":"Mạt Dương bấm quyết, một đạo kiếm khí hóa hai, hai hóa bốn cho đến khi thành sáu mươi tư đạo cùng gào thét lao tới đối thủ. Khi đâm vào người Vương Lâm, dấu ấn hộ thể hiện lên khiến toàn bộ kiếm khí tiêu tan, không gây tổn thương.","nguon":["@c0541"]},{"id":"mat-duong-kiem-tram","name":"Mạt Dương kiếm trảm","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm chiêu","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Mạt Dương"],"blurb":"Kiếm chiêu Mạt Dương thi triển cùng cự kiếm tím dung hợp Tà Dương Chi Hồn, mang kình khí như sét giáng.","detail":"Sau khi rút cự kiếm tím bản mệnh và để Tà Dương Chi Hồn hợp nhất với kiếm tăng uy lực, Mạt Dương thi triển Mạt Dương kiếm trảm, kình khí dữ dội như sét đánh xuống. Vương Lâm tay phải bắt sống cự kiếm, hóa giải chiêu thức rồi diệt Dương Hồn.","nguon":["@c0541"]},{"id":"kiem-khi-lang-thien-hau","name":"Kiếm khí của Lăng Thiên Hậu","cn":"","loai":"than-thong","loaiLabel":"Thần thông bảo mệnh","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Mạt Dương","Lăng Thiên Hậu"],"blurb":"Sát chiêu tối hậu do sư tôn Lăng Thiên Hậu ban cho mỗi đệ tử Kiếm Tiếu Thập Nhị Tử một đạo (tổng mười hai đạo).","detail":"Lăng Thiên Hậu ban cho mỗi đệ tử trong Kiếm Tiếu Thập Nhị Tử một đạo kiếm khí bảo mệnh, tổng cộng mười hai đạo, được xem là sát chiêu tối hậu không thể tùy tiện sử dụng — dùng rồi thì bốn trăm năm còn lại sẽ vô cùng khó khăn. Mạt Dương suýt phải dùng tới khi bị Vương Lâm áp chế nhưng được tha mạng nên giữ lại.","nguon":["@c0541","@c0564","@c0563"]},{"id":"dau-an-ho-the-vuong-lam","name":"Dấu ấn hộ thể của Vương Lâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông hộ thể","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Dấu ấn hiện trên thân Vương Lâm khiến kiếm khí đâm vào lập tức tiêu tan; tay phải hiện ngàn dấu ấn vững như tay cổ thần.","detail":"Khi kiếm khí của địch đâm vào người, trên thân Vương Lâm hiện dấu ấn khiến chúng tiêu tan tức thì. Tay phải hắn có thể hiện ngàn dấu ấn, vững như tay cổ thần, đủ sức bắt giữ và khống chế cự kiếm bản mệnh của đối thủ.","nguon":["@c0541"]},{"id":"phe-hon-sat-luc-de-nhat-thuc","name":"Phệ Hồn Sát Lục đệ nhất thức","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Sát Lục đạo","soHuu":["Vu Sâm"],"blurb":"Thần thông Sát Lục đạo của Vu Sâm: yêu khí ngưng thành các khuôn mặt thống khổ há miệng bay vào tay, hóa chưởng phong đánh trống.","detail":"Thần thông đệ nhất thức trong Sát Lục đạo của Yêu Tướng Vu Sâm. Khi thi triển, yêu khí ngưng tụ thành vô số khuôn mặt thống khổ há miệng bay vào tay phải, tay tỏa ánh sáng lam rồi hóa thành chưởng phong Phệ Hồn. Vu Sâm dùng nó để gõ Chiến Yêu Cổ tiếng thứ ba và thứ tư, nhưng sau đó tay phải mất cảm giác và yêu lực hao tám phần.","nguon":["@c0546"]},{"id":"chuyen-luan-dai-phap-mac-phi","name":"Chuyển Luân Đại Pháp","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Công pháp thần bí của Mặc Phi","soHuu":["Mặc Phi"],"blurb":"Thần thông duy nhất Mặc Phi từng thi triển, thuộc một công pháp thần bí của hắn.","detail":"Thần thông duy nhất mà Yêu Tướng Mặc Phi từng để lộ trước công chúng, vốn thuộc một bộ công pháp thần bí khó dò mà hắn tu luyện. Đến chương này hắn mới chỉ lộ một thức, gợi rằng còn ẩn giấu nhiều thủ đoạn.","nguon":["@c0546"]},{"id":"lac-an-sinh-menh-vuong-lam","name":"Lạc Ấn Sinh Mệnh","cn":"","loai":"cong-phap","loaiLabel":"Công pháp phòng ngự","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vô số dấu ấn sinh mệnh như lá chắn bao phủ toàn thân, sinh sôi không ngừng, tan vỡ rồi ngưng tụ trở lại.","detail":"Còn gọi Sinh Chi Lạc Ấn. Hơn ba ngàn (đỉnh ba nghìn bảy trăm) dấu ấn bao phủ toàn thân Vương Lâm làm lá chắn chống phản lực Yêu Cổ. Chỗ lợi hại thật sự nằm ở việc các Lạc Ấn sinh sôi không ngừng, dù tan vỡ vẫn ngưng tụ trở lại. Theo lời Thiên Vận Tử áo xám, Vương Lâm có thể tới mười triệu đạo Lạc Ấn Sinh Mệnh phòng thân, dù Thiên Vận Tinh sụp đổ hắn cũng bình an.","nguon":["@c0547"]},{"id":"ngon-xuat-phap-tuy","name":"Ngôn Xuất Pháp Tùy","cn":"言出法隨","loai":"khac","loaiLabel":"Cảnh giới / hiện tượng","phamCap":"","hePhai":"","soHuu":[],"blurb":"Lời nói mang khuôn phép, dẫn động thiên uy, không thể không nghe.","detail":"Khi câu nói dung nhập tiếng trống hóa thành vô số hồi âm như tiếng của trời đất, đại diện thiên địa, tựa sấm kinh người. Bảy yêu soái kinh sợ thốt lên cảnh giới này khi Vương Lâm gõ tiếng trống thứ tám mang câu “Ta muốn một bàn tay của ngươi”. Kim tổng quản chỉ ra Vương Lâm chỉ MƯỢN uy lực chiếc trống để dẫn động thiên uy chứ chưa thật sự đạt được cảnh giới ngôn xuất pháp tùy.","nguon":["@c0547"]},{"id":"than-thong-duong-hoa-kim-tong-quan","name":"Thần thông Dương Hỏa (Kim tổng quản)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Kim tổng quản"],"blurb":"Công pháp cực bá đạo liên quan Dương Hỏa, mạnh ban ngày giữa trưa, yếu nửa đêm canh ba khi âm khí mạnh.","detail":"Thần thông của Kim tổng quản, cực bá đạo và liên quan tới Dương Hỏa. Sức mạnh đạt đỉnh ban ngày giữa trưa, suy yếu nửa đêm canh ba lúc âm khí mạnh — Vương Lâm âm thầm tính toán nếu giao đấu giữa trưa thì khó thắng, còn nửa đêm thì dễ đánh hơn.","nguon":["@c0547"]},{"id":"dao-thuan-nghich-vuong-lam","name":"Đạo Thuận - Nghịch","cn":"","loai":"khac","loaiLabel":"Cảm ngộ","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lực đánh là thuận, tiếng trống vang là nghịch; một thuận một nghịch ẩn tàng biến hóa thiên địa.","detail":"Cảm ngộ Vương Lâm đạt được khi gõ Yêu Cổ: phản lực tiếng trống là khí tức bất khuất, cuồng ngạo nghịch thiên trong ý niệm. Trước đó hắn sai khi dùng Sinh Chi Lạc Ấn chống nghịch ý (vô hình chống chọi nghịch ý trong lòng mình). Một thuận một nghịch ẩn tàng biến hóa thiên địa, tương đồng cảm ngộ “đạo niệm bất thành” mà hắn từng có khi nghe tiếng đàn trên sông.","nguon":["@c0547"]},{"id":"tay-tuy-tieng-trong-yeu-co","name":"Tẩy tủy bằng tiếng trống Yêu Cổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Yêu tộc","soHuu":["Vương Lâm"],"blurb":"Dung hợp nguyên thần với khí tức không chịu khuất phục trong Yêu Cổ, thu hồi phòng ngự để lực phản chấn tiến thẳng vào người mà tẩy tủy.","detail":"Pháp môn tẩy tủy mượn lực phản chấn của Yêu Cổ: người đánh dung hợp nguyên thần với cổ khí tức “không chịu khuất phục” ẩn trong trống, thu hồi phòng ngự cho lực trùng kích tiến thẳng vào cơ thể, ép mồ hôi đen dơ bẩn ra khỏi lỗ chân lông và đạt cảm giác tẩy tủy sảng khoái của cảnh Trúc Cơ kỳ. Tuy nhiên nếu tu vi không đủ hoặc đạo không tương hợp thì lực lượng vào người vận chuyển loạn, gây trọng thương — như Yêu Đế từng nói. Vương Lâm về sau nhận ra cốt lõi không nằm ở tu vi mà ở chỗ phải dung hợp theo đạo của riêng mình.","nguon":["@c0548"]},{"id":"trong-truyen-niem","name":"Tiếng trống truyền niệm","cn":"","aliases":["Trống truyền đạo"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu tộc","soHuu":["Vương Lâm"],"blurb":"Cảnh giới đánh trống đem ý niệm bi thương và đạo tâm truyền vào tiếng trống, gây cộng hưởng tâm linh toàn trường.","detail":"Một loại cảnh giới hiếm được tóm gọn “lấy bi nhập thần, dùng thần nhập niệm, lấy niệm đánh trống, dùng trống truyền đạo”. Vương Lâm đem ý niệm bi thương cùng cảm ngộ tiếng đàn hoa thuyền hòa vào tiếng trống thứ mười một của Yêu Cổ, khiến bi niệm lan khắp quảng trường và cả Thiên Yêu thành; mọi người nghe được chìm vào nội tâm, cộng hưởng tâm tình và rơi lệ. Các Yêu soái xem đây là một cảnh giới hiếm có, Huyền Hôn soái cho rằng ngư��i đạt tới có thể chính là kẻ Yêu Đế chờ đợi nhiều năm.","nguon":["@c0548"]},{"id":"cam-ngo-dao-cua-rieng-minh","name":"Cảm ngộ đạo của riêng mình (chữ nghịch)","cn":"","loai":"khac","loaiLabel":"Lý niệm tu hành","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lý niệm rằng mỗi sinh linh nghịch thiên tu hành đều có cái nghịch riêng tùy cảm ngộ, không thể đi theo đạo của kẻ khác.","detail":"Vương Lâm ngộ ra trong Yêu Cổ ẩn tàng một loại ý thức và nghịch lực; nếu chỉ lo dung hợp thì tuy phù hợp âm nghịch nhưng đó là đạo của Yêu Cổ chứ không phải đạo của mình, nên hắn bị thương khi tẩy tủy không phải vì tu vi yếu mà do khác biệt về đạo. Trong thiên hạ bất kể tu sĩ hay sinh linh, chỉ cần nghịch thiên tu hành đều có cái “nghịch” riêng; một chữ nghịch chia thành nhiều con đường tùy cảm ngộ mỗi người. Tu đạo bảy trăm năm, Vương Lâm có đạo riêng, một Ý Cảnh cô độc và suy tàn lóe lên trong mắt.","nguon":["@c0548"]},{"id":"trong-truyen-dao-truyen-niem","name":"Tiếng trống truyền đạo / truyền ni��m","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Yêu Cổ kỹ pháp","hePhai":"Thiên Yêu quận","soHuu":["Vương Lâm"],"blurb":"Dùng tiếng trống Yêu Cổ để truyền niệm — một cảnh giới Ý Cảnh thăng hoa linh hồn.","detail":"Kỹ pháp dùng tiếng trống Yêu Cổ để truyền niệm, đạt tới một cảnh giới Ý Cảnh thăng hoa linh hồn, không liên quan trực tiếp tới tu vi. Người mặc kim giáp tự nhận không thể làm được điều này. Khi Vương Lâm gõ tới tiếng trống thứ mười một, tiếng trống truyền niệm vang lên đã đẩy hắn tới biên giới Vấn Đỉnh.","nguon":["@c0549"]},{"id":"tay-tuy-qua-yeu-co","name":"Tẩy tủy (qua Yêu Cổ)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Yêu Cổ kỹ pháp","hePhai":"Thiên Yêu quận","soHuu":["Vương Lâm"],"blurb":"Quá trình gõ Yêu Cổ dung hợp bi ai tạo lực trùng kích gột sạch tạp chất trong cơ thể.","detail":"Ba tiếng trống thứ mười hai, mười ba, mười bốn dung hợp bi ai tạo lực trùng kích đi vào cơ thể, gột sạch tạp chất, mồ hôi đen tiết ra khắp lỗ chân lông. Có mức thấp gọi là tẩy da lông và mức thật gọi là tẩy tủy. Âm thanh tẩy tủy còn lan ra khiến người nghe sinh dao động tẩy tủy kém hơn.","nguon":["@c0549"]},{"id":"sinh-chi-lac-an-ba-nghin-dao","name":"Sinh Chi Lạc Ấn (ba nghìn đạo)","cn":"","loai":"than-thong","loaiLabel":"Thần thông / ấn pháp phòng ngự","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Vương Lâm chuyển ba nghìn đạo Sinh Chi Lạc Ấn lên khắp toàn thân làm lớp phòng ngự.","detail":"Khi Kim Ô Húc tập kích, Vương Lâm đã sớm chuyển ba nghìn đạo Sinh Chi Lạc Ấn lên khắp toàn thân, kết hợp uy lực tiếng trống thứ mười lăm để chống lại một quyền cầm mặt trời của đối phương, tin chắc đỡ được.","nguon":["@c0550"]},{"id":"dao-nghich-nghich-thien","name":"Nghịch (đạo nghịch thiên)","cn":"","loai":"khac","loaiLabel":"Đạo / lý niệm tu hành","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Con đường Vương Lâm ngộ ra: tu đạo chân chính là nghịch thiên mà đi, không xóa bỏ tình cảm.","detail":"Vương Lâm ngộ ra rằng “dối trời” của tu sĩ thượng cổ thực chất là trốn chạy, là thuận thiên. Đạo của hắn là nghịch — nghịch thiên mà đi, giữ trọn những gì trong lòng nắm giữ dù thiên đạo cũng đừng hòng cướp. Vấn Đỉnh không do thiên định mà do tâm tu sĩ tự quyết: tâm thỏa hiệp thì bị trời lừa, tâm kiên định thì trời không cản nổi. Khi bộc phát, biểu hiện thành luồng khí tức như vô số kiếm sắc đâm thẳng lên trời, ép mây tản ra, trời đất rực sáng.","nguon":["@c0550"]},{"id":"phap-quyet-o-quang-thien-soai","name":"Pháp quyết ô quang (Thiên soái)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Thiên soái"],"blurb":"Thiên soái bấm pháp quyết hóa thành một đạo ô quang đánh vào tay trái Kim Ô Húc.","detail":"Để ngăn Kim Ô Húc giết Vương Lâm, Thiên soái phóng xuống quát ngăn rồi bấm pháp quyết, hóa thành một đạo ô quang đánh vào tay trái Kim Ô Húc (tay Kim Ô Húc vỗ về sau để cản Thiên soái).","nguon":["@c0550"]},{"id":"quyen-cam-mat-troi-kim-o-huc","name":"Quyền cầm mặt trời (Kim Ô Húc)","cn":"","loai":"than-thong","loaiLabel":"Thần thông Yêu nhân","phamCap":"","hePhai":"","soHuu":["Kim Ô Húc"],"blurb":"Tay phải Kim Ô Húc bộc phát hào quang như cầm cả mặt trời, đốt cháy mặt đất trăm trượng như địa ngục.","detail":"Khi tập kích Vương Lâm từ sau lưng, Kim Ô Húc dồn toàn bộ tu vi vào chân phóng tới, tay phải bộc phát hào quang chói lọi như cầm một mặt trời, đốt cháy đất trong phạm vi trăm trượng biến thành cảnh tượng như địa ngục, quyết không cho Vương Lâm đánh tiếng trống thứ mười lăm.","nguon":["@c0550"]},{"id":"dung-hop-dao-tam-tien-luc-van-dinh","name":"Dung hợp đạo tâm – tiên lực (tiến Vấn Đỉnh)","cn":"","loai":"khac","loaiLabel":"Đạo trời","phamCap":"Vấn Đỉnh","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Khi tiên lực và đạo tâm cùng viên mãn thì hai bên dung hợp, tiến hóa từ người thành tiên.","detail":"Lúc tiên lực và đạo tâm đều viên mãn, đạo tâm và tiên lực, linh hồn và xác thịt đánh mạnh vào nhau để tiến hóa từ người thành tiên. Đây là tử kiếp lớn nhất của Vấn Đỉnh: thành thì thành tu sĩ Vấn Đỉnh, không thì chết; muốn thành tán tiên cũng không được, trừ phi dừng lại ở Anh Biến hậu kỳ đại viên mãn.","nguon":["@c0552"]},{"id":"loi-hinh-trung-phat-thien-kiep","name":"Lôi hình trừng phạt (thiên kiếp)","cn":"","loai":"khac","loaiLabel":"Thiên kiếp","phamCap":"","hePhai":"","soHuu":[],"blurb":"Một trong hai loại lôi hình trừng phạt của thiên đạo; loại đầu tiên cũng là loại đơn giản nhất.","detail":"Thiên kiếp dùng lôi hình trừng phạt có hai loại; lần này là loại đầu tiên, đơn giản nhất — hồng vân ngưng tụ thành kiếp lôi đỏ như máu mang thiên sát giáng xuống. Loại thứ hai trong truyền thuyết được cho là đáng sợ hơn nhiều.","nguon":["@c0552"]},{"id":"sat-luc-long-thuong-long","name":"Sát Lục Long (Thương Long)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đỉnh phong","hePhai":"Sát Lục đạo","soHuu":["Vương Lâm"],"blurb":"Vương Lâm ngưng tụ ba nghìn bảy trăm đạo Sinh ấn hóa khí sát lục, ba nghìn luồng khí xám hợp thành Thương Long thôn phệ thiên kiếp.","detail":"Thần thông do Vương Lâm thi triển khi độ kiếp: ngưng tụ ba nghìn bảy trăm đạo Sinh ấn hóa thành khí sát lục, ba nghìn luồng khí xám cuộn thành cơn lốc rồi hợp thành Thương Long — chính là ý thức nghịch thiên của Vương Lâm, mang cả sát tâm lẫn sát ý. Thương Long thôn phệ hồng lôi làm nó tối sầm, thu nhỏ, nhưng vì thiên kiếp mang sát khí của trời nên rồng vẫn tan biến.","nguon":["@c0553"]},{"id":"nghich-tu-khai-niem","name":"Nghịch tu","cn":"","loai":"khac","loaiLabel":"Khái niệm tu luyện","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Con đường tu nghịch thiên đạo, ngênh chiến trực tiếp thay vì thuận theo hay trốn tránh.","detail":"Nghịch tu là con đường tu luyện chống nghịch thiên đạo. Thiên đạo kiêng kỵ những sinh linh chọn ngênh chiến (không trốn tránh) và sẽ giáng thiên kiếp xóa bỏ sạch sẽ. Vương Lâm chọn trực tiếp đối mặt khi tiến Vấn Đỉnh nên thiên kiếp giáng đòn trừng phạt. Tộc Cổ thời sơ khai là sinh linh nghịch tu thứ nhất; ba nhánh Cổ Thần/Cổ Ma/Cổ Yêu là nghịch tu thứ hai.","nguon":["@c0554"]},{"id":"yeu-luc-co-yeu","name":"Yêu lực (Cổ Yêu)","cn":"","loai":"khac","loaiLabel":"Lực lượng đặc thù","phamCap":"","hePhai":"Cổ Yêu","soHuu":["Năm lão già Cổ Yêu"],"blurb":"Lực lượng đặc thù của Cổ Yêu, tung hoành bao phủ toàn Thiên Yêu thành khi phản kháng thiên uy.","detail":"Yêu lực là lực lượng năm lão già con cháu Cổ Yêu vận dụng. Khi phản kháng thiên uy của thiên kiếp, họ phóng Yêu lực bao phủ toàn bộ Thiên Yêu thành rồi lao thẳng lên hồng vân, song vẫn bị quẳng xuống đất.","nguon":["@c0554"]},{"id":"van-dinh-cua-khau","name":"Vấn Đỉnh","loai":"cong-phap","loaiLabel":"Cảnh giới / quá trình tu luyện","phamCap":"Cửa khẩu cảnh giới lớn","hePhai":"Tu chân giả phổ quát","soHuu":["Vương Lâm","Chu Dật"],"blurb":"Cửa khẩu cảnh giới dung hợp tiên lực và Ý Cảnh thành Vấn Đỉnh Chi Tinh — trái tim nguyên thần.","detail":"Vấn Đỉnh là quá trình lấy tiên lực làm ngọn lửa vô hình luyện hóa Ý Cảnh thành Vấn Đỉnh Chi Tinh nằm trong kén nguyên thần. Ý Cảnh hòa tan thành dòng Nguyên Khí, dùng tiên hỏa nung kết tinh; thất bại thì lửa vô hình hóa thực chất đốt cháy nguyên thần và xác thịt thành tro — ứng câu ‘triêu văn đạo tịch tử hĩ’. Bước cảm ngộ Vấn Đỉnh (thần du thiên địa) dùng để rút mệnh hồn với xác suất năm phần; Vương Lâm đã thu hồi mệnh hồn nên bỏ qua bước này.","nguon":["@c0555"]},{"id":"diet-dao-co-yeu","name":"Diệt đạo","aliases":["Vân toái"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông cường giả viễn cổ","hePhai":"Cổ Yêu / Thiên Yêu quận","soHuu":["Cổ Yêu","Vương Lâm"],"blurb":"Thần thông của Cổ Yêu, cùng hô ‘Diệt đạo’ rồi vỗ ‘vân toái’ đập vỡ hồng vân thiên kiếp.","detail":"Cổ Yêu nâng tay trước, Vương Lâm theo sau, cùng hô Diệt đạo; Yêu khí ngập trời bùng lên, hai chưởng ‘vân toái’ đập lên hồng vân thiên kiếp khiến nó vỡ tan, sóng lan mười vạn dặm. Cổ Yêu nhờ nhiều lần chống thiên kiếp nên thân thể ngưng thực lại nhanh sau khi thi triển.","nguon":["@c0555"]},{"id":"y-canh-chi-tu-si-y","name":"Chí Tử Si Ý","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"Ý cảnh Vấn Đỉnh","hePhai":"Của Chu Dật","soHuu":["Chu Dật"],"blurb":"Ý cảnh ẩn trong Vấn Đỉnh Chi Tinh mà Chu Dật tặng Vương Lâm.","detail":"Chí Tử Si Ý là Ý cảnh Chu Dật ngưng tụ trong viên Vấn Đỉnh Chi Tinh tặng Vương Lâm năm xưa. Khi Vương Lâm suýt thất bại tiến Vấn Đỉnh, viên ngọc này từ đan điền bay vào kén nguyên thần, dập bớt tiên hỏa rồi tan vỡ, dồn toàn bộ nguyên khí cho Vương Lâm.","nguon":["@c0555"]},{"id":"luyen-khi-si-vien-co","name":"Tu luyện Luyện Khí Sĩ viễn cổ","loai":"cong-phap","loaiLabel":"Lý luận tu chân","phamCap":"Viễn cổ","hePhai":"Côn Lôn Luyện Khí Sĩ","soHuu":[],"blurb":"Phương thức tu luyện của các Luyện Khí Sĩ thời viễn cổ: luyện Nguyên Khí rút ra ngoài thay tiên lực.","detail":"Người tu thời viễn cổ tự xưng Luyện Khí Sĩ, điển hình là Côn Lôn Luyện Khí Sĩ; luyện Nguyên Khí — thứ Ý cảnh hòa tan tạo ra. Sau khi tiên giới xuất hiện, người tu chuyển sang đem nguyên khí hóa bản mệnh chân khí bọc tiên lực ngoài; nguyên tắc ‘chỉ còn một luồng chân nguyên thì không bao giờ chết’ — chân nguyên chính là nguyên khí. Là nền lý luận giải thích vì sao Ý cảnh Sinh Tử Luân Hồi hòa tan thành nguyên khí khi luyện Vấn Đỉnh.","nguon":["@c0555"]},{"id":"von-xoay-den-hut-nguyen-khi-556","name":"Vòng xoáy đen hút nguyên khí","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chủ nhân áo giáp trong hắc tháp","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"blurb":"Vòng xoáy đen khổng lồ xuất hiện không tiếng động, thần thức không phát hiện sớm, có thể tới khắp nơi thiên hạ.","detail":"Một vòng xoáy đen khổng lồ kèm sấm rền nổ ra trên bầu trời, hút được vạn vật; xuất hiện hết sức xảo diệu khiến thần thức đối phương không kịp phát hiện. Chủ nhân áo giáp dùng vòng xoáy để phóng bộ xương cánh tay đen đi đoạt nguyên khí tu sĩ Vấn Đỉnh và can nhiễu truyền tống của họ, khiến Vương Lâm bị đẩy lệch sang Hỏa Yêu quận.","nguon":["@c0556"]},{"id":"thien-ma-phong","name":"Thiên Ma Phong","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Kẻ trong hắc tháp (Cổ Yêu Thuật)","soHuu":["Chủ nhân hộ uyển (kẻ trong hắc tháp)"],"blurb":"Lực lượng vô hình bay đến như cơn gió nhẹ, thổi lên thân khiến nguyên thần đối thủ muốn bay theo.","detail":"Thần thông của kẻ trong bảo tháp chiến trường viễn cổ, chuyên săn nguyên thần tu sĩ vừa tiến Vấn Đỉnh. Lực vô hình thổi tới khiến nguyên thần muốn bay theo, tâm thần không phản kháng. Vương Lâm phải dùng sát tâm đập vào sát ý sinh sát khí nồng đậm mới kéo được nửa nguyên thần đang thoát ra quay về cơ thể.","nguon":["@c0557"]},{"id":"thien-ma-loan-vu","name":"Thiên Ma Loạn Vũ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Kẻ trong hắc tháp (Cổ Yêu Thuật)","soHuu":["Chủ nhân hộ uyển (kẻ trong hắc tháp)"],"blurb":"Hắc ảnh ma âm chui vào cơ thể hóa từng luồng ma khí chạy theo kinh mạch, trực tiếp chấn động nguyên thần.","detail":"Thần thông phát ra từ hộ uyển/ký hiệu của kẻ địch. Ma diễm hóa hắc ảnh nắm tay một sừng toàn thân đen kịt, chui vào cơ thể đối phương hóa từng luồng ma khí nhỏ chạy theo kinh mạch, tạo ảo giác trực tiếp chấn động nguyên thần. Vương Lâm phải nuốt giọt cô đọng Thăng Tiên Quả lấy kích thích cực mạnh làm động lực mới ép xuất được hắc ảnh ra khỏi cơ thể, rồi diệt bằng Hoàng Tuyền Chỉ.","nguon":["@c0557"]},{"id":"co-yeu-thuat-yeu-linh","name":"Cổ Yêu Thuật","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Lãnh thổ Yêu Linh","soHuu":[],"blurb":"Công pháp bản địa của lãnh thổ Yêu Linh; người tu nó không thể hình thành nguyên khí.","detail":"Trong lãnh thổ Yêu Linh, tu sĩ tu Cổ Yêu Thuật không thể hình thành nguyên khí. Chỉ khi tu sĩ tiến lên Vấn Đỉnh mới sinh nguyên khí — và đây chính là điều kẻ trong hắc tháp lợi dụng để thôn phệ nguyên khí của hầu hết tu sĩ Yêu Linh đạt Vấn Đỉnh suốt nhiều năm.","nguon":["@c0557"]},{"id":"ma-chi-hoa-ma","name":"Ma Chỉ (Hóa ma)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chỉ pháp không dùng tiên lực trong thân mà hấp thụ yêu lực trời đất, ngưng tụ điểm hắc quang thôn phệ ánh sáng.","detail":"Vương Lâm thi triển dưới tu vi Vấn Đỉnh: đầu ngón tr��� hóa vòng xoáy hút yêu lực trong trời đất, ngưng tụ thành điểm hắc quang thôn phệ ánh sáng. Ma khí của Ma Chỉ khác biệt lớn với tử khí của Tịch Diệt Chỉ; búng ra làm bộ xương khô tan vỡ.","nguon":["@c0557"]},{"id":"than-thong-hap-thu-sinh-co-van-vat","name":"Thần thông hấp thu sinh cơ vạn vật","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Tịch diệt","soHuu":["Vương Lâm"],"blurb":"Thần thông hấp thu toàn bộ sinh cơ vạn vật trong trời đất chuyển thành của mình để khôi phục thương thế.","detail":"Vương Lâm vận chuyển tịch diệt để thôn phệ sinh cơ của vạn vật, biến thành sinh cơ của chính mình nhằm khôi phục thân thể trọng thương. Khi hắn phi hành, mặt đất bên dưới khô héo, sinh linh đều chết, cây cối héo rụi, mọi thứ hóa thành bạch quang để tẩm bổ thân thể hắn, khiến hắn tựa như đến từ Ma Giới, từ địa ngục thôn phệ tất cả sự sống.","nguon":["@c0559"]},{"id":"tran-phap-yeu-binh-tu-thu","name":"Trận pháp Yêu binh","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Yêu Linh","soHuu":["Tử Thử"],"blurb":"Trận pháp do ba vạn Yêu binh của Tử Thử bày ra để tập trung sát khí lên đối thủ.","detail":"Khi Tử Thử quyết liều mạng giết Vương Lâm, ba vạn Yêu binh phía sau phóng lên trời bày trận pháp, dồn toàn bộ sát khí tập trung công kích lên một mình Vương Lâm. Tuy thanh thế lớn nhưng toàn bộ ba vạn Yêu binh đã bị Vương Lâm tàn sát và hấp thu sinh cơ.","nguon":["@c0559"]},{"id":"tran-phap-diet-dich-yeu-binh","name":"Trận pháp diệt địch (Yêu binh)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Hỏa Yêu quận","soHuu":["Hỏa Yêu quận"],"blurb":"Trận pháp do các Đô Thống chỉ huy mười vạn Yêu binh bày ra để diệt địch.","detail":"Khi lão già trong đám Yêu tướng ra lệnh, các Đô Thống điều mười vạn Yêu binh xếp trận. Yêu lực toàn quân tập hợp hóa thành một con bọ cạp hư ảo khổng lồ, đuôi phát sáng yêu dị tựa như có thể đánh nát hư không. Trận này đủ sức diệt một tu sĩ Vấn Đỉnh thông thường, nhưng không khuất phục được Vương Lâm trong trạng thái Sát Lục Tiên Quyết bùng phát.","nguon":["@c0560"]},{"id":"uc-hon-thon-phe-ho-bao","name":"Ức hồn thôn phệ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phái sinh từ Luyện Hồn thuật","soHuu":["Hổ Bào"],"blurb":"Chiêu của Hổ Bào, lùa trăm ngàn hồn phách hóa hắc vân ép xuống cắn nuốt đối thủ.","detail":"Thần thông Hổ Bào dùng để điều khiển trăm ngàn hồn phách viễn cổ chiến trường, hóa thành hắc vân ép xuống cắn nuốt mục tiêu. Chiêu này bị Vương Lâm vô hiệu hoàn toàn vì hồn phách của Hổ Bào vốn nằm dưới quyền khống chế tuyệt đối của Vương Lâm — đích hệ truyền thừa Luyện Hồn thuật; khi hô “Ức hồn thôn phệ” và “Hồn, tốc quy!”, hồn phách không nghe lệnh mà quay sang phục tùng Vương Lâm.","nguon":["@c0562"]},{"id":"cong-phap-thoi-phat-tiem-luc-sinh-menh-ho-bao","name":"Công pháp thôi phát tiềm lực và sinh mệnh","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Hổ Bào"],"blurb":"Bộ công pháp Vương Lâm suy đoán Hổ Bào tu, đẩy người đạt đỉnh điểm sức mạnh trong thời gian cực ngắn.","detail":"Vương Lâm kinh ngạc trước tốc độ tăng tiến của Hổ Bào — mạnh hơn cả Hồng Điệp năm xưa mà vẫn không thể trong mười mấy năm đạt tới mức này theo lẽ thường. Hắn đoán Hổ Bào tu một bộ công pháp thôi phát tiềm lực và sinh mệnh, giúp đạt đỉnh điểm sức mạnh rất nhanh nhưng duy trì cực ngắn, e không quá một ngày.","nguon":["@c0562"]},{"id":"dao-niem-hoa-than-hoang-long","name":"Đạo niệm hóa thân (Hoàng Long)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hoàng Tuyền đạo","soHuu":["Vương Lâm"],"blurb":"Vương Lâm thân nhập Hoàng Tuyền liền hóa thành Hoàng Tuyền, kết thành một con Hoàng Long gầm thét phá địch.","detail":"Khi bước thẳng vào trong Hoàng Tuyền do đạo niệm hóa thành, Vương Lâm chính là đạo, là Hoàng Tuyền — thân nhập Hoàng Tuyền liền hóa thành Hoàng Tuyền. Hoàng Tuyền cuộn lại thành hình một con Hoàng Long khổng lồ, đầu rồng là chỗ Vương Lâm đứng. Hoàng Long gầm thét phát ra Hoàng Tuyền chi âm — chính là nghịch tu chi đạo — khiến mưa đen của đối thủ vỡ vụn thành hắc khí phủ kín bầu trời.","nguon":["@c0563"]},{"id":"ngung-hoa-tuyen-hon-hoang-tuyen","name":"Ngưng hóa tuyền hồn (Hoàng Tuyền chi hồn)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Hoàng Tuyền đạo","soHuu":["Vương Lâm"],"blurb":"Dung hàng vạn hồn phách vào Hoàng Tuyền ngưng thành một hồn, khiến Hoàng Tuyền linh động như Hoàng Long sống.","detail":"Trong trạng thái thanh tỉnh, Vương Lâm vỗ Tôn Hồn Phiên phóng hàng vạn hồn phách điên cuồng dung nhập vào đạo Hóa Hoàng Tuyền, ngưng kết thành một Hoàng Tuyền chi hồn (tuyền hồn). Hoàng Tuyền có hồn liền linh động như Hoàng Long sống, đội đất lao ra muốn nuốt chửng thần thông phong vũ lôi điện của đối thủ; khi dung thêm mười ba vạn đạo sát lục chi khí thì Hoàng Tuyền còn mang theo sát khí.","nguon":["@c0563"]},{"id":"phong-vu-loi-dien-sao-tieu-giap","name":"Phong · Vũ · Lôi · Điện (Sáo Tiêu giáp)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Sáo Tiêu giáp","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"blurb":"Bốn thần thông hệ phong–lôi do bộ Sáo Tiêu giáp ban, có thể gộp lại buông xuống đại địa.","detail":"Hệ thần thông gắn với bộ Sáo Tiêu giáp: hô Phong tạo lốc/dòng xoáy cuốn đá vụn (và hút hắc khí); hô Vũ làm mưa đen do ma khí ngưng tụ; hô Lôi giáng hắc lôi xung thiên (trời u ám, mây đen như mặt ma); hô Điện dựng hàng rào điện chi chít. Lão giả có thể tung riêng từng đòn hoặc gộp cả bốn Phong–Vũ–Lôi–Điện buông xuống đại địa. Lôi hệ vốn được nói là khó luyện nhất trong tu sĩ.","nguon":["@c0563"]},{"id":"ma-dao-liem-dao-hac-giap-lao-gia","name":"Ma đạo (ngưng hóa ma liêm đao)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Ma đạo","soHuu":["Chủ nhân áo giáp trong hắc tháp"],"blurb":"Đạo thật trên khải giáp của hắc giáp lão giả: lấy ma niệm ngưng hóa thành ma liêm đao ẩn quy tắc siêu thoát thiên địa.","detail":"Hắc giáp lão giả tuyên bố Phong Vũ Lôi Điện chỉ là thần thông yếu nhất, còn đạo thật trên khải giáp của hắn là Ma đạo. Hắn vuốt ngực khải giáp, ma khí đen ngưng thành một thanh liêm đao tỏa ma diễm, ẩn chứa quy tắc siêu thoát thiên địa khiến không gian nứt vỡ; liêm đao còn ở giữa hư-thực chuyển hóa. Vì ma khí của hắn chưa tinh thuần, cần ma hồn phân thể (ma ảnh một sừng từ mi tâm) dung nhập thì liêm đao mới sống lại thành ma đao thật sự, bắn về phía địch. Ma đao này bị kiếm khí của Lăng Thiên Hậu đánh tan vỡ cùng ma ảnh.","nguon":["@c0564"]},{"id":"nguyen-than-thu-hai","name":"Nguyên thần thứ hai","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Sau Vấn Đỉnh","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông độc đáo chỉ thể hiện sau khi tu sĩ đạt cảnh giới Vấn Đỉnh.","detail":"Nguyên thần thứ hai là thần thông độc đáo thể hiện sau khi đạt cảnh giới Vấn Đỉnh, không phải ai cũng thành công. Nguyên nhân chính nằm ở phôi thể Nguyên thần thứ hai — phải có phôi thể phù hợp mới luyện thành. Vương Lâm tính dùng một Tán ma khổng lồ ở Long Đàm làm phôi thể để luyện thành Nguyên thần thứ hai.","nguon":["@c0567"]},{"id":"can-nuot-tan-ma-lac-an-nguyen-than","name":"Khống chế Tán ma (lạc ấn nguyên thần)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật liên tục biến hóa cấm chế và để lại lạc ấn nguyên thần lên hồn Tán ma nhằm dần khống chế nó.","detail":"Vương Lâm dùng chính mình kết hợp lực Cổ Yêu ngăn chặn, đẩy một Tán ma khổng lồ vào thế hôn mê, rồi liên tục biến hóa cấm chế ấn lên hồn Tán ma và để lại lạc ấn nguyên thần. Tán ma quá lớn nên dù làm mấy tháng vẫn chưa nuốt được; mục tiêu là không ngừng tăng lạc ấn nguyên thần để sớm muộn khống chế hoàn toàn, sau đó hoặc nuốt để tăng tu vi, hoặc dùng làm phôi thể luyện Nguyên thần thứ hai.","nguon":["@c0567"]},{"id":"khuyen-kiem-hon-heo-ac-hoi-tru","name":"Khuyển kiếm hóa hồn heo ác","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm thuật","phamCap":"","hePhai":"Đại La Kiếm Tông","soHuu":["Hợi Trư"],"blurb":"Pháp quyết của Hợi Trư khiến Khuyển kiếm bay ra biến ảo thành hồn một con heo ác đen kịt.","detail":"Khi đối địch Vương Lâm, Hợi Trư bắt pháp quyết thả thanh Khuyển kiếm bay ra, biến ảo thành hồn một con heo ác đen kịt. Chiêu chưa kịp phát huy thì Hợi Trư đã bị Hoàng Tuyền trấn áp và Vương Lâm giết chết.","nguon":["@c0571"]},{"id":"thuat-luyen-hon-bo-lac","name":"Thuật Luyện Hồn (bộ lạc Luyện Hồn)","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Bộ lạc Luyện Hồn","soHuu":["Vương Lâm"],"blurb":"Công pháp tu luyện của bộ lạc Luyện Hồn tại đất Yêu Linh.","detail":"Công pháp tu luyện của bộ lạc Luyện Hồn. Tu dưới lòng đất bằng cách đào hố nơi chiến trường viễn cổ ẩn nhiều hồn phách, hoặc đi quận Hỏa Yêu hấp thu hồn của yêu binh đã chết để tu hành hiệu quả hơn. Bộ lạc phát triển cực nhanh như con bướm trong kén, hứa hẹn ngày phá kén rung động chín quận.","nguon":["@c0573"]},{"id":"nguyen-than-xuat-khieu-vuong-lam","name":"Nguyên thần Xuất khiếu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông thả Nguyên thần ra khỏi Thiên linh cái để thao tác bên ngoài, nền tảng cho việc luyện hóa Xạ Thần Xa.","detail":"Vương Lâm thả Nguyên thần ra khỏi Thiên linh cái, Nguyên thần bay ra bắt cổ hồn thú lôi theo ra ngoài và dùng tay trái bắt huyết phù in lên trán hồn thú. Đây là nền tảng thao tác cho quá trình luyện hóa Xạ Thần Xa thứ hai.","nguon":["@c0574"]},{"id":"than-thong-loi-dien-loi-thu","name":"Thần thông lôi điện (Lôi Thú)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"aliases":["Phong vũ lôi điện"],"blurb":"Thần thông lôi điện của Lôi Thú trong Xạ Thần Xa — lôi điện từ trời đánh xuống bao quanh thân chứ không phải thiên kiếp.","detail":"Khi hồn thú hóa thành Lôi Thú, lôi điện từ trời đánh xuống bao quanh thân thành hình cầu — không phải thiên kiếp mà là thần thông của con thú. Được nhắc trùng với chiêu phong vũ lôi điện mà lão già dưới ma tháp từng xem là chiêu yếu nhất của lão, ám chỉ thực lực thật của lão còn khủng khiếp hơn nhiều.","nguon":["@c0574"]},{"id":"hon-tuyen-vuong-lam","name":"Hồn Tuyền","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật khiến chướng khí mê vụ quay cuồng, bị hút ngưng tụ về trước người thành đoàn khí mật độ cực cao.","detail":"Vương Lâm bấm quyết, dung thanh âm vào ấn quyết, hô “Hồn Tuyền” khiến chướng khí mê vụ quay cuồng, sôi trào, bị hút ngưng tụ về trước người như lốc xoáy. Dùng để phá Hồn Phách thuật của Lão Tổ Liên minh, hút sạch toàn bộ chướng khí vô tận thành một đoàn khí to chừng nắm tay mật độ cực cao, làm căn cứ lần đầu trong vô số năm lộ ra dưới ánh mặt trời.","nguon":["@c0576"]},{"id":"hon-phach-thuat-lao-to-lien-minh","name":"Hồn Phách thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Tu sĩ Liên minh","soHuu":["Lão Tổ Liên minh"],"blurb":"Pháp thuật hồn Lão Tổ thi triển trong chướng khí, khiến chướng khí có linh tính vờn quanh và gào rít như quỷ vật.","detail":"Lão Tổ Liên minh thi triển trong vùng chướng khí: chướng khí có linh tính vờn quanh đối thủ ngày càng nhiều, phát thanh âm như quỷ vật gào rít. Vương Lâm nhận ra đây là Hồn Phách thuật và phá nó bằng Hồn Tuyền.","nguon":["@c0576"]},{"id":"than-thong-hoa-manh-thu-tien-ve","name":"Thần thông hoá mãnh thú (Tiên vệ)","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh kỳ","hePhai":"Tiên vệ (Lão Tổ Liên minh)","soHuu":["Tiên vệ áo đen"],"blurb":"Thần thông của Tiên vệ áo đen, hoá thành con mãnh thú há miệng như chậu máu định nuốt đối thủ.","detail":"Khi Lão Tổ ra lệnh giết Vương Lâm, một Tiên vệ áo đen lao ra thi triển thần thông này, hoá thành mãnh thú khổng lồ há miệng như chậu máu nuốt chửng đối thủ. Trước một chỉ Tịch Diệt của Vương Lâm, mãnh thú hư ảo bị phá toái, ngư��i áo đen vong tức khắc.","nguon":["@c0577"]},{"id":"tran-phap-tam-tien-ve","name":"Trận pháp tám Tiên vệ","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Vấn Đỉnh kỳ","hePhai":"Lão Tổ Liên minh","soHuu":["Lão Tổ Liên minh"],"blurb":"Tám Tiên vệ khoanh chân kết ấn quyết theo một quy tắc để triệu tập Tiên đế.","detail":"Sau khi Vương Lâm cự tuyệt giảng hoà, Lão Tổ triệu tám Tiên vệ. Tám thân ảnh có nam có nữ, khí tức Vấn Đỉnh kỳ nồng đậm, bay ra khoanh chân ngồi thành thế, hai tay không ngừng biến hoá ấn quyết theo một quy tắc nào đó nhằm triệu tập Tiên đế.","nguon":["@c0577"]},{"id":"ao-thuat-cong-kich-tien-de","name":"Ảo thuật công kích “Tiên Đế”","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiên thuật","hePhai":"Lão già Toà thành trắng","soHuu":["Lão già thấp bé (Toà thành trắng)"],"blurb":"Ảo thuật khiến tám Tiên vệ tán phát tiên lực dung hợp thành hư ảnh “Tiên Đế”.","detail":"Tám Tiên vệ tán phát tiên lực dung hợp giữa không trung, hoá thành hư ảnh người đàn ông trung niên mặc tiên bào tay cầm trường kiếm xanh, uy thế tựa tiên uy khiến tu sĩ quỳ tham kiến. Hư ảnh phát ra tiếng vô thanh hoá thành tiếng sấm trong tai địch, ép nguyên thần sụp đổ tương tự thiên kiếp. Vương Lâm đạo tâm kiên định hạ chân đạp vỡ ảo thuật.","nguon":["@c0578"]},{"id":"na-di-thuat","name":"Na Di thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dịch chuyển không gian; thần thức quét ra định vị mục tiêu rồi từ hư không bước ra chặn đầu.","detail":"Vương Lâm thi triển Na Di thuật khi truy đuổi lão già thấp bé: thần thức quét ra phát hiện lão ở ngoài ba vạn dặm, rồi từ hư không bước ra chặn ngay trước mặt lão, cắt đứt đường tẩu thoát bằng độn thuật.","nguon":["@c0579"]},{"id":"dinh-than-thuat","name":"Định Thân thuật","cn":"","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Tiên thuật","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tiên thuật Vương Lâm cảm ngộ hơn mấy chục năm; chỉ một chữ ‘Định’ khiến thiên địa bất động, định trụ đối thủ không nhúc nhích.","detail":"Tiên thuật mà Vương Lâm cảm ngộ trải hơn mấy chục năm, đến chương này mới chạm tới bề ngoài. Một tiếng ‘Định’ nhỏ phát trong toà tháp đã khoá cứng Lôi Suất khiến thời gian như ngừng, mây đen bất động, hơi thở hắn tiêu tán, chỉ đôi mắt còn cử động. Khi toàn lực thi triển ‘một chữ Định, thiên địa bất động’, toàn bộ yêu binh hai Quận bên ngoài bộ lạc lập tức không nhúc nhích, mở màn cho cuộc tàn sát. Một số đối thủ có thủ đoạn đặc biệt có thể thoát định sau vài tức.","nguon":["@c0583","@c0605"],"aliases":["Định"]},{"id":"sat-luc-khi-tu-phan","name":"Sát Lục khí (tụ · phân)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Sát Lục đạo","soHuu":["Vương Lâm"],"blurb":"Thần thông triệu tụ rồi phân hoá Sát Lục khí: Vương Lâm gọi sát khí tích tụ trăm năm về một mối rồi tách đôi liên tiếp thành trăm vạn đạo.","detail":"Vương Lâm thốt “Sát lục khí, tụ!” triệu sát khí mà tộc nhân Luyện Hồn bộ lạc ẩn nấp khắp Hoả Yêu Quận tích tụ suốt trăm năm — trong yêu binh, người áo đen và tướng lĩnh song phương — khiến mười vạn đạo Sát Lục khí ngưng gần thành thực chất tụ về hắn. Căn nguyên của nó là sát tâm và sát ý dung hợp lại, biểu hiện qua hồng quang trong mắt. Khi thốt “Phân!”, mười vạn đạo lập tức tách đôi thành hai mươi vạn, rồi lại phân tiếp; sau hơn mười lần phân chia chớp mắt, đã biến thành trăm vạn đạo phủ kín thiên địa.","nguon":["@c0584"]},{"id":"tam-tai-kiem-tran","name":"Tam Tài kiếm trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Kiếm trận Vương Lâm vận hành cùng ba hồn thú Tử Thử, Hợi Trư, Mạt Dương.","detail":"Trận pháp gồm ba đạo kiếm quang phối hợp cùng ba hồn thú Tử Thử, Hợi Trư, Mạt Dương; ba kiếm quang xuyên qua thân nữ tử hạ sát nàng, sau đó kiếm trận bay về tay Vương Lâm.","nguon":["@c0584"]},{"id":"than-thong-cam-tri-mo-dung-trac","name":"Thần thông cảm tri của Mộ Dung Trác","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Mặc môn","soHuu":["Mộ Dung Trác"],"blurb":"Khả năng phát hiện đối phương mạnh ở ngoài ngàn dặm.","detail":"Thần thông cho phép Mộ Dung Trác cảm tri và phát hiện sự xuất hiện của đối phương mạnh từ ngoài ngàn dặm. Chính vì thần thông này mà Vương Lâm đặc biệt lưu tâm và nhận lời kết bạn cùng nhóm.","nguon":["@c0589"]},{"id":"tam-thuat-nhin-thau-noi-tam-trieu-y-huyen","name":"Tâm thuật nhìn thấu nội tâm của Triệu Y Huyên","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Phù Vân phái","soHuu":["Triệu Y Huyên"],"blurb":"Khả năng nhìn thấu nội tâm người khác, bị định lực hoặc che chắn đặc biệt cản trở.","detail":"Tâm thuật giúp Triệu Y Huyên nhìn thấu tâm tư hầu hết mọi người ở đất Yêu Linh. Tuy nhiên bị cản trở bởi định lực đóng kín cửa tâm linh của Vương Lâm, sương mù hóa lợi kiếm của Thần Long, và tâm tư biến hóa khôn lường của Mộ Dung Trác.","nguon":["@c0589"]},{"id":"dinh-luc-dong-kin-cua-tam-linh-vuong-lam","name":"Định lực đóng kín cửa tâm linh của Vương Lâm","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Không cần sương mù hay biến ảo, chỉ bằng định lực khóa trụ toàn bộ tâm thần khiến người khác không dò thấu.","detail":"Khác với Thần Long dùng sương mù che chắn hay Mộ Dung Trác dùng tâm tư biến ảo, Vương Lâm chỉ bằng định lực thuần túy đóng kín cửa tâm linh, khóa trụ toàn bộ tâm thần. Nhờ vậy Triệu Y Huyên không thể nhìn thấu nội tâm của hắn.","nguon":["@c0589"]},{"id":"ky-hieu-bay-net-tien-but","name":"Ký hiệu bảy nét tiên bút","loai":"than-thong","loaiLabel":"Thần thông tiên gia","phamCap":"Thần thông tiên nhân","hePhai":"Phù chú tiên gia","soHuu":["Vương Lâm"],"blurb":"Thần thông tiên nhân vẽ bằng tiên bút: bảy nét liên tiếp, mỗi nét dung nhập một tia nguyên thần, hợp thành hình tròn ẩn chứa càn khôn.","detail":"Vương Lâm dùng tiên bút vẽ liên tiếp tạo ký hiệu, mỗi nét rút một tia nguyên thần của hắn. Bảy nét là cực hạn hiện tại — sau khi tế luyện ở bộ lạc Luyện Hồn hắn vẫn không vẽ nổi nét thứ tám vì nguyên thần không chia được thành chín phần (muốn thế phải bỏ thân thể cho nguyên thần dung nhập hết). Ký hiệu hoàn thành hợp lại thành hình tròn ẩn chứa càn khôn, làm sáng rực cả Triều Tịch vực, đủ sức đối kháng thần niệm Lăng Thiên Hậu trong chốc lát. Khi va chạm với kiếm khí của Lăng Thiên Hậu, ký hiệu tan nát khiến sáu trong bảy đạo nguyên thần bị hủy, song tàn dư của nó hóa kim quang vây kiếm khí thành kén ánh sáng vàng giữ chân tạm thời.","nguon":["@c0594"]},{"id":"luyen-tien-hoa-ma-dai-tran","name":"Luyện Tiên Hóa Ma đại trận","loai":"bi-thuat","loaiLabel":"Trận pháp phong ấn","phamCap":"Đại trận tiên cấp","hePhai":"Lăng Thiên Hậu tự sáng tạo","soHuu":["Lăng Thiên Hậu"],"blurb":"Đại trận do Lăng Thiên Hậu tự nghĩ ra để phong ấn và luyện hóa Chu Dật, mượn yêu khí Cổ Yêu ăn mòn linh thể.","detail":"Cốt lõi trận là bốn thanh bảo kiếm cắm trên mặt đất — vốn là bốn tiểu Thiên Địa được Lăng Thiên Hậu luyện thành bốn thanh kiếm Nguyên Thần — cộng bốn đạo thần niệm hóa quả cầu bay quanh. Trận dẫn yêu khí của tàn hồn Cổ Yêu Thủy Yêu quận theo mạch ngầm thông tới miếu Cổ Yêu ở đế đô, để yêu khí gặm nuốt linh thể Chu Dật, ép tâm hắn buông xuôi và để Cổ Yêu đoạt thân thể chịu được yêu lực.","nguon":["@c0594"]},{"id":"ban-menh-kiem-khi-kiem-linh","name":"Bản mệnh kiếm khí của kiếm linh","loai":"kiem-quyet","loaiLabel":"Kiếm khí tiên gia","phamCap":"Tiên cấp","hePhai":"Vũ chi tiên kiếm","soHuu":["Chu Dật"],"blurb":"Kiếm khí bản mệnh của kiếm linh trong Vũ chi tiên kiếm, uy lực cực mạnh khiến cả Lăng Thiên Hậu cũng vất vả.","detail":"Chu Dật — kiếm linh của Vũ chi tiên kiếm — vốn có 99 đạo bản mệnh kiếm khí. Năm xưa truy đuổi Lăng Thiên Hậu từ tiên giới hắn đã dùng hơn nửa, nay chỉ còn bốn đạo. Một đạo phóng ra đủ đâm vỡ quả cầu thần niệm thứ tư và đánh tan một phần thần niệm Lăng Thiên Hậu, hóa điểm sáng dung nhập hồi phục — thậm chí tăng trưởng — nguyên thần Vương Lâm. Chu Dật cho biết kiếm khí này không thể để lại trong người Vương Lâm cũng không cấp được, chỉ giúp hắn bình phục.","nguon":["@c0594"]},{"id":"tien-an","name":"Tiên ấn","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Thượng phẩm tiên thuật","hePhai":"Tiên giới","soHuu":["Chu Dật"],"blurb":"Thượng phẩm tiên thuật chỉ Tiên đế mới thi triển; Chu Dật từng dùng một ngón tay làm Lăng Thiên Hậu bị thương.","detail":"Tiên ấn là thượng phẩm tiên thuật mà tương truyền chỉ Tiên đế mới thi triển được. Chu Dật, sau khi thi thể nữ tử áo trắng dùng tiên lực nâng hắn lên thành kiếm linh, từng dùng Tiên ấn chỉ với một ngón tay khiến Lăng Thiên Hậu bị thương trong cuộc truy đuổi từ tiên giới.","nguon":["@c0594"]},{"id":"kiem-y-vien-co-bon-kiem-ky","name":"Kiếm ý viễn cổ (Bốn loại kiếm ký)","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Truyền thừa viễn cổ","hePhai":"Truyền thừa kiếm linh Vũ chi tiên kiếm","soHuu":["Chu Dật","Hứa Lập Quốc"],"blurb":"Truyền thừa kiếm ký từ thời viễn cổ của kiếm linh Vũ tiên kiếm, gồm bốn loại kiếm ký.","detail":"Truyền thừa thời viễn cổ mà kiếm linh Vũ chi tiên kiếm nắm giữ, gồm bốn loại kiếm ký. Chu Dật truyền vào Hứa Lập Quốc qua ánh mắt, thúc dục sinh trưởng cho tới khi điều khiển hoàn toàn được thanh kiếm tiên, biến Hứa Lập Quốc thành kiếm linh chính thức. Việc tự thân truyền thừa khiến linh thể Chu Dật bị thương tổn.","nguon":["@c0595"]},{"id":"lac-an-truyen-thua-chu-dat","name":"Lạc ấn (cài trong truyền thừa)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Cấm chế truyền thừa","hePhai":"Thủ đoạn kiếm linh Chu Dật","soHuu":["Chu Dật"],"blurb":"Dấu ấn Chu Dật cài vào truyền thừa kiếm ý của Hứa Lập Quốc để phòng phản bội.","detail":"Khi truyền kiếm ý viễn cổ cho Hứa Lập Quốc, Chu Dật cố ý để lại một chút lạc ấn trong truyền thừa. Nếu sau này Hứa Lập Quốc phản bội Vương Lâm thì truyền thừa sẽ cắn trả hắn — một cơ chế ràng buộc trung thành phòng kẻ dễ thay đổi.","nguon":["@c0595"]},{"id":"tran-phap-phong-an-lang-thien-hau","name":"Trận pháp phong ấn của Lăng Thiên Hậu","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Trận pháp phong ấn","hePhai":"Lăng Thiên Hậu","soHuu":["Lăng Thiên Hậu"],"blurb":"Trận pháp Lăng Thiên Hậu dùng phong ấn Chu Dật trong cái khe suốt mấy trăm năm.","detail":"Cái khe phong ấn Chu Dật gồm trận pháp dưới nền cùng bốn thành kiếm Nguyên Thần và ba quả cầu thần niệm. Nó giam giữ Chu Dật mấy trăm năm, cho tới khi bản mệnh kiếm khí của hắn đập vỡ ba quả cầu thần niệm, làm tan bốn thành kiếm Nguyên Thần và phá tan trận pháp, khiến cái khe sụp xuống.","nguon":["@c0595"]},{"id":"truyen-thua-kiem-y-vien-co","name":"Truyền thừa kiếm ý viễn cổ","loai":"bi-thuat","loaiLabel":"Truyền thừa / Kiếm ý","phamCap":"Viễn cổ","hePhai":"Vũ tiên kiếm / kiếm linh","soHuu":["Chu Dật","Hứa Lập Quốc"],"blurb":"Truyền thừa kiếm ý từ thời viễn cổ; người thừa kế kết hợp thân phận kiếm linh có thể phá lạc ấn trên tiên kiếm.","detail":"Truyền thừa kiếm ý từ thời viễn cổ. Người lĩnh hội kết hợp thân phận kiếm linh có thể phá bỏ lạc ấn trên tiên kiếm và mở con đường trở thành kiếm linh chí tôn. Chu Dật trao cho Hứa Lập Quốc lĩnh hội, đưa Hứa Lập Quốc thành kiếm linh đời thứ nhất của thanh Vũ tiên kiếm trao cho Vương Lâm.","nguon":["@c0596"]},{"id":"ban-menh-kiem-khi-chu-dat","name":"Bản Mệnh Kiếm Khí (của Chu Dật)","loai":"than-thong","loaiLabel":"Kiếm khí / Thần thông","phamCap":"Kiếm tiên","hePhai":"Vũ tiên kiếm","soHuu":["Chu Dật"],"blurb":"Kiếm khí của Kiếm tiên Chu Dật tán phát phá tan trở ngại, làm sương mù tím tan biến khi tiếp xúc.","detail":"Kiếm khí của Kiếm tiên Chu Dật, tán phát ra có thể phá tan trở ngại; khi tiếp xúc làm sương mù tím quái dị nơi đáy Triều Tịch vực tan biến, mở đường tăng tốc. Gắn liền với hơi thở một đời kiếm linh của Vũ tiên kiếm.","nguon":["@c0596"]},{"id":"kiem-linh-co-che","name":"Kiếm linh (cơ chế)","loai":"khac","loaiLabel":"Thân phận / Cơ chế kiếm","phamCap":"—","hePhai":"Vũ tiên kiếm","soHuu":[],"blurb":"Linh hồn điều khiển tiên kiếm; đời đời kiếp kiếp gắn với một thanh kiếm, có thể luân hồi không diệt.","detail":"Kiếm linh là linh hồn điều khiển tiên kiếm, đời đời kiếp kiếp gắn với một thanh kiếm và có thể trải vô số luân hồi không bị diệt. Ở tiên giới phải đạt cảnh giới Tiên quân mới có cơ hội thành kiếm linh chí tôn.","nguon":["@c0596"]},{"id":"kiem-thuc-chu-dat-muon-nhin","name":"Kiếm thức (của Chu Dật)","loai":"than-thong","loaiLabel":"Thần thông kiếm","phamCap":"Bất minh","hePhai":"Kiếm đạo (Chu Dật)","soHuu":["Chu Dật","Vương Lâm"],"blurb":"Kiếm thức bám lấy mục tiêu, cho người dùng ‘nhìn’ được vị trí đối thủ ngay cả khi thần thức bị che lấp.","detail":"Trong làn Tử khí cô lập cả hình ảnh lẫn thần thức, Chu Dật cho Vương Lâm mượn kiếm thức để khóa lấy bốn đệ tử Đại La, nhờ đó ‘nhìn’ được vị trí của họ giữa sương mù và lần lượt ra tay. Chu Dật ra hạn mười lần hô hấp, hết hạn sẽ cưỡng chế đưa Vương Lâm rời đi.","nguon":["@c0601"]},{"id":"that-ma-cham","name":"Thất Ma Châm","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thần thông khống chế của Tham Lang thi triển qua bảy ngân châm.","detail":"Tham Lang bắt quyết quát ‘ấn’, ép bảy ngân châm cắm trên đầu Văn thú lớn cắm sâu thêm ba tấc để khống chế nó. Khi cần phòng thân, hắn thu bảy châm về tạo thành một màn bảo vệ màu bạc che thân lúc lao vào hợp chiến.","nguon":["@c0602"]},{"id":"phe-tu-nhat-thuc","name":"Phệ Tử Nhất Thức","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thức thứ nhất của Phệ Tử thuật, hút lục khí thôn phệ pháp thuật đối thủ.","detail":"Tham Lang đánh tay vào vách đá vực sâu r��i rút ra vô số lục khí tràn như thác nước xanh biếc, vung về phía địch. Lục khí mang đặc tính thôn phệ: nuốt Tịch Diệt Chỉ của Vương Lâm khiến chỉ phong đen chuyển xanh biếc sắp tan nát, và đánh tan Long hồn của Thần Long khiến bảo kiếm lắc lư bay về.","nguon":["@c0602"]},{"id":"phe-tu-nhi-thuc-rut-son-hon","name":"Phệ Tử nhị thức (Rút sơn hồn)","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thức thứ hai của Phệ Tử thuật, rút sơn hồn ra khỏi ngọn núi tiên giới.","detail":"Tham Lang chụp tay lên ngọn núi tiên giới khắc đầy phù văn, quát ‘Rút, sơn hồn’, kéo khí tức tang thương tích tụ như tu sĩ tu luyện vô số năm ra khỏi núi. Núi mất sơn hồn liền nứt vỡ thành đá vụn rơi xuống, còn sơn hồn hư ảo lơ lửng trong tay có thể giáng xuống đè trọng thương đối thủ và ẩn chứa tiên lực mênh mông phá tan cả sát lục khí.","nguon":["@c0602"]},{"id":"toai-kiem-hoa-than","name":"Toái Kiếm Hóa Thần","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"","soHuu":["Lăng Thiên Hậu","Thần Long"],"blurb":"Thần thông kiếm vốn của Lăng Thiên Hậu, Thần Long đang thi triển.","detail":"Hóa đại kiếm thành hắc long mang kiếm khí lao tới; khi Long hồn bị phá, người dùng phun nguyên thần tinh huyết lên bảo kiếm niệm chú khiến kiếm nứt vỡ lột một lớp da, mảnh vụn mang huyết khí tái hóa thành hắc long lần hai mạnh hơn. Tham Lang nhận đúng đây là Toái Kiếm Hóa Thần của Lăng Thiên Hậu nhưng chê thần thông chưa hoàn chỉnh nên trong mắt hắn vẫn yếu.","nguon":["@c0602"]},{"id":"dinh-toa-thien-dinh-dia","name":"Định","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Tiên thuật hạ phẩm","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tiên thuật hạ phẩm ‘tỏa thiên định địa’, phóng sợi tơ vô hình khống chế đối thủ trong tích tắc.","detail":"Khi thi triển, Vương Lâm thầm hô ‘Định’, phóng ra sợi tơ lực lượng vô hình quấn quanh đối thủ, ngưng giữ nguyên thần và phong tỏa tiên lực khiến đối thủ sững lại không nhúc nhích được trong khoảnh khắc. Trong cuộc tranh đoạt lệnh bài, hắn dùng thuật này khống chế cả Thần Long (làm rơi lệnh bài) lẫn Tham Lang (chặn đúng lúc để tự chụp lấy lệnh bài).","nguon":["@c0603"]},{"id":"phe-tu-tam-thuc","name":"Phệ Tử Tam Thức","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Tham Lang"],"blurb":"Thần thông của Tham Lang: tiếng thét hóa sóng gợn vượt vòng vây, ngưng hóa thành đệ nhị nguyên thần.","detail":"Khi bị vây khốn, Tham Lang gầm thét phát ra các đợt sóng gợn liên tiếp vượt khỏi vòng vây Văn thú lao tới đối thủ, rồi ngưng hóa thành một người nhỏ bé toàn thân trong suốt — đệ nhị nguyên thần mang khí tức nồng đậm của bản thể, có thể bắt quyết phóng thần lôi đen oanh kích kẻ địch.","nguon":["@c0603"]},{"id":"than-thong-tai-sinh-van-thu","name":"Thần thông tái sinh của Văn thú","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đàn Văn thú tan nát thành huyết nhục bọc hồng quang lao tới rồi khôi phục, giết chẳng chết.","detail":"Khi Văn thú của Vương Lâm phát tiếng kêu, toàn bộ đàn Văn thú phát hồng quang, thân thể tan nát hóa thành huyết nhục bọc hồng quang lao tới đối thủ rồi khôi phục một cách quỷ dị. Thân chúng cứng như thép; giết một con thì nó hóa thành mây đỏ lui ra rồi ngưng hóa trở lại, khiến đối thủ khó lòng thoát khỏi vòng vây.","nguon":["@c0603"]},{"id":"diet-tien-loi","name":"Diệt Tiên Lôi","loai":"than-thong","loaiLabel":"Thần thông lôi hệ","phamCap":"","hePhai":"","soHuu":["Tham Lang"],"blurb":"Lôi pháp của đệ nhị nguyên thần Tham Lang: ngưng lôi chùy chuyển màu máu rồi đánh vào vách đá vực sâu tạo điện võng đỏ vây khốn đối thủ.","detail":"Đệ nhị nguyên thần lôi hệ của Tham Lang ngưng tụ cây lôi chùy (búa điện quang) chuyển thành màu máu, đánh ra Diệt Tiên Lôi vào hai vách đá vực sâu. Vách đá hiện điện võng đỏ rực vây quanh Vương Lâm. Vương Lâm phải bóp nát huyết ngọc Diêu Tích Huyết tạo huyết quang phòng hộ và dùng Tam Tài kiếm trận phản công mới thoát.","nguon":["@c0604"]},{"id":"tien-thuat-dinh-than-vuong-lam","name":"Tiên thuật Định (định thân)","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tiên thuật khiến đối thủ đang vung tay sững lại trong khoảnh khắc, đủ để Vương Lâm dứt điểm.","detail":"Khi điện võng co rút, Vương Lâm thi triển tiên thuật Định khiến đệ nhị nguyên thần Tham Lang đang vung tay sững lại trong khoảnh khắc. Hắn nhân cơ hội hô Sát, Tam Tài kiếm trận xuyên thủng cơ thể đệ nhị nguyên thần.","nguon":["@c0604"]},{"id":"cuu-tinh-lien-chau-tham-lang","name":"Cửu tinh liên châu (chiêu lôi)","loai":"than-thong","loaiLabel":"Chiêu lôi","phamCap":"","hePhai":"","soHuu":["Tham Lang"],"blurb":"Đệ nhị nguyên thần Tham Lang sắp chín lôi cầu màu đen thành hàng như mũi tên phá lực cản lao tới đối thủ.","detail":"Đệ nhị nguyên thần của Tham Lang ngưng chín lôi cầu màu đen xếp thẳng hàng như mũi tên, gọi là cửu tinh liên châu, phá lực cản bên dưới vực lao thẳng tới Vương Lâm. Vương Lâm thả Lôi Thú từ Xạ Thần Xa nuốt hai lôi cầu để hóa giải.","nguon":["@c0604"]},{"id":"luyen-che-tien-ve","name":"Luyện chế Tiên Vệ","loai":"bi-thuat","loaiLabel":"Bí thuật tế luyện","phamCap":"Cực phẩm (nghịch thiên)","hePhai":"Tiên Đế Thanh Lâm (mô phỏng Cổ Thần)","soHuu":["Vương Lâm","Tiên Đế Thanh Lâm"],"blurb":"Bí thuật biến người sống thành khôi lỗi nhân thể pháp bảo Tiên Vệ, do Tiên Đế Thanh Lâm bắt chước Cổ Thần sáng tạo.","detail":"Thuật tế luyện nghịch thiên gồm bốn bước: một là luyện thân thể đến cực mạnh để pháp bảo tầm thường không tổn hại được; hai là hóa nguyên thần, luyện chảy mài nhỏ rồi thúc giãn nở dung nhập vào cơ thể, khiến cơ thể vô thần mà thần ở trong ý; ba là luyện hóa lục phủ ngũ tạng cho nội tạng héo rũ, không hấp thụ tiên khí hồi phục, cắt đứt năm cảm giác để không thấy đau đớn; bốn là diệt sạch thần thức nhưng bảo lưu linh trí. Tiên Vệ thành phẩm không cảm xúc nhưng có linh động, thân thể mạnh mẽ, dù đầu rơi hay thân bị xé cũng không nhăn mặt, chia bốn trình độ Kim · Ngân · Đồng · Thiết. Điều kiện trọng yếu: người được luyện chế không được dâng lên một tia chống cự, nếu không lập tức thất bại. Bí thuật ghi trong ngọc giản, chứa thần thông mà chỉ Tiên Vệ mới thi triển được.","nguon":["@c0608"],"aliases":["#luyen-che-tien-ve-bi-thuat"]},{"id":"than-thong-rieng-tien-ve","name":"Thần thông riêng của Tiên Vệ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tiên gia","hePhai":"Tiên Đế Thanh Lâm","soHuu":["Vương Lâm"],"blurb":"Vài loại thần thông trong ngọc giản chỉ dành cho khôi lỗi Tiên Vệ, gồm thuật ‘Ẩn’ hóa hư vô.","detail":"Bộ thần thông riêng được ghi trong ngọc giản, chỉ truyền cho khôi lỗi Tiên Vệ thông qua việc gắn ngọc giản vào giữa lông mày nó. Trong đó có thuật ‘Ẩn’ cho phép Tiên Vệ hóa thành hư vô, nấp vào thân ảnh của chủ nhân. Vương Lâm xác định phải để Tiên Vệ nắm chắc khoảng sáu phần các thần thông này mới yên tâm rời tuyệt địa.","nguon":["@c0609"]},{"id":"hoang-tuyen-chi-luc","name":"Hoàng Tuyền Chi Lực","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Thức (thần thông đạo niệm)","hePhai":"Thần thông đạo niệm của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đệ Tam Thức trong thần thông đạo niệm của Vương Lâm, lĩnh ngộ nhờ tự thân hóa thành lực hút của vực sâu tựa hoàng tuyền.","detail":"Hoàng Tuyền Chi Lực là Đệ Tam Thức Vương Lâm lĩnh ngộ được sau mười bảy năm bị cầm chân trong tuyệt địa hố sâu lực hút. Muốn dung hợp lực hút không thể chống cự mà phải thả lỏng tâm thần để nó xuyên thấu qua thân thể; bước cuối cùng là chính mình trở thành một bộ phận của lực hút. Khi đạt cảnh giới này, lực hút xuyên thẳng qua cả thân thể lẫn nguyên thần, thân hình đang rơi giữa hố sâu vô tận có thể đột ngột dừng lại vì đã hòa làm một với chính lực hút của vực hoàng tuyền.","nguon":["@c0611"]},{"id":"that-tinh-kiem-tran","name":"Thất Tinh Kiếm Trận","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"","hePhai":"Kiếm trận của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Kiếm trận do Kiếm Tôn Lăng Thiên Hậu sáng chế, hóa bảy đạo cầu vồng truy sát, mang tà hồn Thất Sanh Tiếu trên thất kiếm. (+) Trận thế bảy thanh bảo kiếm vờn quanh Vương Lâm, xoay tròn cực nhanh tạo lốc xoáy sinh lực đẩy. [CAN-SOAT-GOP]","detail":"Thất Tinh Kiếm Trận do bảy thanh bảo kiếm hợp thành, vờn quanh thân Vương Lâm rồi xoay tròn cực nhanh tạo thành lốc xoáy sinh ra lực đẩy. Trong tuyệt địa hố sâu, hắn dùng trận này chống lại lực hút khủng khiếp kéo xuống, song một mình kiếm trận không đủ. Về sau khi hắn ngồi bất động cảm thụ lực hút, kiếm trận ngừng xoay và cắm thẳng xuống đất.","nguon":["@c0611","@c0630"],"aliases":["#that-tinh-kiem-tran-630"]},{"id":"thien-loi-chan-chinh","name":"Thiên Lôi (chân chính)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông bản năng nguyên thần","hePhai":"Lôi hệ","soHuu":["Vương Lâm"],"blurb":"Thiên Lôi chân chính do nguyên thần Vương Lâm dung hợp với Thái Cổ Lôi Long sinh ra, mang lôi uy chân chính chứ không phải phép biến ảo tầm thường.","detail":"Không phải phép thuật biến ảo tầm thường mà là Thiên Lôi chân chính, sinh ra từ việc nguyên thần Vương Lâm dung hợp với Thái Cổ Lôi Long, thành nguyên thần bản năng. Khi thi triển, trong nguyên thần hiện một tia chớp dũng mãnh theo tay bắn ra; liên tiếp chỉ ra sấm sét, theo sau là tiếng nổ vang trời, sấm chớp như rồng hoá thành uy áp. Tại La Vân Tinh Vực, hắn dùng nó tiêu tan toàn bộ sương độc của Minh vụ trùng — loài vốn sợ nhất Lôi hệ — khiến chúng cảm nhận lôi uy chân chính nên lùi ra rất nhanh.","nguon":["@c0615"]},{"id":"anh-mat-thuc-chat-vuong-lam","name":"Ánh mắt thực chất","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thức cực cảnh","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ánh mắt của Vương Lâm như có thực chất, nơi nào chiếu vào liền thành chỗ trống không, đủ khiến Minh vụ trùng run rẩy rút lui.","detail":"Khi Vương Lâm chú ý đám sương xám, ánh mắt hắn tựa như thực chất; nơi nào ánh mắt chiếu vào liền thành chỗ trống không. Chỉ một cái nhìn đã khiến vô số Minh vụ trùng trong sương độc run rẩy mà rút lui, khiến bốn người Nhiễm Vân Tinh ngẩn ra kinh hãi. Khi hắn thu hồi ánh mắt, sương lại dũng mãnh vây kín như cũ.","nguon":["@c0615"],"aliases":["#anh-mat-thuc-chat-vuong-lam-615","#anh-mat-thuc-chat-vuong-lam-c0615"]},{"id":"tram-la-quyet","name":"Trảm La Quyết","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Kinh thiên","hePhai":"Truyền thừa Cự Phú","soHuu":["Vương Lâm"],"blurb":"Thức kiếm quyết duy nhất ẩn trong Cự Phú, một thức kinh thiên Vương Lâm cảm ngộ được sau hai năm tĩnh tâm.","detail":"Bên trong Cự Phú chỉ có duy nhất một thức kiếm quyết — Trảm La Quyết. Sau hai năm cảm thụ ý chí ẩn trong di vật, Vương Lâm lĩnh ngộ được thức này; khi hắn thu tâm thần ra, Cự Phú hoàn toàn tiêu tan như đã hoàn thành truyền thừa cả đời nó, để lại Trảm La Quyết là thứ duy nhất còn lại. Động tác thi triển đơn giản không hoa mỹ: hai ngón tay tạo kiếm chém về phía trước, đủ khiến cuộn tranh nữ tử thần bí cuộn lại im tiếng.","nguon":["@c0610"],"aliases":["#tram-la-quyet-cu-phu"]},{"id":"that-tinh-kiem-tran-chong-luc-hut","name":"Thất Tinh Kiếm Trận (chống lực hút)","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm trận","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bảy thanh kiếm hóa bảy đạo cầu vồng cắm sâu xuống đất, điện quang đan xen thành màn bảo vệ cố định thân hình giữa lực hút khủng khiếp.","detail":"Khi đối mặt dòng xoáy cực lớn phát ra lực hút mạnh ở đáy hố vùng yêu linh, Vương Lâm triển khai Thất Tinh Kiếm Trận: bảy kiếm hóa bảy đạo cầu vồng cắm sâu xuống đất quanh hắn, điện quang đan xen thành màn bảo vệ giữ chặt vị trí. Kiếm Hồn rít gào dung hợp biến hình chống cự, kiếm như hòa làm một thể với mặt đất. Dù vậy nguyên thần hắn vẫn bị hút, chỉ có lớp màng giam giữ khiến nó không thoát ra ngoài.","nguon":["@c0612"]},{"id":"van-ao-thien-ma-dao","name":"Vạn Ảo Thiên Ma Đạo","loai":"cong-phap","loaiLabel":"Công pháp","hePhai":"Vô Tình Đạo","soHuu":[],"blurb":"Cảnh giới đạo cao hơn của Vô Tình Đạo mà Thiên Huyễn Vô Tình Đạo có thể phát triển tới.","detail":"Vạn Ảo Thiên Ma Đạo là tầng đạo cao hơn của dòng Vô Tình Đạo. Lão già đại trưởng lão Huyễn gia nhận thấy Mi nhi tu luyện Thiên Huyễn Vô Tình Đạo có tiềm năng mơ hồ phát triển tới Vạn Ảo Thiên Ma Đạo — điều cực kỳ hiếm thấy, nên thu nàng làm đệ tử.","nguon":["@c0616"],"aliases":["#vach-anh-thien-ma-dao-mi-nhi"]},{"id":"loi-he-than-thong","name":"Lôi hệ thần thông","loai":"than-thong","loaiLabel":"Thần thông","soHuu":[],"blurb":"Hệ thần thông lôi điện được La Vân Tinh Vực và Lôi Chi Tiên Giới coi là pháp thuật uy lực lớn nhất.","detail":"Lôi hệ thần thông được La Vân Tinh Vực cùng Lôi Chi Tiên Giới xem là pháp thuật thần thông uy lực lớn nhất. Tuy vậy, Lôi hệ thần thông thông thường không thể biến ảo linh hoạt để ngưng ra một tia lôi uy chân chính như Vương Lâm thi triển — điều khiến Tôn Tuyết Sơn khiếp sợ vì ngay cả tổ tiên gia tộc hắn cũng chưa làm được.","nguon":["@c0616"]},{"id":"nguy-ke-thua-phong-an-vuong-lam","name":"Ngụy kế thừa (phong ấn đặc thù)","cn":"","loai":"bi-thuat","loaiLabel":"Thủ pháp luyện khí","phamCap":"Tự sáng tạo","hePhai":"Vương Lâm tự sáng","soHuu":["Vương Lâm"],"blurb":"Thủ pháp Vương Lâm tự sáng tạo: thêm một đạo phong ấn đặc thù vào pháp bảo và đặt bí quyết mở phong ấn vào ngọc giản, mô phỏng hiệu quả kế thừa chân chính.","detail":"Vốn chỉ Đại Tông Sư luyện khí mới luyện được pháp bảo có năng lực kế thừa (như Tôn Hồn Phiên, Xạ Thần Xa). Vương Lâm nghĩ lệch: thay vì kế thừa thật, thêm cho pháp bảo một đạo phong ấn đặc thù và đặt bí quyết mở phong ấn vào ngọc giản. Nếu phong ấn đủ mạnh thì không ai phá giải, hiệu quả như kế thừa thật. Hắn áp lên gương đồng bằng cách đánh liên tiếp các cấm chế tạo hắc quang nhiều kí hiệu, dẫn khói nến qua hạt châu rồi nắm khói đặt vào kí hiệu cho khói đen chui vào gương, sau đó ấn bí quyết phá giải vào ngọc giản.","nguon":["@c0617"]},{"id":"ba-tran-phap-hat-chau-xanh","name":"Ba trận pháp trong hạt châu xanh","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Pháp thuật nhỏ (La Thiên Tinh Vực)","hePhai":"La Thiên Tinh Vực","soHuu":[],"blurb":"Ba trận pháp ẩn trong hạt châu xanh nạm trên nóc phòng: hấp thu khói nến, hóa nhiệt, ngưng thành quang, kèm trận pháp tỏa hương thơm.","detail":"Hạt châu màu xanh to bằng nắm tay nạm trên nóc nhà ẩn ba trận pháp: khói nến bị hạt châu hấp thu, hóa nhiệt, ngưng thành quang tỏa ánh sáng êm dịu làm nguồn sáng duy nhất khi tắt nến, kèm một mùi hương nhẹ không độc giúp tu sĩ thổ nạp nhanh hơn và là vật liệu luyện đan. Vương Lâm nhận xét loại pháp thuật nhỏ này ở La Thiên Tinh Vực mạnh hơn nhiều so với Tu Chân Liên Minh.","nguon":["@c0617"]},{"id":"tran-phap-linh-thach-bao-hop-lau","name":"Trận pháp linh thạch Bảo Hợp Lâu","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Bảo Hợp Lâu","soHuu":["Bảo Hợp Lâu"],"blurb":"Trận pháp bày từ tám khối thượng phẩm nguyên linh thạch cao ba trượng, có tầng phòng vệ ngăn thần thức.","detail":"Tám khối thượng phẩm nguyên linh thạch cao ba trượng bày thành trận, tỏa linh uy nồng đậm, dung hợp bốn phía thành cảm giác mù mịt như hư vô; bên trong còn có tầng phòng vệ ngăn thần thức thâm nhập.","nguon":["@c0618"],"aliases":["#tran-phap-linh-thach-bao-hop-lau-618"]},{"id":"thuan-di-lac-an-phi-kiem","name":"Thuấn di (lạc ấn trong phi kiếm)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Khả năng dịch chuyển tức thời được khắc thành lạc ấn trong phi kiếm; kích hoạt thì kiếm biến mất rồi xuất hiện cách xa.","detail":"Lạc ấn thuấn di khắc trong phi kiếm: khi mở thần thông, kiếm đột nhiên biến mất rồi xuất hiện cách đó hơn mười trượng, hoặc bay ra ngoài ngàn dặm rồi quay về tức khắc. Bình thường phi kiếm không thể lưu giữ lạc ấn thuấn di vì kiếm thể không chịu được ma sát lớn; cần tu vi phi thường, công pháp cực cao và ý cảnh đặc thù mới khắc và duy trì được. Chính nhờ ý cảnh sinh tử luân hồi của Vương Lâm mà lạc ấn này sinh sôi không ngừng.","nguon":["@c0619"],"aliases":["#thuan-di-lac-an-phi-kiem-619"]},{"id":"thuat-dai-na-di-phi-kiem","name":"Thuật Đại Na Di (phi kiếm ngụy tiên bảo)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao cấp","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật không gian khắc trên phi kiếm ngụy tiên bảo, được lão già áo xanh nhận ra khi kiểm định.","detail":"Thuật Đại Na Di trên phi kiếm ngụy tiên bảo Vương Lâm bán; là một trong những đặc tính khiến lão già áo xanh định danh thanh kiếm là ngụy tiên bảo. Kết hợp với lôi điện kì dị tạo nên giá trị khác biệt của thanh phi kiếm so với ngụy tiên bảo thường.","nguon":["@c0619"]},{"id":"tran-phap-thanh-truc-cac","name":"Trận pháp Thanh Trúc Các","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thanh Trúc Các","soHuu":["Lão già áo xanh (trưởng lão Thanh Trúc Các)"],"blurb":"Trận do trưởng lão gia tộc lắp đặt trong Thanh Trúc Các khiến tu sĩ dưới Vấn Đỉnh không thể che giấu tu vi.","detail":"Trận pháp bố trí trong Thanh Trúc Các tại Nhiễm Vân Tinh: bất kỳ tu sĩ nào dưới cảnh giới Vấn Đỉnh khi vào đều không thể che giấu được tu vi thật. Khiến Tôn Mặc nghi ngờ nhưng vẫn tin Vương Lâm chỉ ở Kết Đan hậu kỳ.","nguon":["@c0619"]},{"id":"phap-quyet-ep-tien-khi-tho-nap","name":"Pháp quyết ép tiên khí thổ nạp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật tu luyện","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Pháp quyết Vương Lâm dùng khi thổ nạp tiên ngọc: đánh ra vài đạo quang ấn ép tiên khí co rút quanh mình để thổ nạp hiệu quả.","detail":"Vương Lâm bắt pháp quyết, đánh ra vài đạo quang ấn rơi lên tiên ngọc đặt khắp bốn phía, ép luồng tiên khí toả ra co rút lại quanh mình không thoát ra ngoài. Nhờ vậy hắn thổ nạp được lượng lớn tiên khí một cách hiệu quả; thổ nạp ba ngày liền, nghìn khối tiên ngọc hóa thành bụi phấn.","nguon":["@c0621"]},{"id":"phap-thuat-che-phu-tuong-mao","name":"Pháp thuật che phủ tướng mạo","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật ngụy trang","phamCap":"","hePhai":"","soHuu":["Người thanh niên nữ giả nam"],"blurb":"Pháp thuật người nữ giả nam dùng che mặt, khiến tướng mạo thật không lộ ra.","detail":"Một pháp thuật phủ trên mặt của người nữ giả nam gần chỗ ở Vương Lâm, che giấu tướng mạo thật khiến nhìn bên ngoài giống một người thanh niên gầy gò. Dù Vương Lâm đã nhận ra đây là nữ giả nam từ mấy ngày trước, hắn vẫn chưa nhìn thấy được khuôn mặt thật của người này.","nguon":["@c0621"]},{"id":"than-thong-suong-mu-hoa-ban-tay-trung-nien","name":"Thần thông sương mù hóa bàn tay","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Nguyên Anh","soHuu":["Người đàn ông trung niên gầy yếu (cướp bảo Tôn gia)"],"blurb":"Triệu sương mù quỷ dị từ hư không, ngưng thành bàn tay to chộp người kèm tia chớp.","detail":"Thần thông của người trung niên Nguyên Anh trung kỳ: sương mù quỷ dị giáng từ hư không, ngưng thành một bàn tay to lớn chộp tới kèm tiếng gào và một tia chớp lóe. Bị Vương Lâm phất tay phải, tiên lực khổng lồ quét sạch, bàn tay tan thành mây khói.","nguon":["@c0620"]},{"id":"con-loc-vung-tay-ao-vuong-lam","name":"Cơn lốc vung tay áo","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh (biểu hiện)","soHuu":["Vương Lâm"],"blurb":"Vung tay áo tạo gió lớn thành lốc xoáy quét trăm trượng, cuốn văng tu sĩ địch.","detail":"Vương Lâm vung tay áo, gió lớn dấy lên thành cơn lốc xoáy quét trăm trượng, cuốn văng các tu sĩ Tôn gia bay lên nghênh chiến. Một đòn thị uy điềm tĩnh khi đối đầu cả gia tộc Tôn gia.","nguon":["@c0620"]},{"id":"uy-ap-giang-xuong-vuong-lam","name":"Uy áp giáng xuống","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh (biểu hiện)","soHuu":["Vương Lâm"],"blurb":"Nhấn tay phải, giáng một cỗ uy áp khổng lồ buộc cả gia tộc vận linh lực chống đỡ kẻo sụp đổ.","detail":"Vương Lâm nhấn tay phải xuống, giáng một cỗ uy áp khổng lồ lên tòa nhà lớn của Tôn gia, áp lực ép xuống khiến cả gia tộc phải vận linh lực chống đỡ kẻo tòa nhà sụp đổ. Uy thế khiến lão hắc y Anh Biến hậu kỳ và Lão tổ tầng Vấn Đỉnh đều phải nhượng bộ.","nguon":["@c0620"]},{"id":"hoan-huyet-huyen-gia","name":"Hoán Huyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Huyễn Gia","soHuu":["Sư phụ của Liễu Mi"],"blurb":"Pháp thuật rất ít khi dùng để thay đổi máu huyết của đệ tử, đưa huyết mạch một gia tộc vào người được chọn.","detail":"Pháp thuật hiếm dùng dùng để thay đổi máu huyết. Sư phụ Huyễn Gia định thi triển Hoán Huyết để đưa máu huyết Huyễn Gia vào huyết mạch Liễu Mi, nhờ đó nàng có huyết mạch tu được công pháp cao giai và được gia tộc bảo hộ, đồng thời đổi tên thành Huyễn Mi.","nguon":["@c0622"]},{"id":"hoan-huyet-dai-phap-huyen-gia","name":"Hoán Huyết đại pháp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Huyễn gia","soHuu":[],"blurb":"Đại pháp của Huyễn gia dùng để biến một đệ tử ngoại lai thành người chính thống của gia tộc. (+) Đại pháp đổi huyết mạch mà Lão tổ Huyễn gia định thi triển cho con gái nuôi Liễu Mi. [CAN-SOAT-GOP]","detail":"Nghi thức mà một tổ tiên Huyễn gia trở về sau mấy ngàn năm định thi triển cho đệ tử tư chất kinh người mà ông mang theo, dự kiến ba tháng sau. Mục đích biến đệ tử này thành người chính thống của Huyễn gia.","nguon":["@c0626","@c0630"],"aliases":["#hoan-huyet-dai-phap-huyen-gia-630"]},{"id":"tran-phap-hap-thu-tien-ngoc-vuong-lam","name":"Trận pháp hấp thu tiên ngọc","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Đạo Hóa Hoàng Tuyền","soHuu":["Vương Lâm"],"blurb":"Trận pháp không tên Vương Lâm nghiên cứu từ thức thứ ba Đạo Hóa Hoàng Tuyền để hấp thu lượng lớn tiên lực đột phá.","detail":"Vương Lâm rải gần ba mươi vạn tiên ngọc trong phạm vi mười dặm rồi vận trận. Khi hô “Vỡ!” toàn bộ tiên ngọc tự nổ bùng lên cơn lốc tiên lực khổng lồ; khi hô “Hút!” cơn lốc bị hắn nuốt trọn, nguyên thần cắn nuốt tiên lực để đề cao tu vi.","nguon":["@c0626"]},{"id":"chuong-tam-loi-nhiem-gia","name":"Chưởng Tâm Lôi","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Nhiễm gia","soHuu":["Lão tổ Nhiễm Gia"],"blurb":"Đòn sét lao thẳng vào hư không do lão tổ Nhiễm gia thi triển.","detail":"Chưởng Tâm Lôi là thần thông sét của lão tổ Nhiễm gia, tia sét đánh thẳng vào hư khôn nơi Vương Lâm ẩn thân. Đòn này bị con rối Tiên vệ của Vương Lâm đánh tan trong nháy mắt.","nguon":["@c0627","@c0633"]},{"id":"sinh-tu-luan-hoi-dao-vuong-lam","name":"Sinh Tử Luân Hồi (đạo)","cn":"","loai":"khac","loaiLabel":"Đạo / Ý cảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh Vương Lâm tu luyện, nay đã dung hợp làm một với nguyên thần; gồm hai mặt sinh và tử.","detail":"Sinh Tử Luân Hồi là ý cảnh trục của Vương Lâm, đến chương này đã dung hợp làm một với nguyên thần — nguyên thần chính là sự cảm ngộ về sinh tử. Đạo gồm hai mặt: “tử” biểu hiện qua Đạo Hóa Hoàng Tuyền (tử vào Hoàng tuyền) đã được hắn nắm khi Vấn Đỉnh, còn đạo “sinh” thì vẫn chưa rõ ở đâu. Phía trước sinh tử là đạo nhân quả quá lớn chưa thể xác định.","nguon":["@c0627"]},{"id":"dao-hoa-hoang-tuyen","name":"Đạo Hóa Hoàng Tuyền","cn":"","loai":"khac","loaiLabel":"Đạo / Lĩnh ngộ","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo Vương Lâm hiểu ra lúc Vấn Đỉnh, là biểu hiện của “tử” trong sinh tử (tử vào Hoàng tuyền).","detail":"Đạo Hóa Hoàng Tuyền là phần đạo Vương Lâm lĩnh ngộ lúc Vấn Đỉnh, biểu hiện cho mặt “tử” trong Sinh Tử Luân Hồi — chết là hóa vào Hoàng tuyền. Nó là một nửa của đạo sinh tử, đối lập với đạo “sinh” mà hắn còn đang truy tìm.","nguon":["@c0627"]},{"id":"hoan-huyet-dai-phap-huyen-gia-627","name":"Hoán Huyết đại pháp (Huyễn gia)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Huyễn gia","soHuu":["Lão tổ Huyễn Gia"],"blurb":"Pháp môn lão tổ Huyễn gia không tiếc thi triển vì Liễu Mi.","detail":"Hoán Huyết đại pháp là pháp môn lão tổ Huyễn gia đã không tiếc thi triển vì Liễu Mi (nghĩa nữ mang về từ Liên minh tinh vực). Việc này bị gia chủ Huyễn Phong Thần lấy làm cớ nghi ngờ lão tổ định giao Huyễn gia cho người ngoài.","nguon":["@c0627"]},{"id":"thien-huyen-vo-tinh-dao-huyen-gia","name":"Thiên Huyễn Vô Tình đạo (Huyễn gia)","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Bản chất Thiên Huyễn thánh Huyễn gia","hePhai":"Huyễn gia","soHuu":["Vương Lâm"],"blurb":"Phương pháp tu luyện thần thông Huyễn gia, là bản chất của Thiên Huyễn thánh.","detail":"Ghi chép trong ngọc giản di vật người Huyễn gia: phương pháp tu luyện thần thông Huyễn gia, là bản chất của Thiên Huyễn thánh Huyễn gia. Trên có cấm chế đặc thù che mấy chỗ quan trọng, phải phá giải bằng huyết mạch mới mở được. Vương Lâm có được ngọc giản này từ tay người Huyễn gia chết bốn năm trước.","nguon":["@c0628"]},{"id":"tam-y-ngu-hanh-quyet-huyen-gia","name":"Tâm Ý Ngũ Hành quyết","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đạo pháp bậc hai của Huyễn gia","hePhai":"Huyễn gia","soHuu":["Huyễn Đông"],"blurb":"Đạo pháp bậc hai của Huyễn gia, chia theo Ngũ Hành; Huyễn Đông tu vì tư chất không hợp Thiên Đạo Vô tình.","detail":"Đạo pháp bậc hai của Huyễn gia, dành cho người tư chất không đủ để tu Thiên Đạo Vô tình. Pháp môn chia theo Ngũ Hành; Huyễn Đông cảm ngộ ý cảnh kim bí quyết — Kim không gì không phá được — bấm pháp quyết hóa ánh sáng trắng biến ảo cùng khí tức âm hàn, mượn uy lực của ánh sáng. Khi giao thủ với Vương Lâm, hắn kích Uy lực của Kim lên kim kiếm để chống đỡ Tịch Diệt chỉ nhưng vẫn bị phá vỡ.","nguon":["@c0629"],"aliases":["#tam-y-ngu-hanh-quyet-huyen-gia-629"]},{"id":"thien-dao-vo-tinh-huyen-gia","name":"Thiên Đạo Vô tình","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Đạo pháp cấp cao của Huyễn gia","hePhai":"Huyễn gia","soHuu":[],"blurb":"Công pháp cấp cao của Huyễn gia, đòi hỏi tư chất cao; Huyễn Đông không đủ tư chất để tu hành.","detail":"Đạo pháp cấp cao nhất của Huyễn gia, đòi hỏi tư chất phù hợp mới có thể tu hành. Huyễn Đông vì tư chất không hợp nên không tu được mà phải chuyển sang Tâm Ý Ngũ Hành quyết bậc hai.","nguon":["@c0629"],"aliases":["#thien-dao-vo-tinh-huyen-gia-629"]},{"id":"toa-tinh-dai-tran-huyen-gia","name":"Tỏa tinh đại trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Huyễn gia","soHuu":["Lão tổ Huyễn Gia"],"blurb":"Đại trận do Huyễn gia bố trí, sẽ trực tiếp giáng lâm Nhiễm Vân tinh để vây tinh cầu, đề phòng ba nhà chạy thoát. (+) Đại trận phong tỏa Huyễn gia bố trí bên ngoài một tinh cầu, không cho ai chạy ra. [CAN-SOAT-GOP]","detail":"Sau khi tộc vệ Huyễn Đông bị giết, Huyễn gia bố trí Tỏa tinh đại trận vây quanh Nhiễm Vân tinh, không cho bất kỳ ai chạy ra, biến cả tinh cầu thành vật trong lồng, chờ sau khi Huyễn Mi hoàn thành Hoán huyết đại pháp mới ra tay trả thù.","nguon":["@c0630","@c0632"],"aliases":["#toa-tinh-dai-tran-huyen-gia-632"]},{"id":"hoan-huyet-dai-phap-truyen-thua-huyen-gia","name":"Hoán huyết đại pháp","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đại pháp truyền thừa huyết mạch","hePhai":"Huyễn gia","soHuu":["Lão tổ Huyễn Gia"],"blurb":"Đại pháp dung hợp máu mấy vạn tộc nhân Huyễn gia, luyện hóa huyết mạch tinh khiết để truyền thừa cho người được chọn.","detail":"Lão tổ Huyễn gia hút cạn nước đầm tạo hố lõm, để mấy vạn tộc nhân lần lượt cứa tay đổ máu vào, cuối cùng tự cắt cổ tay đổ máu nhiều nhất rồi niệm “Dung” khiến máu dung hợp thành một, luyện hóa thành một ngàn huyết phù. Niệm “Huyết mạch, hiện” cho ao máu dựng cột rồi sụp thành huyết phù khắc lên thân người được truyền, dung nhập biến họ thành người mang huyết mạch Huyễn gia — huyết mạch tổ tiên vốn là tiên nhân Lôi tiên giới đã hủy, đồng thời bức máu cũ ra ngoài.","nguon":["@c0631"]},{"id":"van-huyen-vo-tuong-dao-huyen-gia","name":"Vạn Huyễn Vô Tướng đạo","loai":"cong-phap","loaiLabel":"Đạo / Công pháp","phamCap":"Đạo của Lão tổ Huyễn gia","hePhai":"Huyễn gia","soHuu":["Lão tổ Huyễn Gia"],"blurb":"Đạo của Lão tổ Huyễn gia, bàn tay phát ánh sáng thần thánh thiên biến vạn hóa hiện sinh lão bệnh tử yêu hận tình cừu của đời người.","detail":"Khi truyền công cho Liễu Mi, bàn tay Lão tổ phát ánh sáng thần thánh thiên biến vạn hóa, hiện ra sinh - lão - bệnh - tử - yêu - hận - tình - cừu của đời người, ấn lên Thiên Linh nàng để đả đạo niệm khổng lồ vào nguyên thần.","nguon":["@c0631"]},{"id":"van-huyen-thien-ma-dao-lieu-mi","name":"Vạn Huyễn Thiên Ma đạo","cn":"","aliases":["Vạn Huyễn Yêu Ma đạo"],"loai":"than-thong","loaiLabel":"Thần thông / Ma đạo","phamCap":"","hePhai":"Liễu Mi","soHuu":["Liễu Mi"],"blurb":"Pháp môn ma đạo của Liễu Mi, như Thiên ma hóa thân nhập thể, gợi nguyên thần chi hỏa đốt cháy thể xác và tinh thần đối phương.","detail":"Vạn Huyễn Thiên Ma đạo (còn gọi Vạn Huyễn Yêu Ma đạo) sưu tập quá khứ và người quen của nạn nhân rồi biến hóa thành họ — “trong giả có thực” — để công tâm đối thủ. Pháp môn như Thiên ma hóa thân nhập thể, gợi lên nguyên thần chi hỏa đốt cháy cả thể xác lẫn tinh thần. Liễu Mi dùng nó lần lượt hóa thành Hồng Điệp, Chu Như, mẹ Vương Lâm, cha hắn, Vương Trác, Độn Thiên và Lý Mộ Uyển; nhưng nhờ nguyên thần ẩn chứa thượng cổ Lôi Long, Vương Lâm không bị lay động và phá vỡ huyễn cảnh.","nguon":["@c0634"]},{"id":"dao-niem-vuong-lam","name":"Đạo niệm","cn":"","aliases":[],"loai":"khac","loaiLabel":"Lĩnh ngộ / Ý cảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo niệm Vương Lâm sở hữu khiến Hồng Điệp kinh ngạc, tăng uy lực cho Đạo hóa Hoàng Tuyền.","detail":"Đạo niệm là phần lĩnh ngộ về đạo của Vương Lâm; khi hòa vào Đạo hóa Hoàng Tuyền đã làm tăng uy lực thần thông, khiến hình huyễn Hồng Điệp kinh ngạc vì Vương Lâm tu vi chỉ Vấn Đỉnh sơ kỳ nhưng đã sở hữu đạo niệm.","nguon":["@c0634"]},{"id":"phu-van-hoa-hong-diep","name":"Phù văn hoa của Hồng Điệp","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Liễu Mi"],"blurb":"Nhụy và cánh hoa hồng tổ hợp thành phù văn lớn trăm trượng như núi đè xuống.","detail":"Khi biến thành Hồng Điệp, Liễu Mi lấy ra đóa hoa hồng đỏ; cánh hoa bay lên mang lực lượng kỳ dị tấn công, nhụy hoa tổ hợp thành một phù văn lớn trăm trượng như núi đè xuống đối thủ. Bị Đạo hóa Hoàng Tuyền của Vương Lâm bóp nát.","nguon":["@c0634"]},{"id":"hoang-tuyen-chi-luc-de-tam-thuc","name":"Hoàng Tuyền Chi Lực (Đệ Tam Thức)","cn":"黃泉之力","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Thức (thần thông đạo niệm)","hePhai":"Thần thông đạo niệm của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đệ Tam Thức trong thần thông đạo niệm của Vương Lâm, lĩnh ngộ nhờ tự thân hóa thành lực hút của vực sâu như hoàng tuyền.","detail":"Là đệ tam thức trong thần thông đạo niệm của Vương Lâm. Muốn lĩnh ngộ phải thả lỏng tâm thần không chống cự, để lực hút khủng khiếp của hố sâu xuyên thấu qua thân thể, rồi tiến tới mức chính mình trở thành một bộ phận của lực hút. Khi dung nhập hoàn toàn cả thân thể lẫn nguyên thần vào lực hút, vực sâu đáy hố như hoàng tuyền vô tận thuận theo ý chí. Vương Lâm mất mười bảy năm cảm ngộ mới thành tựu thức này.","nguon":["@c0611"],"aliases":["#hoang-tuyen-chi-luc-de-tam-thuc-611"]},{"id":"that-tinh-kiem-tran-chong-luc-hut-612","name":"Thất Tinh Kiếm Trận (chống lực hút dòng xoáy)","loai":"bi-thuat","loaiLabel":"Kiếm trận","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Bảy thanh kiếm hóa bảy đạo cầu vồng cắm sâu xuống đất quanh Vương Lâm, điện quang đan thành màn bảo vệ cố định thân hắn trước lực hút khủng khiếp của dòng xoáy.","detail":"Khi tiến sát miệng khe có dòng xoáy cực lớn, Vương Lâm triển khai Thất Tinh Kiếm Trận: bảy thanh kiếm hóa bảy đạo cầu vồng cắm xuống đất, điện quang đan xen thành màn bảo vệ giữ thân. Dưới lực hút mạnh, Kiếm Hồn rít gào dung hợp biến hình chống cự, kiếm như hòa làm một thể với mặt đất, giúp hắn không bị cuốn vào dòng xoáy.","nguon":["@c0612"]},{"id":"nguy-ke-thua-phong-an-dac-thu","name":"Ngụy kế thừa (phong ấn đặc thù)","cn":"","loai":"bi-thuat","loaiLabel":"Thủ pháp luyện khí","phamCap":"Tự sáng tạo","hePhai":"Vương Lâm tự chế","soHuu":["Vương Lâm"],"blurb":"Thủ pháp Vương Lâm tự sáng tạo, mô phỏng hiệu quả kế thừa chân chính bằng cách thêm phong ấn đặc thù vào pháp bảo.","detail":"Năng lực kế thừa chân chính của pháp bảo (như Tôn Hồn Phiên, Xạ Thần Xa) chỉ Đại Tông Sư luyện khí mới luyện được. Vương Lâm nghĩ lệch sang việc thêm cho pháp bảo một đạo phong ấn đặc thù và cất bí quyết mở phong ấn vào ngọc giản — nếu phong ấn đủ mạnh tới mức không ai phá giải thì hiệu quả gần như kế thừa thật, giúp giá trị pháp bảo tăng nhiều lần. Hắn áp dụng thành công lên gương đồng: đánh liên tiếp cấm chế tạo hắc quang nhiều kí hiệu, dẫn khói nến qua hạt châu rồi nắm khói đặt vào kí hiệu cho khói đen chui vào gương, sau đó ấn bí quyết phá giải vào ngọc giản.","nguon":["@c0617"]},{"id":"y-canh-sinh-tu-luan-hoi-phi-kiem-619","name":"Ý cảnh sinh tử luân hồi (nuôi lạc ấn phi kiếm)","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh của Vương Lâm khiến lạc ấn thuấn di trong phi kiếm sinh sôi không ngừng.","detail":"Nhờ ý cảnh sinh tử luân hồi mà lạc ấn thuấn di khắc trong phi kiếm ngụy tiên bảo sinh sôi không ngừng, duy trì khả năng thuấn di lâu dài; nếu cân bằng của ý cảnh bị phá thì lạc ấn sẽ mất hiệu lực. Đây là điều khiến phi kiếm của Vương Lâm khác biệt với ngụy tiên bảo thường.","nguon":["@c0619"]},{"id":"lac-an-thuan-di-phi-kiem-619-loi-dien","name":"Lôi điện kì dị (điện quang trên phi kiếm)","cn":"","loai":"khac","loaiLabel":"Uy năng","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo điện quang chạy trên phi kiếm ngụy tiên bảo; chạm vào bật ra tiếng ầm chấn người lùi mấy bước.","detail":"Một đạo điện quang (quang điện) chạy trên thanh phi kiếm ngụy tiên bảo của Vương Lâm. Khi lão già áo xanh chạm thử, lôi điện bật ra tiếng ầm khiến lão bị chấn lùi mấy bước, sắc mặt tái nhợt. Lão coi đây là điểm quý báu khiến phi kiếm khác biệt hẳn so với ngụy tiên bảo thông thường.","nguon":["@c0619"]},{"id":"luyen-che-tien-ve-bi-thuat-608","name":"Luyện chế Tiên Vệ (bí thuật tế luyện)","cn":"","aliases":["Nhân thể pháp bảo"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Tiên cấp","hePhai":"Tiên Đế Thanh Lâm / Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Bí thuật do Tiên Đế Thanh Lâm bắt chước Cổ Thần sáng tạo, biến người sống thành khôi lỗi Tiên Vệ — nhân thể pháp bảo không cảm xúc mà có linh trí.","detail":"Bốn bước: (1) Luyện thân thể đến cực mạnh, pháp bảo tầm thường không tổn hại; (2) Hóa nguyên thần, mài nhỏ rồi dung nhập vào cơ thể, khiến thần ở trong ý; (3) Luyện hóa lục phủ ngũ tạng héo rũ, cắt đứt năm cảm giác, không thấy đau đớn; (4) Diệt sạch thần thức nhưng bảo lưu linh trí — khôi lỗi linh động mà vô cảm xúc. Tiên Vệ có bốn trình độ: Kim, Ngân, Đồng, Thiết. Điều kiện bắt buộc: người được luyện không được dâng lên một tia chống cự, nếu không lập tức thất bại. Bước hai chỉ cần thất bại một lần là tế luyện hỏng hẳn, thân thể không thể bị đoạt xá hay dung nhập nguyên thần khác. Ngọc giản ghi bí thuật còn chứa thần thông chỉ Tiên Vệ mới thi triển được.","nguon":["@c0608"]},{"id":"dao-niem-hai-thuc-vuong-lam","name":"Đạo niệm hai thức (Hoàng Tuyền · Tuyền Hồn)","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Đạo niệm","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo niệm của Vương Lâm gồm hai thức: đạo hóa Hoàng Tuyền và ngưng hóa Tuyền Hồn.","detail":"Đạo niệm Vương Lâm có hai thức: thức nhất đạo hóa Hoàng Tuyền, thức nhì ngưng hóa Tuyền Hồn. Thức nhì còn thiếu một mạng hung sát — Tuyền Hồn năm xưa được ngưng hóa từ hồn phách trên Tôn Hồn Phiên; Thiên Quỷ có hung khí nhưng chỉ hung mà vô sát, không đủ thành Tuyền Hồn. Vương Lâm ngộ ra Tuyền Hồn chân chính không cần hồn phách hùng mạnh — hồn phách càng đơn giản nhỏ bé càng ẩn nhiều hung và sát; hắn dự định rời nơi này đi khắp nhân gian rút khí hung sát từ hồn phách phàm nhân để ngưng luyện hồn phách Hoàng Tuyền, và sáng tạo thức thứ ba từ cảm thụ sức mạnh thiên địa.","nguon":["@c0610"]},{"id":"am-duong-hu-that-than-thong-bong","name":"Âm Dương Hư Thật (thần thông bóng)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông bóng Vương Lâm thi triển dưới ánh trăng, kéo dài bóng thân thành bóng đen lao khỏi mặt đất công kích.","detail":"Dưới ánh trăng, Vương Lâm vận thần thông bóng từ Âm Dương Hư Thật Nhị Ý: bóng hắn kéo dài hóa bóng đen lao khỏi mặt đất, đánh xuyên thân Thạch Tiêu khiến mọi bộ phận cơ thể vỡ vụn; ánh mắt bóng đen còn áp chế khiến nguyên thần Trần Đào co lại.","nguon":["@c0613"]},{"id":"thien-loi-chan-chinh-vuong-lam","name":"Thiên Lôi (chân chính)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thiên Lôi chân chính sinh ra từ nguyên thần Vương Lâm dung hợp với Thái Cổ Lôi Long, mang lôi uy chân chính.","detail":"Không phải phép thuật biến ảo tầm thường mà là Thiên Lôi chân chính, do nguyên thần Vương Lâm dung hợp với Thái Cổ Lôi Long sinh ra nguyên thần bản năng. Hắn chỉ tay về phía trước, trong nguyên thần hiện một tia chớp dũng mãnh theo tay bắn ra, liên tiếp chỉ ra sấm sét; sấm chớp như rồng hoá thành uy áp lao vào sương mù, mang lôi uy chân chính khiến Minh vụ trùng cảm nhận được mà lùi nhanh, tiêu tan toàn bộ sương độc.","nguon":["@c0615"]},{"id":"tien-ve-than-thong-doi-tuong-mao-vuong-lam","name":"Tiên vệ thần thông (che giấu tướng mạo)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm dựa vào để che giấu và đổi tướng mạo bên trong, khiến cả tu sĩ bậc cao khó nhìn ra chân tướng.","detail":"Khác với thuật biến hóa tướng mạo thông thường (mà tu sĩ bậc cao chỉ cần ngưng thần là nhìn ra chân tướng), Vương Lâm dựa vào tiên vệ thần thông bên trong để thay đổi dung mạo một cách chậm rãi nên ít ai nhận ra được.","nguon":["@c0616"]},{"id":"sat-luc-chi-y","name":"Sát lục chi ý / Sát lục chi tâm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát lục chi ý sinh ra từ sát lục chi tâm của Vương Lâm; dưới lực hút cực mạnh hóa thành tơ đỏ lộ dưới da, số lượng lên tới trăm vạn bằng đúng số Sinh Mệnh Lạc Ấn.","detail":"Khi Vương Lâm chống lực hút khủng khiếp ở miệng khe, sát lục chi ý từ sát lục chi tâm hóa thành vô số tơ đỏ từ dưới da lộ ra, số lượng lên tới trăm vạn — đúng bằng số Sinh Mệnh Lạc Ấn hắn từng tích, cho thấy mức độ sát khí tích tụ qua quá trình tu đạo.","nguon":["@c0612"]},{"id":"y-canh-sinh-tu-luan-hoi","name":"Ý cảnh sinh tử luân hồi","cn":"","loai":"khac","loaiLabel":"Ý cảnh","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ý cảnh đặc thù của Vương Lâm, nhờ nó mà lạc ấn thuấn di trong phi kiếm sinh sôi không ngừng; nếu cân bằng bị phá thì mất hiệu lực.","detail":"Ý cảnh sinh tử luân hồi là yếu tố then chốt khiến phi kiếm ngụy tiên bảo có thể duy trì lạc ấn thuấn di — điều bình thường bất khả vì kiếm thể không chịu được ma sát lớn. Nhờ ý cảnh này, lạc ấn tự sinh sôi và duy trì liên tục bên trong kiếm, tạo nên khả năng thuấn di độc đáo.","nguon":["@c0619"]},{"id":"tam-buoc-ap-buc","name":"Tám bước áp bức","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Uy thế đạp bước của Vương Lâm: tiến tám bước, mỗi bước như sấm sét nổ trong tâm thần đối thủ.","detail":"Vương Lâm ung dung tiến từ ba mươi bước, áp lực tăng dần tới mười bước thì đạt đỉnh. Hắn liên tục đi tám bước, mỗi bước như sấm sét nổ trong tâm thần đối phương, tạo gió lốc chồng chất; bước cuối ngưng tụ toàn bộ khí thế dẫn phát một lần, khiến Tôn Tích trắng bệch liên tục lui kinh hoàng.","nguon":["@c0622"]},{"id":"than-thong-cu-ma-toc-lao-to","name":"Thần thông Cự Ma Tộc lão tổ","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cự Ma Tộc","soHuu":["Cự Ma Tộc lão tổ"],"blurb":"Thần thông di chuyển không gian của lão tổ Cự Ma Tộc, từng đưa Tôn Thái tới tận La Thiên Tinh Vực.","detail":"Thần thông được Cự Ma Tộc lão tổ thi triển năm xưa, đưa Tôn Thái vượt khoảng cách xa tới tận La Thiên Tinh Vực. Uy lực vượt mức mà cả Vương Lâm lẫn Tôn Thái cho là Cự Ma Tộc có thể đạt được, trở thành nghi vấn treo mấy trăm năm chưa lời giải.","nguon":["@c0624"]},{"id":"na-di-vuong-lam-627","name":"Na Di","loai":"bi-thuat","loaiLabel":"Độn thuật","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật di chuyển tức thời Vương Lâm dùng để về Tôn gia thành.","detail":"Thuật di chuyển Vương Lâm sử dụng để trở về Tôn gia thành, sau đó đi bộ trên phố suy tư cảm ngộ ý cảnh sinh tử luân hồi.","nguon":["@c0627"]},{"id":"tien-ve-than-thong-c0628","name":"Tiên Vệ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông bóng của Vương Lâm: cái bóng dưới chân kéo dài bao phủ vật, theo biến hóa âm dương hư thực để soi ra manh mối ẩn giấu.","detail":"Khi Vương Lâm triệu, cái bóng dưới chân kéo dài bao phủ vật phẩm. Theo biến hóa âm dương hư thực của Tiên Vệ, hắn nhìn ra được những thần thông/cơ quan ẩn giấu — như thần thông nhỏ liên quan mệnh hồn cài trong lệnh bài thân phận người Huyễn gia.","nguon":["@c0628"]},{"id":"tich-diet-chi-vuong-lam-629","name":"Tịch Diệt chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông chỉ pháp của Vương Lâm; lúc này nhuốm điện quang đậm đặc khiến uy lực tăng mấy lần, hóa cầu vồng đen kịt phá không tựa sấm sét Thiên kiếp.","detail":"Khi Vương Lâm chỉ ra, Tịch Diệt chỉ ẩn chứa điện quang đậm đặc, uy lực tăng mấy lần, chỉ phong hóa cầu vồng đen kịt phá không lao ra, bốn phía sóng gợn điện quang. Chỉ phong đen như rồng đen đánh vỡ kim kiếm của Huyễn Đông rồi đánh hắn phun máu, một phần điện quang quỷ dị chia ra vờn quanh nguyên thần đối phương khiến đau đớn.","nguon":["@c0629"]},{"id":"than-thong-am-duong-hu-thuc-nhi-y","name":"Thần thông âm dương hư thực nhị ý","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cao cấp","hePhai":"","soHuu":[],"blurb":"Trình độ thần thông gắn với Vấn Đỉnh đại viên mãn, bước nửa bước vào âm dương hư thực nhị ý.","detail":"Trình độ mà Đỗ Kiến nếu luyện chế Tiên Vệ thành công có thể bước nửa bước vào, gắn với Vấn Đỉnh đại viên mãn. Vương Lâm hứa dùng bí thuật tế luyện khiến Đỗ Kiến có cơ hội đạt tới trình độ này.","nguon":["@c0608"]},{"id":"phuong-phap-luyen-che-tien-ve","name":"Phương pháp luyện chế Tiên Vệ (khôi lỗi)","loai":"bi-thuat","loaiLabel":"Bí thuật luyện chế","phamCap":"Tiên Đế bí pháp","hePhai":"Tiên Đế Thanh Lâm","soHuu":["Vương Lâm","Thanh Lâm"],"blurb":"Phương pháp do Tiên Đế Thanh Lâm sáng tạo, dùng nguyên thần dung nhập huyết nhục tạo khôi lỗi Tiên Vệ.","detail":"Ghi trong ngọc giản, gồm bước thứ hai luyện hóa cực khó: nguyên thần bị xóa mờ nhưng phải giữ liên kết chặt để đạt thần ở trong ý, lơ lỏng là tử vong nên cần chấp niệm mạnh (như chấp niệm nghịch tu). Tu sĩ có đạo niệm tự thân luyện Tiên Vệ xác suất cao hơn. Kèm phương pháp khống chế chống Tiên Vệ phản bội và vài thần thông riêng cho Tiên Vệ.","nguon":["@c0609"]},{"id":"cuu-tinh-lien-chau","name":"Cửu tinh liên châu","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Lôi hệ","soHuu":["Tham Lang"],"blurb":"Chiêu lôi của đệ nhị nguyên thần Tham Lang: chín lôi cầu xếp thẳng hàng như mũi tên phá lực cản lao tới.","detail":"Đệ nhị nguyên thần lôi hệ của Tham Lang sắp chín lôi cầu thành cửu tinh liên châu, xếp thẳng hàng như mũi tên phá lực cản dưới vực sâu lao thẳng tới Vương Lâm; bị Lôi Thú nuốt mất hai khỏa.","nguon":["@c0604"]},{"id":"phu-van-tien-but","name":"Phù văn tiên bút","loai":"bi-thuat","loaiLabel":"Bí thuật","hePhai":"Phù thuật","soHuu":["Vương Lâm"],"blurb":"Vương Lâm dùng tiên bút vẽ năm nét phù văn vàng, chia năm luồng thần thức chống điện long.","detail":"Trong đấu lôi pháp dưới vực, Vương Lâm vận tiên bút vẽ ra năm nét phù văn vàng, chia năm luồng thần thức điều khiển chống đỡ điện long và hắc lôi của đệ nhị nguyên thần Tham Lang; va chạm nổ vang khiến vực sâu như sụp đổ.","nguon":["@c0604"]},{"id":"thon-hon","name":"Thôn hồn","loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Thần thông bẩm sinh của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông bẩm sinh nuốt hết thảy hồn phách trong thiên hạ của Vương Lâm.","detail":"Bản lĩnh nuốt hết thảy hồn phách trong thiên hạ; lâu nay Vương Lâm ít dùng. Trong hố sâu, hắn phóng nguyên thần từ giữa lông mày hóa cực lớn, một ngụm nuốt linh hồn Thái Cổ Lôi Long rồi triển khai thôn hồn hấp thu mạnh mẽ lôi lực trong nửa linh thể, điện quang chạy vào huyết mạch khiến thân thể lóe điện như đang ở trong sấm sét.","nguon":["@c0605"]},{"id":"loi-cau-loi-long","name":"Lôi cầu","loai":"khac","loaiLabel":"Chiêu thức","hePhai":"Chiêu thức của Thái Cổ Lôi Long","soHuu":["Thái Cổ Lôi Long"],"blurb":"Lôi cầu lớn khí thế như Thiên Kiếp do Thái Cổ Lôi Long phun ra.","detail":"Thái Cổ Lôi Long phun ra lôi cầu lớn khí thế tựa Thiên Kiếp; trong hố sâu, lôi cầu đang lao tới bỗng chệch quỹ đạo, chúc xuống và bị lực hút đáy hố hút mất.","nguon":["@c0605"]},{"id":"cam-che-phong-an-loi-long","name":"Cấm chế phong ấn (thân Thái Cổ Lôi Long)","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thủ pháp in cấm chế lên thân Thái Cổ Lôi Long để khống chế, phong ấn nó trong nguyên thần.","detail":"Vương Lâm dùng tay trái in một lượng lớn cấm chế lên thân Thái Cổ Lôi Long, lặp đi lặp lại tạo thành lớp như vảy rồng chồng nhau khiến Lôi Long bớt giãy giụa, qua đó khống chế và phong ấn nó trong nguyên thần suốt quá trình cắn nuốt luyện hóa.","nguon":["@c0606"]},{"id":"can-nuot-thai-co-loi-long-phoi-cam-che","name":"Cắn nuốt Thái Cổ Lôi Long phối cấm chế phong ấn","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật luyện hóa","phamCap":"Không rõ","hePhai":"Lôi đạo / nguyên thần","soHuu":["Vương Lâm"],"blurb":"Thủ pháp Vương Lâm dùng để luyện hóa Thái Cổ Lôi Long bằng nguyên thần kết hợp cấm chế phong ấn.","detail":"Vương Lâm xuất nguyên thần, tay phải luồn vào túm Thái Cổ Lôi Long lôi ra non nửa, tay trái vung lên in một lượng lớn cấm chế phong ấn lên thân Lôi Long; vừa phong ấn vừa cắn nuốt, lặp đi lặp lại để dung hợp dần. Cấm chế chi chít hình thành lớp vảy rồng chồng lên nhau trên thân Lôi Long. Quá trình kéo dài nhiều năm, thân thể phải chìm vào chết giả để bảo trì sức sống; cuối cùng luyện hóa được một phần năm, phần còn lại bị phong ấn trong nguyên thần.","nguon":["@c0606"]},{"id":"kiem-khi-su-ton-ban","name":"Kiếm khí sư tôn ban","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"Chưa rõ","hePhai":"Đại La Kiếm Tông","soHuu":["Thần Long"],"blurb":"Kiếm khí Thần Long được sư tôn ban tặng, dự định dùng để phản bội Tham Lang.","detail":"Kiếm khí mà sư tôn ban cho Thần Long. Cuối chương 600, Thần Long hối hận vì đã do dự không dùng kiếm khí này sớm hơn để hạ quyết tâm phản bội Tham Lang.","nguon":["@c0600"]},{"id":"kiem-khi-ban-menh-lang-thien-hau","name":"Kiếm khí bản mệnh của Lăng Thiên Hậu","loai":"than-thong","loaiLabel":"Thần thông kiếm khí","phamCap":"Không rõ","hePhai":"Đại La Kiếm Tông","soHuu":["Thần Long","Ngọ Mã","Tị Xà"],"blurb":"Kiếm khí bản mệnh do Lăng Thiên Hậu luyện hóa bốn tiểu thiên địa thành Nguyên Thần kiếm.","detail":"Kiếm khí bản mệnh ẩn trong Nguyên Thần kiếm do Lăng Thiên Hậu luyện hóa bốn tiểu thiên địa thành. Mạnh hơn kiếm khí của Tử Thử mấy lần, đủ sức đột phá Tử khí. Đệ tử Đại La giữ sẵn để phóng thích phản kích; Thần Long dùng nó tự mở lỗ hổng thoát khỏi sương tím.","aliases":[],"nguon":["@c0601"]},{"id":"sat-luc-tien-quyet-thien-van-tu","name":"Sát Lục Tiên Quyết của Thiên Vận Tử","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông","hePhai":"Thiên Vận Tử","soHuu":["Vương Lâm","Thiên Vận Tử"],"blurb":"Thần thông nén sát lục khí từ trăm vạn xuống một đạo rồi búng ra, hô “Tán” hóa lại thành trăm vạn để thôn phệ.","detail":"Thần thông gắn với Thiên Vận Tử. Vương Lâm điểm mi tâm nén sát lục khí từ trăm vạn xuống còn một đạo rồi búng đi; khi cần lại hô “Tán” hóa một thành trăm vạn để thôn phệ đối thủ. Người thi triển luôn giữ một tia sát lục khí trong nguyên thần để khôi phục sau khi tiêu hao. Tham Lang chê thần thông này chưa hoàn chỉnh.","nguon":["@c0602"]},{"id":"luyen-hon-thuat","name":"Luyện Hồn thuật","cn":"炼魂术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Luyện Hồn tông","soHuu":["Vương Lâm","Hổ Bào"],"blurb":"Thuật khống chế hồn phách truyền thừa của Luyện Hồn tông, lấy hồn phiên vi tôn, trải qua vô số thế hệ tế luyện mấy vạn năm.","detail":"Vương Lâm là đích hệ truyền thừa, để lại chỗ thiếu sót trong thuật khi truyền thụ cho người khác — nhờ đó có thể khống chế tuyệt đối mọi hồn phách mà người tu thuật do hắn truyền thu thập. Thuật không thể bị trọng tổ trong vài chục năm bởi người không có truyền thừa chính thức. Hổ Bào từng dùng thuật này thu trăm vạn hồn phách nhưng bị Vương Lâm đoạt quyền khống chế bằng một đạo phù văn.","nguon":["@c0562","@c0561"]},{"id":"nhat-chi-hoang-tuyen","name":"Nhất Chỉ Hoàng Tuyền","cn":"一指黄泉","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hoàng Tuyền","soHuu":["Vương Lâm"],"blurb":"Chỉ pháp dẫn Hoàng Tuyền hà cuộn xoáy mang luân hồi chi lực, đánh tan hắc lôi.","detail":"Vương Lâm dùng chỉ pháp dẫn dòng Hoàng Tuyền cuộn xoáy mang luân hồi chi lực để hóa giải hắc lôi của Sáo Tiêu giáp lão giả, một phần ba Hoàng Tuyền sụp đổ mới chặn được lôi tán.","nguon":["@c0563"]},{"id":"hoang-tuyen-chi-am","name":"Hoàng Tuyền chi âm","cn":"黄泉之音","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hoàng Tuyền / Nghịch tu chi đạo","soHuu":["Vương Lâm"],"blurb":"Tiếng gầm thét của Hoàng Long do Vương Lâm phát ra bằng nghịch tu chi đạo, có thể phá tan hắc vũ.","detail":"Khi Vương Lâm đạo niệm hóa thân nhập Hoàng Tuyền thành Hoàng Long, phát ra tiếng gầm Hoàng Tuyền chi âm (nghịch tu chi đạo), làm hắc vũ vỡ vụn thành hắc khí.","nguon":["@c0563"]},{"id":"ma-dao-liem-dao","name":"Ma đạo (Ma đao)","cn":"","aliases":["Ma đao","Liêm đao ma diễm"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Hắc giáp lão giả"],"blurb":"Thần thông ma đạo của hắc giáp lão giả, vu��t khải giáp ngưng ma khí thành liêm đao tỏa ma diễm, ẩn chứa quy tắc siêu thoát thiên địa.","detail":"Lão giả vuốt ngực khải giáp ngưng ma khí đen thành thanh liêm đao tỏa ma diễm, ở giữa hư-thực chuyển hóa. Ma ảnh đầu một sừng (ma hồn phân thể thật) từ mi tâm lão giả chui ra nhập vào liêm đao khiến đao sống lại. Lão giả không phải ma nhân chân chính nên ma đao chưa hoàn mỹ. Bị kiếm khí Lăng Thiên Hậu (Bá đạo) phá vỡ, ma ảnh tiêu tan.","nguon":["@c0564"]},{"id":"tu-dao-kiem-than","name":"Tứ đạo kiếm thần","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Kiếm đạo","soHuu":["Lăng Thiên Hậu"],"blurb":"Lăng Thiên Hậu mở tứ tiểu thiên địa luyện hóa thành tứ đạo kiếm thần, là thần thông trứ danh.","detail":"Lăng Thiên Hậu mở tứ tiểu thiên địa luyện hóa thành tứ đạo kiếm thần, nổi danh cùng Thiên Vận Tử trên Thiên Vận tinh.","nguon":["@c0564"]},{"id":"thien-nung-thien-truong-dia-dong","name":"Thiên Nùng (Thiên Trướng Địa Đông)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu Vệ","soHuu":["Địa Ma"],"blurb":"Thần thông trấn áp của Yêu Vệ Địa Ma: ném quả cầu chất dịch xuống đất tạo tường nước vây bốn phía, co rút thành quả cầu khổng lồ giam đối thủ.","detail":"Thiên Nùng, còn gọi Thiên Trướng Địa Đông, là thần thông sở trường của Yêu Vệ Địa Ma. Khi thi triển, Địa Ma ném một quả cầu ngưng tụ từ chất dịch xuống đất, chất dịch lan ra tạo thành tường nước vây kín bốn phía, rồi co rút thành quả cầu khổng lồ giam nhốt đối thủ bên trong. Trước đó, phía sau lưng Địa Ma hiện một hư ảnh hình kén cao mười trượng, há miệng nuốt chửng đòn công kích của địch rồi ngưng tụ thành quả cầu này. Khi vây Vương Lâm, quả cầu co rút chỉ còn ba trượng thì đột nhiên ngừng lại — chiến ý và sát khí điên cuồng từ bên trong xuyên ra, khiến chính Địa Ma cũng co rút đồng tử kinh hãi.","nguon":["@c0561"]},{"id":"hu-anh-hinh-ken","name":"Hư ảnh hình kén","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu Vệ","soHuu":["Địa Ma"],"blurb":"Thần thông phòng ngự của Địa Ma: hư ảnh đen hình kén cao mười trượng sau lưng, há miệng nuốt công kích rồi ngưng tụ thành quả cầu.","detail":"Hư ảnh hình kén là thần thông phụ trợ của Yêu Vệ Địa Ma, xuất hiện phía sau lưng lão khi định thi triển thần thông Thiên Nùng. Hư ảnh đen cao mười trượng này há miệng nuốt chửng đòn công kích của đối thủ — từng nuốt Tịch Diệt Chỉ của Vương Lâm — rồi ngưng tụ thành quả cầu chất dịch dùng cho Thiên Trướng Địa Đông. Tuy vậy, hư ảnh ẩn chứa Phong Ngâm bên trong từng bị Vương Lâm vung trảo phóng khí sát lục bóp vỡ tung, chất dịch tuôn ra, lộ thân Phong Ngâm.","nguon":["@c0561"]},{"id":"dia-tich","name":"Địa Tích","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Thần thông địa hệ: bấm pháp quyết hô tên, khiến mặt đất chu vi ngàn trượng nứt vô số lỗ hổng như vết lở loét rồi nổ tung.","detail":"Địa Tích là thần thông địa hệ do một lão già địch thủ của Vương Lâm thi triển. Khi bấm pháp quyết và hô lớn tên thần thông, mặt đất trong phạm vi chu vi ngàn trượng nứt ra vô số lỗ hổng trông như vết lở loét, sau đó nổ tung. Từ những vết lở loét trên đất phun lên chất lỏng dày cả mười trượng. Đây là đòn tấn công diện rộng dựa trên kiểm soát mặt đất.","nguon":["@c0561"]},{"id":"chuong-an-vo-danh","name":"Chưởng ấn vô danh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dấu tay khổng lồ của Vương Lâm: khí sát lục ẩn trong dấu tay xuyên qua cơ thể đối thủ; từng dọa Mạc Lệ Hải khiếp sợ.","detail":"Chưởng ấn vô danh là một dấu tay khổng lồ Vương Lâm thi triển khi ấn ngón tay, năm xưa từng dọa Mạc Lệ Hải khiếp sợ. Khí sát lục ẩn trong dấu tay, khi thi triển dấu tay xuyên thẳng qua cơ thể đối thủ đưa khí sát lục vào người, khiến nạn nhân tan vỡ hóa thành máu thịt — từng giết chết Yêu Vệ Phong Ngâm. Đáng chú ý, kẻ trong hắc tháp khi chứng kiến chưởng ấn này đã kinh sợ vì nó có bảy phần tương tự thần thông của một nhân vật bí ẩn “người kia”.","nguon":["@c0561"]},{"id":"hac-quang-tich-diet","name":"Hắc quang tịch diệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đòn đánh của Vương Lâm: ấn ngón cái xuất ra hắc quang tốc độ cực nhanh, không bị thôn phệ tiêu tán mà xuyên thẳng qua đối thủ.","detail":"Hắc quang tịch diệt là đòn đánh Vương Lâm thi triển bằng cách ấn ngón cái, phóng ra một đạo hắc quang tốc độ cực nhanh mang ý vị tịch diệt. Khi lão già địch há miệng định thôn phệ đạo hắc quang vào miệng, nó không tiêu tán mà xuyên thẳng ra phía sau, thể hiện uy lực xuyên phá khó cản. Đây là biểu hiện của chỉ pháp Tịch Diệt Chỉ Vương Lâm sử dụng trong trạng thái bị Thăng Tiên Quả kích thích.","nguon":["@c0561"]},{"id":"tu-bao-van-dinh-ky","name":"Tự bạo (Vấn Đỉnh kỳ)","cn":"自爆","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Vấn Đỉnh kỳ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đòn liều của tu sĩ Vấn Đỉnh: cơ thể và nguyên thần hóa lực lượng quét ngang, uy lực cực lớn.","detail":"Tự bạo là đòn liều mạng của tu sĩ Vấn Đỉnh kỳ — toàn thân và nguyên thần thiêu đốt, hóa thành lực lượng phá hủy quét ngang khắp nơi. Tu sĩ Vấn Đỉnh tự bạo rất nguy hiểm khiến đối thủ cường đại cũng phải khiếp sợ lùi tránh. Khi Vương Lâm thi triển, bốn giọt tiên dịch trong cơ thể sôi trào khiến uy lực vượt xa thường lệ, đủ để xé tan thân hắc giáp lão giả sau khi lão mất Bạch giáp thuẫn bài. Trong một quyền tự bạo còn ẩn chứa đạo niệm, sinh mệnh, nguyên thần cùng Cổ Thần chi niệm.","nguon":["@c0565"]},{"id":"co-than-chi-niem","name":"Cổ Thần chi niệm","cn":"古神之念","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Đạo niệm của bổn tôn Cổ Thần, được Vương Lâm ẩn trong một quyền tự bạo đánh về hắc tháp.","detail":"Cổ Thần chi niệm là đạo niệm thuộc thân phận Cổ Thần của bổn tôn Vương Lâm. Khi tự bạo, Vương Lâm đánh ra một quyền chứa đạo niệm, sinh mệnh, nguyên thần và ẩn Cổ Thần chi niệm của bổn tôn về phía hắc tháp, góp phần cùng vết nứt kiếm khí làm sụp đổ hắc tháp.","nguon":["@c0565"]},{"id":"co-yeu-chi-mang","name":"Cổ Yêu chi mang","cn":"古妖之芒","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Yêu","soHuu":["Bối La"],"blurb":"Yêu mang của Cổ Yêu bao phủ luyện hóa hết thảy sinh linh thiên địa; ma khí chạm vào liền bị luyện sạch.","detail":"Cổ Yêu chi mang là thần thông của Cổ Yêu Bối La. Yêu mang lan tỏa bao phủ, có thể luyện hóa hết thảy sinh linh thiên địa nằm trong phạm vi. Khi đại chiến tán ma, ma khí của đại hán vừa tản ra liền bị Cổ Yêu chi mang luyện sạch; cuối trận, mang này dùng để luyện hóa thân thể đại hán bị chiếm xác.","nguon":["@c0565"]},{"id":"hoang-tuyen-huyen-thuat","name":"Hoàng Tuyền (huyễn thuật)","cn":"黄泉","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần thuật","soHuu":["Vương Lâm"],"blurb":"Cổ Thần thuật huyễn hóa sông Hoàng Tuyền cõi âm, dùng làm nồi dung hợp pháp bảo và thần thức thành hoàng mang.","detail":"Hoàng Tuyền là một Cổ Thần thuật trong ký ức truyền thừa Đồ Ti. Vương Lâm bấm quyết huyễn hóa ra sông Hoàng Tuyền với vô số tay chân cụt và tiếng than khóc não nề. Hoàng Tuyền được dùng như một nồi luyện: ném gần như toàn bộ pháp bảo vào trong, cùng thần thức và đạo niệm cưỡng ép dung hợp, cô đọng lại thành hoàng mang có uy lực cực lớn đủ trọng thương tán ma.","nguon":["@c0565"]},{"id":"co-than-ngu","name":"Cổ Thần ngữ","cn":"古神语","loai":"khac","loaiLabel":"Khác","phamCap":"","hePhai":"Cổ Thần","soHuu":[],"blurb":"Ngôn ngữ kỳ dị giọng the thé của giới Cổ Thần, được ma hồn tán ma sử dụng và Vương Lâm nhận ra.","detail":"Cổ Thần ngữ là ngôn ngữ kỳ dị, giọng the thé của giới Cổ Thần. Ma hồn nơi mi tâm đại hán dùng Cổ Thần ngữ quát Bối La. Vương Lâm nhận ra được thứ ngôn ngữ này nhờ ký ức truyền thừa liên quan đến Cổ Thần.","nguon":["@c0565"]},{"id":"an-quyet-do-ti","name":"Ấn quyết cổ quái (ký ức Đồ Ti)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần thuật","soHuu":["Vương Lâm"],"blurb":"Ấn quyết cổ quái theo ký ức truyền thừa Đồ Ti, chỉ có vẻ ngoài nhưng dẫn dắt bản tôn tóc hồng hô ứng hút linh lực.","detail":"Ấn quyết cổ quái nằm trong ký ức truyền thừa Đồ Ti. Vương Lâm theo bản năng giơ tay đánh ra ấn quyết này — chỉ có vẻ ngoài, bản thân không mang lực công kích. Tuy vậy, thông qua dẫn dắt nguyên thần, ấn quyết hô ứng với bản tôn tóc hồng ở tiểu tinh bán phế xa xôi, khiến bản tôn cùng đánh ấn quyết, hô “Thu” để hút linh lực sâu trong lòng đất.","nguon":["@c0565"]},{"id":"thien-truong-dia-dong","name":"Thiên Trướng Địa Đông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Yêu Vệ Địa Ma"],"aliases":["Thiên Nùng"],"blurb":"Thần thông của Yêu Vệ Địa Ma tạo tường nước/chất dịch bao quanh co rút thành quả cầu giam đối thủ.","detail":"Thần thông của Yêu Vệ gầy gò Địa Ma. Sau khi hư ảnh hình kén nuốt luồng tịch diệt và ngưng tụ thành quả cầu ném xuống đất, thần thông tạo nên tường nước cùng chất dịch bao quanh đối thủ, dần co rút thành một quả cầu khổng lồ giam giữ giữa trời đất. Quả cầu co còn ba trượng thì ngừng do chiến ý sát khí của đối thủ xuyên ra, làm thi triển giả co đồng tử.","nguon":["@c0561"]},{"id":"thien-te-hoang-tuyen","name":"Đạo Hóa Hoàng Tuyền","aliases":["Thiên Tế Hoàng Tuyền","Hoàng Tuyền hà"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đạo niệm hóa thành sông lớn Hoàng Tuyền mang luân hồi chi lực.","detail":"Thần thông biến đạo niệm thành con sông lớn Hoàng Tuyền hà mang luân hồi chi lực. Vương Lâm có thể nhập thân hóa thành Hoàng Long, ngưng hóa tuyền hồn để tăng cường. Khi đối chiến hắc giáp lão giả, Hoàng Tuyền dùng để chống đỡ chuỗi thần thông Phong/Lôi/Vũ/Điện và bị sụp đổ một phần ba.","nguon":["@c0563"]},{"id":"phong-loi-vu-dien","name":"Phong Lôi Vũ Điện","aliases":["Phong","Lôi","Vũ","Điện"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Sáo Tiêu giáp","soHuu":["Hắc giáp lão giả"],"blurb":"Chuỗi thần thông từ Sáo Tiêu giáp tạo lốc gió, hắc lôi, hắc vũ ma khí và hàng rào điện quang.","detail":"Chuỗi thần thông liên tiếp của hắc giáp lão giả phát ra từ bộ Sáo Tiêu giáp: Phong tạo lốc gió, Lôi tạo hắc lôi, Vũ tạo hắc vũ ma khí, Điện tạo hàng rào điện quang. Được lão giả vận dụng trong trận đánh với Vương Lâm tại hắc tháp.","nguon":["@c0563"]},{"id":"ngung-hoa-tuyen-hon","name":"Ngưng hóa tuyền hồn","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Dung nhập một trăm ngàn hồn phách vào Hoàng Tuyền tạo Hoàng Tuyền chi hồn.","detail":"Thủ pháp ngưng hóa: Vương Lâm cho một trăm ngàn hồn phách từ Tôn Hồn Phiên dung nhập vào Hoàng Tuyền, ngưng hóa làm một thành Hoàng Tuyền chi hồn, khiến Hoàng Tuyền có hồn đội đất lao ra như Hoàng Long nuốt thần thông phong vũ lôi điện.","nguon":["@c0563"]},{"id":"phong-vu-loi-dien","name":"Phong Vũ Lôi Điện","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Hắc giáp lão giả"],"blurb":"Thần thông hắc lôi mưa mang điện và phong tuyền của hắc giáp lão giả.","detail":"Thần thông mà hắc giáp lão giả tự nhận là yếu nhất, gồm hắc lôi, mưa mang điện và phong tuyền. Buông xuống va chạm với Hoàng Tuyền chân chính của Vương Lâm rồi cuối cùng bị kiếm khí Lăng Thiên Hậu đánh tan vỡ.","nguon":["@c0564"]},{"id":"ma-dao","name":"Ma đạo / Ma đao","cn":"","loai":"than-thong","loaiLabel":"Đạo / Thần thông","phamCap":"","hePhai":"","soHuu":["Hắc giáp lão giả"],"blurb":"Đạo trên khải giáp hắc giáp lão giả, ngưng ma khí thành ma đao.","detail":"Đạo trên khải giáp của hắc giáp lão giả. Hắn vuốt ngực khải giáp ngưng ma khí thành liêm đao tỏa ma diễm nửa hư nửa thực; ma ảnh đầu một sừng (ma hồn phân thể) từ mi tâm chui ra dung nhập biến thành ma đao ẩn chứa ma đạo, đao sống lại bắn về Vương Lâm, sau bị kiếm khí Lăng Thiên Hậu phá vỡ.","nguon":["@c0564"]},{"id":"dai-na-di-thuat","name":"Đại Na Di thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông di chuyển tầm xa, tiêu hao tiên lực nhiều nhất trong các thuật Na Di.","detail":"Là cấp cao hơn của thuật di chuyển Na Di, cho phép dịch chuyển khoảng cách rất xa nhưng tiêu hao tiên lực lớn nhất. Sau khi phục sinh nhờ Huyết Hồn đan và để bốn giọt tiên dịch dung nhập cơ thể, Vương Lâm phát hiện tiên lực vừa hao tổn đã lập tức được bổ sung, nhờ vậy có thể thi triển Đại Na Di nhiều lần liên tục để chạy trốn.","nguon":["@c0565"]},{"id":"co-than-thuat","name":"Cổ Thần thuật","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"aliases":["Cổ Thần thuật của Đồ Ti"],"blurb":"Truyền thừa thuật pháp Cổ Thần nằm trong ký ức Cổ Thần Đồ Ti; Vương Lâm lĩnh ngộ thêm khi quan sát chiến đấu.","detail":"Là hệ thống thuật pháp của Cổ Thần lưu trong ký ức Cổ Thần Đồ Ti mà Vương Lâm thừa kế. Trong lúc thổ nạp dưỡng thương và quan sát trận chiến giữa Cổ Yêu và tán ma, các Cổ Thần thuật trong ký ức bắt đầu mọc rễ nảy mầm trong nhận thức của Vương Lâm; hắn theo bản năng đánh ra những ấn quyết cổ quái (ban đầu chỉ có vẻ ngoài, chưa có lực công kích). Qua dẫn dắt trong nguyên thần, bản tôn tóc hồng trên tiểu tinh bán phế cũng đồng bộ biến ấn quyết, mi tâm lóe tinh mang và hô \"Thu!\" để hút linh lực sâu dưới lòng đất; Vương Lâm ở Yêu Linh địa làm động tác tương tự và mỉm cười vì học thêm được Cổ Thần thuật.","nguon":["@c0565"]},{"id":"phong-loi-vu-dien-sao-tieu-giap","name":"Phong Lôi Vũ Điện","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Sáo Tiêu giáp","soHuu":["Hắc giáp lão giả"],"blurb":"Chuỗi bốn thần thông liên hoàn của Sáo Tiêu giáp: lốc gió, hắc lôi, hắc vũ ma khí và hàng rào điện quang.","detail":"Hắc giáp lão giả mặc Sáo Tiêu giáp liên tiếp thi triển Phong, Lôi, Vũ, Điện công kích Vương Lâm: gió cuộn thành lốc, hắc lôi giáng xuống, hắc vũ mang ma khí, hàng rào điện quang vây phủ; nguồn lực đến từ đạo riêng của Sáo Tiêu giáp.","nguon":["@c0563"]},{"id":"hoang-tuyen","name":"Hoàng Tuyền","cn":"黄泉","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Hoàng Tuyền chân chính của Vương Lâm, ẩn chứa mười ba vạn sát lục chi khí, trăm ngàn hồn phách và đạo cuộc đời hắn.","detail":"Hoàng Tuyền chân chính lao vào thần thông đối phương gây rung chuyển đại địa. Sau khi kiếm khí Lăng Thiên Hậu xuất hiện, Hoàng Tuyền dung nhập vào cơ thể Vương Lâm, mười ba vạn sát lục chi khí tan vỡ, Hoàng Tuyền chi hồn từ một hóa trăm ngàn.","nguon":["@c0564"]},{"id":"co-yeu-chi-mang-than-thong","name":"Cổ Yêu chi mang","cn":"古妖之芒","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông Cổ Yêu","soHuu":["Cổ Yêu"],"blurb":"Thần thông cực lợi hại của Cổ Yêu, có thể luyện hóa hết thảy sinh linh thiên địa.","detail":"Một thần thông cực kỳ lợi hại do Cổ Yêu thi triển, mang theo lực luyện hóa hết thảy sinh linh thiên địa. Trong đại chiến tại Thiên Yêu thành, Cổ Yêu hóa thân hai sừng dùng Cổ Yêu chi mang đuổi theo tán ma đại hán sau khi hắn bị hoàng mang Vương Lâm uy hiếp khựng lại, luyện hóa hết chín phần ma khí trong áo giáp nương thân của tán ma — chỉ chừa lại một phần để tán ma vất vả xông thoát.","nguon":["@c0565"]},{"id":"hoang-mang-vuong-lam","name":"Hoàng mang","cn":"黄芒","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Đạo thuật tổng hợp","soHuu":["Vương Lâm"],"blurb":"Đạo hoàng mang Vương Lâm rút từ sông Hoàng Tuyền sau khi gom gần hết pháp bảo và đạo của mình vào trong.","detail":"Vương Lâm bấm quyết huyễn hóa sông Hoàng Tuyền chứa đầy tay chân cụt và tiếng than khóc, rồi lần lượt ném vào Tôn Hồn Phiên, Cấm Phiên, tiên kiếm (kèm kiếm linh Hứa Lập Quốc), loan đao, Côn Cực Tiên, vỏ kiếm, Mạt Dương chi kiếm — gần hết pháp bảo trừ Xạ Thần Xa và cuộn tranh thần bí. Hắn rút Hoàng Tuyền lại thành một đạo hoàng mang chứa cả pháp bảo lẫn ‘đạo’ của bản thân, dùng để uy hiếp tán ma đại hán. Khi đại hán đấm vào hoàng mang liền bị thần thức/niệm cưỡng hợp uy hiếp, khựng lại đủ để Cổ Yêu chi mang đuổi tới.","nguon":["@c0565"]},{"id":"thang-tien-qua-than-thong","name":"Luyện hồn thuật","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Luyện Hồn bộ lạc","soHuu":["Hổ Bào"],"blurb":"Công pháp luyện hồn của Hổ Bào, đại thành cho phép điều khiển trên trăm ngàn hồn phách.","detail":"Luyện hồn thuật là công pháp Hổ Bào tu luyện sau khi được ‘chủ nhân’ cứu sống. Khi đại thành, người tu có thể thu nhiếp và điều khiển trên trăm ngàn hồn phách, tụ thành đám mây đen vây quanh, vừa hộ thể vừa tạo uy thế. Hổ Bào còn tuyên bố dùng pháp này phong ấn hồn phách kẻ địch, rút hồn nhốt vào hồn phiên để hành hạ lâu dài.","nguon":["@c0561"]},{"id":"huyet-hon-chi-luc","name":"Huyết Hồn chi lực","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Bí pháp phục sinh","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bí pháp đi cùng Huyết Hồn đan: sau khi chủ nhân tử vong, dùng Huyết Hồn chi lực thu hồi vật dẫn và nguyên thần để phục sinh.","detail":"Sau khi bóp vỡ Huyết Hồn đan, người tu cắn ngón tay đẩy máu tươi hóa thành phù văn phức tạp, dung hợp với giọt máu lam trong đan rồi ấn lên mi tâm, bắn phù văn bay xa ngàn dặm để ẩn giấu. Khi vật dẫn tương liên cùng nguyên thần dung nhập hư vô lúc tử vong, Huyết Hồn chi lực sẽ thu hồi tất cả, dùng giọt máu lam tái hiện thân ảnh, tái chiếm túi trữ vật, hồi phục sinh mệnh.","nguon":["@c0565"]},{"id":"hoang-tuyen-hoang-mang","name":"Hoàng Tuyền hoàng mang","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt học","hePhai":"Tu Đạo","soHuu":["Vương Lâm"],"blurb":"Đạo thuật Vương Lâm gom toàn bộ pháp bảo và đạo của mình vào sông Hoàng Tuyền, rút thành một đạo hoàng mang uy lực kinh người.","detail":"Vương Lâm bấm quyết huyễn hóa con sông Hoàng Tuyền đầy tay chân cụt và tiếng than khóc, sau đó lần lượt ném pháp bảo (Tôn Hồn Phiên, Cấm Phiên, tiên kiếm, loan đao, Côn Cực Tiên, vỏ kiếm, Mạt Dương chi kiếm…) vào Hoàng Tuyền, chừa lại Xạ Thần Xa và cuộn tranh thần bí. Sau khi sông nuốt hết pháp bảo, hắn rút Hoàng Tuyền lại thành một đạo hoàng mang chứa cả pháp bảo lẫn đạo của bản thân, dùng để uy hiếp và đả thương tán ma đại hán. Đây là sự kết hợp giữa thần niệm Cổ Thần, đạo thuật và toàn bộ pháp bảo nuôi nhiều năm.","nguon":["@c0565"]},{"id":"yeu-mac","name":"Yêu mạc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Yêu","soHuu":["Cổ Yêu"],"blurb":"Đạo màn yêu khí Cổ Yêu buông từ trời che phủ cả Thiên Yêu thành, cách ly chiến trường.","detail":"Khi Cổ Yêu tung yêu vụ bao vây tán ma đại hán, một đạo yêu mạc đồng thời buông từ trời xuống che phủ toàn bộ Thiên Yêu thành, dùng làm tường ngăn cách chiến trường với bên ngoài. Bên trong yêu mạc, ma diễm và yêu khí tung hoành suốt ba ngày mà không lộ ra ngoài.","nguon":["@c0565"]},{"id":"dao-hoang-tuyen-vuong-lam","name":"Đạo Hoàng Tuyền","cn":"","loai":"than-thong","loaiLabel":"Đạo tự tạo","phamCap":"Rìa thiên đạo bước hai","hePhai":"Đạo của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đạo tự tạo của Vương Lâm — đạo niệm hóa dòng sông Hoàng Tuyền, mở luân hồi riêng không chịu quản lý của trời đất.","detail":"Sau mười năm cảm ngộ, kết hợp kích thích của Thăng Tiên Quả và tiên lực khổng lồ, đạo niệm mơ hồ của Vương Lâm lần đầu thành thực chất, hóa ra một dòng sông Hoàng Tuyền. Vương Lâm tuyên bố không tu thiên, không tu đất, không tu tiên, không tu thần — tự tạo đạo của chính mình. Kẻ rơi vào hoàng tuyền sẽ theo luân hồi của Vương Lâm, không chịu sự quản lý của trời đất. Đây là bước ngộ đạo đầu tiên đưa hắn tới rìa thiên đạo bước hai.","nguon":["@c0561"]},{"id":"than-thong-thien-nung","name":"Thiên Nùng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Yêu Vệ Địa Ma","soHuu":["Địa Ma"],"blurb":"Thần thông của Yêu Vệ Địa Ma — há miệng nuốt công kích, phía sau hiện hư ảnh hình kén mười trượng đồng bộ nuốt theo, ngưng tụ chất dịch thành quả cầu phản kích.","detail":"Khi giao chiến Vương Lâm trên cánh đồng hoang đầy hài cốt, Địa Ma há miệng nuốt Tịch Diệt Chỉ. Phía sau lão hiện ra hư ảnh hình kén mười trượng cũng nuốt theo. Bụng lão phồng lên rồi phun ra nước tanh, ngưng tụ thành quả cầu chất dịch đậm đặc dùng để phản kích. Quả cầu này khi ném xuống đất sẽ là nền cho thần thông Thiên Trướng Địa Đông phía sau.","nguon":["@c0561"]},{"id":"dia-tich-than-thong","name":"Địa Tích","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Người hầu Tôn Ma","soHuu":["Người hầu Tôn Ma"],"blurb":"Thần thông của lão già hắc y (Người hầu Tôn Ma) — bấm pháp quyết, mặt đất chu vi ngàn trượng xuất hiện lỗ hổng giống vết lở loét, nổ tung phun chất lỏng dày mười trượng.","detail":"Khi đối đầu Vương Lâm vừa phá kén bước ra, lão già hét lớn “Địa Tích!” và bấm pháp quyết. Mặt đất chấn động, trong chu vi ngàn trượng xuất hiện những lỗ hổng giống vết lở loét, sau đó mở rộng rồi nổ tung phun lên cao chất lỏng dày mười trượng. Là thần thông tấn công diện rộng dựa vào địa hình.","nguon":["@c0561"]},{"id":"hoang-tuyen-huyen-canh","name":"Hoàng Tuyền huyễn cảnh","cn":"黄泉幻境","loai":"than-thong","loaiLabel":"Thần thông trận","phamCap":"Trấn phái","soHuu":["Vương Lâm"],"blurb":"Bấm quyết huyễn hóa con sông Hoàng Tuyền đầy tay chân cụt và tiếng than khóc, dung chứa pháp bảo và đạo của chủ nhân để cô đặc thành hoàng mang.","detail":"Vương Lâm bấm quyết bày Hoàng Tuyền — sông huyễn có vô số tay chân cụt nhô lên, vang tiếng than khóc rền rĩ. Hắn ném gần như toàn bộ pháp bảo (Tôn Hồn Phiên, Cấm Phiên, tiên kiếm Hứa Lập Quốc, loan đao, Côn Cực Tiên, vỏ kiếm, Mạt Dương chi kiếm) vào sông để dung hợp; cuối cùng rút ra thành một đạo hoàng mang ẩn chứa cả pháp bảo lẫn thần thức lẫn đạo của hắn, uy lực đủ chấn dừng tán ma đại hán đã thụ thương.","nguon":["@c0565"]},{"id":"sinh-chi-lac-an-muoi-ba-van","name":"Sinh chi lạc ấn (mười ba vạn)","loai":"than-thong","loaiLabel":"Thần thông phòng ngự","phamCap":"Trấn phái","soHuu":["Vương Lâm"],"blurb":"Điểm mi tâm chuyển hóa mười ba vạn sát lục chi khí thành mười ba vạn sinh chi lạc ấn dày đặc thủ hộ quanh thân.","detail":"Vương Lâm điểm mi tâm, đem mười ba vạn sát lục chi khí tích lũy chuyển hóa thành mười ba vạn sinh chi lạc ấn xếp dày đặc bao quanh thân, tạo thành lớp phòng ngự cực mạnh trước khi xông tới đại hán tán ma. Lượng ấn lớn hơn bội phần so với lần dùng trước, nhưng vẫn bị một vỗ của đại hán phá vỡ toàn bộ.","nguon":["@c0565"]},{"id":"thuat-thu-ban-ton-toc-hong","name":"Thuật “Thu” của bản tôn tóc hồng","loai":"than-thong","loaiLabel":"Thần thông luyện địa","phamCap":"Trấn phái","soHuu":["Bản tôn tóc hồng của Vương Lâm"],"blurb":"Bản tôn tóc hồng trên tiểu tinh bán phế hô một tiếng “Thu!”, rút linh lực sâu trong lòng tinh cầu quy về thân.","detail":"Khi Vương Lâm lĩnh ngộ Cổ Thần thuật, qua nguyên thần dẫn dắt, bản tôn tóc hồng trên một tiểu tinh bán phế cách Đông Hải chi môn vô số dặm đồng bộ mở mắt, mi tâm lóe tinh mang. Bản tôn hô “Thu!” khiến từng đạo linh lực ở sâu dưới lòng đất tinh cầu phun ra quy tụ về thân, biểu hiện một mặt của Cổ Thần thuật trong việc cướp đoạt linh khí thiên địa.","nguon":["@c0565"]},{"id":"dao-hoang-tuyen-vuong-lam-tu-tao","name":"Đạo Hoàng Tuyền (Vương Lâm tự tạo)","cn":"","loai":"than-thong","loaiLabel":"Đạo tự tạo / Thần thông","phamCap":"Rìa thiên đạo bước hai","hePhai":"Đạo của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đạo niệm Vương Lâm hóa thành dòng sông Hoàng Tuyền, mở luân hồi riêng không chịu quản lý của trời đất.","detail":"Sau mười năm cảm ngộ, kết hợp kích thích của Thăng Tiên Quả và tiên lực khổng lồ, đạo niệm mơ hồ của Vương Lâm lần đầu thành thực chất, hóa ra một dòng sông Hoàng Tuyền. Hắn không tu thiên, không tu đất, không tu tiên, không tu thần — mà tự tạo đạo của chính mình, đạt tới bước thứ hai bên rìa thiên đạo. Kẻ rơi vào Hoàng Tuyền sẽ theo luân hồi của hắn, không chịu sự quản lý của trời đất; mười Yêu Tướng bị cuốn xuống đất theo dòng sông này. Vương Lâm có thể phóng thẳng vào trong dòng hoàng tuyền, dòng sông vững như Thái Sơn nâng đỡ thân hắn.","nguon":["@c0561"]},{"id":"luyen-hon-thuat-ho-bao","name":"Luyện hồn thuật (Hổ Bào đại thành)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật luyện hồn","phamCap":"Đại thành","hePhai":"Chủ nhân của Hổ Bào","soHuu":["Hổ Bào"],"blurb":"Bí thuật luyện hồn Hổ Bào tu thành đại thành, mỗi ngày tạo trên trăm ngàn hồn phách, có thể phong ấn hồn phách kẻ địch trong thân.","detail":"Sau khi được chủ nhân bí ẩn cứu sống, Hổ Bào tu luyện luyện hồn thuật tới mức đại thành. Mỗi ngày tu luyện hắn thành tựu trên trăm ngàn hồn phách, hợp lại tạo mây đen hình phễu gào thét. Tiếng hét của hắn đồng thời là tiếng của trăm ngàn hồn phách dung hợp, đủ sức làm nguyên thần Vương Lâm (đang bị Thăng Tiên Quả xâm nhập) hiện một tia thanh tỉnh. Hổ Bào tuyên bố sẽ dùng thuật này phong ấn hồn phách Vương Lâm trong thân, ném vào hắc lao cửu quận, sau đó rút hồn vào hồn phiên hành hạ, rồi trở lại Luyện Hồn bộ lạc biến tất cả mọi người thành hồn phách.","nguon":["@c0561"]}]};
